import { GoogleGenAI, Type } from "@google/genai";
import { Appointment, Client } from "../types";

export class GeminiAssistant {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeSchedule(appointments: Appointment[], clients: Client[], query: string) {
    const context = `
      You are an AI Scheduling Assistant for a professional business.
      Current Date: 2024-05-15

      Current Appointments:
      ${JSON.stringify(appointments)}

      Client List:
      ${JSON.stringify(clients)}

      Instructions:
      Analyze the schedule and provide concise, helpful insights. 
      If the user asks to "book" or "find a slot", look for gaps in the 9:00 to 17:00 workday.
      Be professional and business-oriented.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: context + "\n\nUser Question: " + query,
        config: {
          temperature: 0.7,
          topP: 0.9,
        }
      });

      return response.text || "I'm sorry, I couldn't process that request.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "There was an error connecting to the AI assistant.";
    }
  }

  async getSummary(appointments: Appointment[]) {
    const summaryPrompt = `
      Summarize the business performance based on these appointments: ${JSON.stringify(appointments)}.
      Give me a 2-sentence executive summary.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: summaryPrompt,
      });
      return response.text;
    } catch (error) {
      return "Unable to generate summary at this time.";
    }
  }
}

export const geminiAssistant = new GeminiAssistant();

