import React from 'react';
import { Appointment } from '../types';
import { Calendar as CalendarIcon, Clock, ChevronLeft, ChevronRight, Plus } from 'lucide-react';

interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ appointments, onAddClick }) => {
  // Simple grouping by day for a demo
  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
      <div className="p-6 border-b flex items-center justify-between bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-xl font-bold text-gray-900">May 2024</h3>
          <p className="text-sm text-gray-500">Upcoming schedule and client bookings</p>
        </div>
        <div className="flex items-center gap-2">
          <div className="flex border rounded-lg overflow-hidden">
            <button className="p-2 hover:bg-gray-50 border-r text-gray-400"><ChevronLeft size={20} /></button>
            <button className="p-2 hover:bg-gray-50 text-gray-400"><ChevronRight size={20} /></button>
          </div>
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-medium"
          >
            <Plus size={18} />
            Add Appointment
          </button>
        </div>
      </div>

      <div className="p-6 space-y-8">
        {dates.length === 0 ? (
          <div className="text-center py-20 text-gray-500">
            <CalendarIcon size={48} className="mx-auto mb-4 opacity-20" />
            <p>No appointments found for this period.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                <CalendarIcon size={14} />
                {new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
              </h4>
              <div className="grid grid-cols-1 gap-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group relative flex items-center gap-4 p-4 rounded-xl border border-gray-100 hover:border-indigo-200 hover:bg-indigo-50/30 transition-all cursor-pointer">
                    <div className="flex flex-col items-center justify-center w-20 text-center border-r pr-4">
                      <span className="text-lg font-bold text-gray-900">{apt.time}</span>
                      <span className="text-xs text-gray-400 flex items-center gap-1"><Clock size={10} /> {apt.duration}m</span>
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center justify-between mb-1">
                        <h5 className="font-bold text-gray-900">{apt.clientName}</h5>
                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide ${
                          apt.status === 'confirmed' ? 'bg-green-100 text-green-700' :
                          apt.status === 'pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
