import React, { useEffect, useState } from 'react';
import { Appointment, Client } from '../types';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { TrendingUp, Users, CalendarCheck, Clock, Sparkles } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';

interface DashboardProps {
  appointments: Appointment[];
  clients: Client[];
}

const Dashboard: React.FC<DashboardProps> = ({ appointments, clients }) => {
  const [aiSummary, setAiSummary] = useState<string>("Analyzing your business data...");

  useEffect(() => {
    const fetchAiSummary = async () => {
      const summary = await geminiAssistant.getSummary(appointments);
      setAiSummary(summary || "No insights available.");
    };
    fetchAiSummary();
  }, [appointments]);

  const stats = [
    { label: 'Appointments', value: appointments.length, icon: CalendarCheck, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Clients', value: clients.length, icon: Users, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { label: 'Rate', value: '94%', icon: TrendingUp, color: 'text-green-600', bg: 'bg-green-50' },
    { label: 'Duration', value: '55m', icon: Clock, color: 'text-orange-600', bg: 'bg-orange-50' },
  ];

  const chartData = [
    { name: 'Mon', revenue: 400 },
    { name: 'Tue', revenue: 700 },
    { name: 'Wed', revenue: 550 },
    { name: 'Thu', revenue: 900 },
    { name: 'Fri', revenue: 1100 },
    { name: 'Sat', revenue: 300 },
    { name: 'Sun', revenue: 150 },
  ];

  return (
    <div className="space-y-4 md:space-y-6">
      <header>
        <h2 className="text-xl md:text-2xl font-bold text-gray-900">Dashboard Overview</h2>
        <p className="text-sm text-gray-500">Welcome back! Here's today's pulse.</p>
      </header>

      {/* AI Insight Card */}
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-4 md:p-6 text-white shadow-lg relative overflow-hidden">
        <div className="absolute -top-4 -right-4 p-4 opacity-10">
          <Sparkles size={80} />
        </div>
        <div className="relative z-10">
          <h3 className="text-sm md:text-lg font-semibold flex items-center gap-2 mb-2">
            <Sparkles size={16} />
            Gemini AI Insight
          </h3>
          <p className="text-xs md:text-sm text-indigo-100 italic leading-relaxed">
            "{aiSummary}"
          </p>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-4 md:p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
            <div className={`w-10 h-10 md:w-12 md:h-12 ${stat.bg} ${stat.color} rounded-xl flex items-center justify-center mb-2 md:mb-4`}>
              <stat.icon size={20} />
            </div>
            <p className="text-[10px] md:text-sm font-medium text-gray-500 uppercase md:normal-case">{stat.label}</p>
            <p className="text-lg md:text-2xl font-bold text-gray-900">{stat.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 md:gap-6">
        <div className="lg:col-span-2 bg-white p-4 md:p-6 rounded-2xl border border-gray-100 shadow-sm">
          <h3 className="text-base md:text-lg font-semibold mb-4 md:mb-6">Revenue Trend</h3>
          <div className="h-[200px] md:h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} dy={10} />
                <YAxis hide={window.innerWidth < 768} axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Area type="monotone" dataKey="revenue" stroke="#4f46e5" strokeWidth={3} fillOpacity={1} fill="url(#colorRevenue)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-4 md:p-6 rounded-2xl border border-gray-100 shadow-sm">
          <h3 className="text-base md:text-lg font-semibold mb-4 md:mb-6">Upcoming</h3>
          <div className="space-y-3 md:space-y-4">
            {appointments.slice(0, 4).map((apt) => (
              <div key={apt.id} className="flex items-center gap-3 p-2 md:p-3 rounded-xl hover:bg-gray-50 transition-colors border border-transparent hover:border-gray-100">
