                  <p className="text-xs text-gray-500 truncate">{apt.service}</p>
                </div>
                <div className="text-right text-xs shrink-0">
                  <p className="font-semibold text-gray-900">{apt.time}</p>
                  <p className={`capitalize font-medium ${apt.status === 'confirmed' ? 'text-green-600' : 'text-amber-500'}`}>{apt.status}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
      {/* Spacer for bottom nav */}
      <div className="h-16 md:hidden"></div>
