          <h3 className="text-lg md:text-xl font-bold text-gray-900">May 2024</h3>
          <p className="text-xs md:text-sm text-gray-500">Scheduled client sessions</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-2">
          <div className="flex border border-gray-100 rounded-lg overflow-hidden bg-gray-50">
            <button className="p-2 hover:bg-white text-gray-400 border-r border-gray-100"><ChevronLeft size={18} /></button>
            <button className="p-2 hover:bg-white text-gray-400"><ChevronRight size={18} /></button>
          </div>
          <button 
            onClick={onAddClick}
            className="hidden md:flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-medium text-sm"
          >
            <Plus size={16} />
            Schedule New
          </button>
        </div>
      </div>

      <div className="p-4 md:p-6 space-y-6 md:space-y-8">
        {dates.length === 0 ? (
          <div className="text-center py-20 text-gray-400">
            <CalendarIcon size={40} className="mx-auto mb-4 opacity-10" />
            <p className="text-sm">Your schedule is empty.</p>
