        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400"></span>
                {new Date(date).toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
              </h4>
              <div className="space-y-3">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group relative flex items-center gap-3 md:gap-4 p-3 md:p-4 rounded-xl border border-gray-50 hover:border-indigo-100 hover:bg-indigo-50/20 transition-all cursor-pointer bg-white">
                    <div className="flex flex-col items-center justify-center w-14 md:w-16 text-center border-r border-gray-50 pr-3 md:pr-4">
                      <span className="text-sm md:text-base font-bold text-gray-900 leading-tight">{apt.time}</span>
                      <span className="text-[9px] text-gray-400 font-medium uppercase">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <h5 className="font-bold text-gray-900 text-sm md:text-base truncate">{apt.clientName}</h5>
                        <span className={`px-1.5 py-0.5 rounded-md text-[8px] md:text-[9px] font-bold uppercase tracking-tight shrink-0 ${
                          apt.status === 'confirmed' ? 'bg-green-50 text-green-600' :
                          apt.status === 'pending' ? 'bg-amber-50 text-amber-600' : 'bg-red-50 text-red-600'
                        }`}>
                          {apt.status}
                        </span>
                      </div>
                      <p className="text-[11px] md:text-sm text-gray-500 truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="text-xs md:text-sm font-bold text-gray-900">${apt.price}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

