        <button 
          onClick={() => window.location.reload()}
          className="w-full max-w-xs py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg"
        >
          Done
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
