import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Download } from 'lucide-react';

const App: React.FC = () => {
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || 'Studio Admin');

  // Initialize state from LocalStorage or use Mocks
  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  // Basic Routing Simulation
  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) {
      setIsPublicView(true);
    }
  }, []);

  // Persist data whenever it changes
  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
  }, [appointments]);

  useEffect(() => {
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
  }, [clients]);

  useEffect(() => {
    localStorage.setItem('bookly_business_name', businessName);
  }, [businessName]);

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
    const exists = clients.some(c => c.name === newBooking.clientName);
    if (!exists) {
      const newClient: Client = {
        id: Math.random().toString(36).substr(2, 9),
        name: newBooking.clientName,
        email: 'customer@email.com',
        phone: 'Not provided',
      };
      setClients(prev => [...prev, newClient]);
    }
  };

  const exportClientsToCSV = () => {
    const headers = ['Name', 'Email', 'Phone', 'Last Visit'];
    const rows = clients.map(c => [c.name, c.email, c.phone, c.lastVisit || 'N/A']);
    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(r => r.join(','))].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "bookly_clients.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return <AppointmentCalendar appointments={appointments} onAddClick={() => setShowAddModal(true)} />;
      case 'clients':
        return (
          <div className="bg-white p-4 md:p-8 rounded-3xl border border-gray-100 shadow-sm animate-in fade-in duration-500">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h2 className="text-2xl font-bold text-gray-900">Clients</h2>
                <p className="text-sm text-gray-500">Manage your customer relationships.</p>
              </div>
              <button 
                onClick={exportClientsToCSV}
                className="flex items-center gap-2 px-4 py-2 bg-gray-50 text-gray-600 rounded-xl hover:bg-gray-100 transition-colors font-bold text-xs"
              >
                <Download size={14} />
                Export CSV
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {clients.map(client => (
                <div key={client.id} className="p-5 border border-gray-100 rounded-2xl hover:border-indigo-300 transition-all cursor-pointer group bg-white hover:shadow-lg hover:shadow-indigo-50">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center font-bold border border-indigo-100 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-300">
                      {client.name.charAt(0)}
                    </div>
                    <div className="min-w-0">
                      <p className="font-bold text-gray-900 truncate">{client.name}</p>
                      <p className="text-xs text-gray-400 truncate">{client.email}</p>
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-50 flex justify-between items-center">
                    <span className="text-xs text-gray-500 font-medium">{client.phone}</span>
                    <button className="text-xs font-bold text-indigo-600 hover:underline">Profile</button>
                  </div>
                </div>
              ))}
              <button 
                onClick={() => setShowAddModal(true)}
                className="border-2 border-dashed border-gray-100 rounded-2xl p-6 flex flex-col items-center justify-center text-gray-300 hover:text-indigo-600 hover:border-indigo-200 hover:bg-indigo-50/20 transition-all gap-2"
              >
                <div className="w-10 h-10 rounded-full border-2 border-dashed border-current flex items-center justify-center">
                  <Plus size={20} />
                </div>
                <span className="font-bold text-xs uppercase tracking-widest">New Customer</span>
              </button>
            </div>
            <div className="h-24 md:hidden"></div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing />;
      case 'settings':
        return <Settings businessName={businessName} onUpdateBusinessName={setBusinessName} />;
      default:
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Mobile Header */}
        <header className="h-14 md:h-16 bg-white border-b flex items-center justify-between px-4 md:px-8 shrink-0 z-20">
          <div className="md:hidden flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
              <Sparkles size={16} />
            </div>
            <span className="font-bold text-indigo-900 tracking-tight">Bookly</span>
          </div>

          <div className="hidden md:flex items-center gap-4 bg-gray-50 rounded-full px-4 py-2 w-80 lg:w-96 border border-gray-100 focus-within:ring-2 focus-within:ring-indigo-100 transition-all">
            <Search size={16} className="text-gray-400" />
            <input 
              type="text" 
              placeholder="Search appointments..." 
              className="bg-transparent border-none focus:outline-none text-sm w-full"
            />
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="hidden sm:flex items-center gap-2 px-3 py-1 bg-green-50 text-green-600 rounded-full border border-green-100">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
              <span className="text-[10px] font-bold uppercase tracking-wider">Online</span>
            </div>

            <button className="p-2 text-gray-400 hover:text-indigo-600 relative transition-colors">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-1.5 h-1.5 bg-red-500 rounded-full"></span>
            </button>

            <div className="h-6 w-[1px] bg-gray-200 mx-1 hidden sm:block"></div>

            <div className="flex items-center gap-2 md:gap-3 pl-1">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-bold text-gray-900 leading-none">{businessName}</p>
                <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-tighter">Pro Studio</p>
              </div>
              <img 
                src={`https://ui-avatars.com/api/?name=${businessName}&background=4f46e5&color=fff&rounded=true`}
                alt="Profile" 
                className="w-8 h-8 md:w-9 md:h-9 rounded-full ring-2 ring-indigo-50 shrink-0"
              />
            </div>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10 max-w-7xl mx-auto w-full">
          {renderContent()}
        </div>

        {/* Floating Action Button (Mobile Only) */}
        {(activeTab === 'calendar' || activeTab === 'dashboard') && (
           <button 
            onClick={() => setShowAddModal(true)}
            className="md:hidden fixed bottom-20 right-4 w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center active:scale-95 transition-transform z-40 border-4 border-white"
           >
             <Plus size={28} />
           </button>
        )}

        {/* Bottom Navigation for Mobile */}
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {/* Add Appointment Modal */}
      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
        />
      )}
    </div>
  );
};

export default App;

