import { GoogleGenAI } from "@google/genai";
import { Appointment, Client } from "../types";

export class GeminiAssistant {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeSchedule(appointments: Appointment[], clients: Client[], query: string) {
    const context = `
      You are the "Bookly Business Growth Advisor".
      Business Name: ${localStorage.getItem('bookly_business_name') || 'Studio Admin'}
      Current Date: 2024-05-15

      Inventory:
      Appointments: ${JSON.stringify(appointments)}
      Clients: ${JSON.stringify(clients)}

      Goal: Help the owner grow their business. 
      If they ask about competition, trends, or local marketing, USE GOOGLE SEARCH.
      Always extract and list URLs if you use search results.
      Be strategic, encouraging, and data-driven.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: context + "\n\nUser Question: " + query,
        config: {
          tools: [{ googleSearch: {} }],
          temperature: 0.7,
        }
      });

      // Extract grounding if available
      const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      let text = response.text || "I'm sorry, I couldn't process that request.";

      if (grounding && grounding.length > 0) {
        text += "\n\n**Sources & Research:**\n" + grounding.map((chunk: any) => `- [${chunk.web?.title || 'Source'}](${chunk.web?.uri})`).join('\n');
      }

      return text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "There was an error connecting to the AI assistant. Please check your internet connection.";
    }
  }

  async getSummary(appointments: Appointment[]) {
    const summaryPrompt = `
      Summarize business performance for: ${JSON.stringify(appointments)}.
      Give a 2-sentence executive summary focusing on revenue and schedule density.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: summaryPrompt,
      });
      return response.text;
    } catch (error) {
      return "Analyzing your daily performance...";
    }
  }
}

