  ];

  const handleNext = () => {
    if (step === 1 && name) setStep(2);
    else if (step === 2 && category) onComplete({ name, category });
  };

  return (
    <div className="min-h-screen bg-white flex items-center justify-center p-6">
      <div className="max-w-md w-full text-center space-y-12">
        <div className="space-y-4">
          <div className="w-16 h-16 bg-indigo-600 rounded-[24px] flex items-center justify-center text-white mx-auto shadow-xl shadow-indigo-100 animate-bounce">
            <Sparkles size={32} />
          </div>
          <h1 className="text-4xl font-black text-gray-900 tracking-tight">Welcome to Bookly</h1>
          <p className="text-gray-500 font-medium">Let's set up your business workspace.</p>
        </div>

        {step === 1 ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-500">
            <div className="text-left">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">What's your business name?</label>
              <input 
                type="text" 
                autoFocus
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="e.g. Zen Spa, Tech Consulting..."
                className="mt-2 w-full bg-gray-50 border-none rounded-3xl py-6 px-8 text-xl font-bold focus:ring-4 focus:ring-indigo-100 outline-none transition-all"
                onKeyDown={(e) => e.key === 'Enter' && name && setStep(2)}
              />
            </div>
            <button 
              disabled={!name}
              onClick={() => setStep(2)}
              className="w-full py-5 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 transition-all flex items-center justify-center gap-2"
            >
              Next Step <ArrowRight size={20} />
            </button>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-500">
            <div className="grid grid-cols-2 gap-4">
              {categories.map((cat) => (
                <button
                  key={cat.id}
                  onClick={() => setCategory(cat.id)}
                  className={`p-6 rounded-[32px] border-2 flex flex-col items-center justify-center gap-3 transition-all ${
                    category === cat.id ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-gray-50 bg-gray-50 text-gray-400 hover:border-indigo-100'
                  }`}
                >
                  <cat.icon size={28} />
                  <span className="text-xs font-bold uppercase tracking-widest">{cat.label}</span>
                </button>
              ))}
            </div>
            <button 
              disabled={!category}
              onClick={() => onComplete({ name, category })}
              className="w-full py-5 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 transition-all"
            >
              Launch My Dashboard
            </button>
            <button onClick={() => setStep(1)} className="text-xs font-bold text-gray-400 hover:text-indigo-600 transition-colors uppercase tracking-widest">
              Go Back
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState } from 'react';
import { Save, Building2, Mail, Phone, Bell, Shield, Trash2, Plus, Clock, DollarSign, X } from 'lucide-react';

interface SettingsProps {
  businessName: string;
  onUpdateBusinessName: (name: string) => void;
  services: any[];
  onUpdateServices: (services: any[]) => void;
}

const Settings: React.FC<SettingsProps> = ({ businessName, onUpdateBusinessName, services, onUpdateServices }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'services'>('profile');
  const [name, setName] = useState(businessName);
  const [newService, setNewService] = useState({ name: '', price: '', duration: '' });
  const [showToast, setShowToast] = useState(false);

  const handleSaveProfile = () => {
    onUpdateBusinessName(name);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleAddService = () => {
    if (!newService.name || !newService.price) return;
    onUpdateServices([...services, { 
      name: newService.name, 
      price: Number(newService.price), 
      duration: Number(newService.duration) || 60 
    }]);
    setNewService({ name: '', price: '', duration: '' });
  };

  const handleDeleteService = (index: number) => {
    onUpdateServices(services.filter((_, i) => i !== index));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-24 md:pb-0">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Settings</h2>
        <div className="flex bg-gray-100 p-1 rounded-2xl">
          <button 
            onClick={() => setActiveTab('profile')}
            className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'profile' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            Profile
          </button>
          <button 
            onClick={() => setActiveTab('services')}
            className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'services' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            Services
          </button>
        </div>
      </div>

      {activeTab === 'profile' ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in fade-in duration-300">
          <div className="md:col-span-2 space-y-6">
            <section className="bg-white p-8 rounded-[32px] border border-gray-100 shadow-sm">
              <h3 className="font-bold text-gray-900 mb-6 flex items-center gap-2">
                <Building2 size={18} className="text-indigo-600" />
                Business Profile
              </h3>
              <div className="space-y-4">
                <label className="block">
                  <span className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">Business Name</span>
                  <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="mt-2 w-full bg-gray-50 border-none rounded-2xl py-4 px-6 focus:ring-2 focus:ring-indigo-600 outline-none font-medium"
                  />
                </label>
                <button onClick={handleSaveProfile} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2">
                  <Save size={18} /> Save Changes
                </button>
              </div>
            </section>
          </div>
        </div>
      ) : (
        <div className="space-y-6 animate-in fade-in duration-300">
          <section className="bg-white p-8 rounded-[32px] border border-gray-100 shadow-sm">
            <h3 className="font-bold text-gray-900 mb-6 flex items-center gap-2">
              <Clock size={18} className="text-indigo-600" />
              Manage Service Menu
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 mb-8">
              <input 
                placeholder="Service Name"
                className="sm:col-span-2 bg-gray-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-indigo-600 outline-none"
                value={newService.name}
                onChange={(e) => setNewService({...newService, name: e.target.value})}
              />
              <input 
                placeholder="Price ($)"
                type="number"
                className="bg-gray-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-indigo-600 outline-none"
                value={newService.price}
                onChange={(e) => setNewService({...newService, price: e.target.value})}
              />
              <button 
                onClick={handleAddService}
                className="bg-indigo-600 text-white rounded-2xl p-4 font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
              >
                <Plus size={18} /> Add
              </button>
            </div>

            <div className="space-y-3">
              {services.map((service, i) => (
                <div key={i} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl hover:bg-indigo-50/50 transition-colors">
                  <div>
                    <p className="font-bold text-gray-900">{service.name}</p>
                    <p className="text-xs text-gray-500">{service.duration} mins • ${service.price}</p>
                  </div>
                  <button onClick={() => handleDeleteService(i)} className="p-2 text-gray-300 hover:text-red-600 transition-colors">
                    <X size={18} />
                  </button>
                </div>
              ))}
            </div>
          </section>
        </div>
      )}

      {showToast && (
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-8 py-4 rounded-full shadow-2xl z-50 animate-in slide-in-from-bottom-4">
          <p className="text-sm font-bold">Profile updated successfully!</p>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { X, Calendar, Clock, User, Briefcase, DollarSign } from 'lucide-react';
import { Appointment } from '../types';

interface AddAppointmentModalProps {
  onClose: () => void;
  onAdd: (appointment: Appointment) => void;
  clients: any[];
  services: any[];
}

const AddAppointmentModal: React.FC<AddAppointmentModalProps> = ({ onClose, onAdd, clients, services }) => {
  const [formData, setFormData] = useState({
    clientName: '',
    service: services[0]?.name || '',
    date: new Date().toISOString().split('T')[0],
    time: '09:00',
    price: services[0]?.price || 0
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const service = services.find(s => s.name === formData.service);
    const newApt: Appointment = {
      id: Math.random().toString(36).substr(2, 9),
      clientId: 'manual',
      clientName: formData.clientName,
      service: formData.service,
      date: formData.date,
      time: formData.time,
      duration: service?.duration || 60,
      status: 'confirmed',
      price: formData.price
    };
    onAdd(newApt);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-sm animate-in fade-in">
      <div className="bg-white w-full max-w-lg rounded-[40px] overflow-hidden shadow-2xl animate-in zoom-in-95">
        <div className="p-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-2xl font-bold text-gray-900">New Appointment</h2>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full"><X size={24} /></button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Client</label>
              <input required list="clients" value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} className="w-full bg-gray-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-indigo-600 outline-none" placeholder="Search or type name..." />
              <datalist id="clients">{clients.map(c => <option key={c.id} value={c.name} />)}</datalist>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Service</label>
                <select value={formData.service} onChange={(e) => {
                  const s = services.find(x => x.name === e.target.value);
                  setFormData({...formData, service: e.target.value, price: s?.price || 0});
                }} className="w-full bg-gray-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-indigo-600 outline-none appearance-none">
                  {services.map(s => <option key={s.name} value={s.name}>{s.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Price</label>
                <input type="number" value={formData.price} onChange={(e) => setFormData({...formData, price: Number(e.target.value)})} className="w-full bg-gray-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-indigo-600 outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <input type="date" value={formData.date} onChange={(e) => setFormData({...formData, date: e.target.value})} className="w-full bg-gray-50 border-none rounded-2xl p-4" />
              <input type="time" value={formData.time} onChange={(e) => setFormData({...formData, time: e.target.value})} className="w-full bg-gray-50 border-none rounded-2xl p-4" />
            </div>

            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">
              Add to Schedule
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

