import React, { useState } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Phone, MapPin, Instagram, Facebook, Share2 } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState("");
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const timeSlots = ["09:00", "10:00", "11:00", "13:00", "14:00", "15:00", "16:00"];

  const handleBook = () => {
    setIsSubmitting(true);
    setTimeout(() => {
      const newBooking = {
        id: Math.random().toString(36).substr(2, 9),
        clientName: clientInfo.name,
        service: selectedService.name,
        date: selectedDate,
        time: selectedTime,
        duration: selectedService.duration,
        status: 'pending',
        price: selectedService.price
      };
      onBookingComplete(newBooking);
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-[32px] flex items-center justify-center mb-8 shadow-xl">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-4xl font-black text-gray-900 mb-4">Confirmed!</h2>
        <p className="text-gray-500 mb-12 max-w-sm">We've scheduled your <strong>{selectedService?.name}</strong> at {businessName}.</p>
        <button onClick={() => window.location.reload()} className="w-full max-w-xs py-5 bg-gray-900 text-white rounded-3xl font-bold shadow-2xl">Done</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white md:bg-gray-50 pb-20 font-sans">
      <div className="bg-indigo-600 text-white pt-16 pb-32 px-6 text-center relative">
        <h1 className="text-4xl font-black mb-2">{businessName}</h1>
        <p className="text-indigo-100 font-medium uppercase text-xs">Book an appointment</p>
        {onBack && <button onClick={onBack} className="absolute top-6 left-6 px-4 py-2 bg-white/10 rounded-xl text-xs font-bold">BACK TO ADMIN</button>}
      </div>

      <div className="max-w-3xl mx-auto -mt-20 px-4">
        <div className="bg-white rounded-[40px] shadow-2xl p-6 md:p-10 border border-indigo-50">
          <div className="flex justify-between items-center mb-10">
            {[1, 2, 3].map((s) => (
              <div key={s} className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black text-sm ${step >= s ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-400'}`}>
                {s}
              </div>
            ))}
          </div>

          {step === 1 && (
            <div className="space-y-4">
              <h2 className="text-2xl font-black text-gray-900 mb-6">Select a service</h2>
              {services.map((service) => (
                <button key={service.name} onClick={() => { setSelectedService(service); setStep(2); }} className="w-full bg-gray-50 p-6 rounded-[28px] border-2 border-transparent hover:border-indigo-600 hover:bg-white transition-all text-left">
                  <p className="font-black text-gray-900 text-lg">{service.name}</p>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">{service.duration} mins • ${service.price}</p>
                </button>
              ))}
            </div>
          )}

          {step === 2 && (
            <div className="space-y-6">
              <h2 className="text-2xl font-black text-gray-900 mb-2">Choose time</h2>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                {timeSlots.map((time) => (
                  <button key={time} onClick={() => { setSelectedTime(time); setSelectedDate('2024-05-16'); setStep(3); }} className="bg-gray-50 py-5 rounded-[20px] font-black text-gray-700 hover:bg-gray-900 hover:text-white transition-all">
                    {time}
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6">
              <h2 className="text-2xl font-black text-gray-900 mb-8">Your details</h2>
              <div className="space-y-4">
                <input placeholder="Name" className="w-full bg-gray-50 border-none rounded-[20px] py-4 px-6 font-bold" value={clientInfo.name} onChange={(e) => setClientInfo({...clientInfo, name: e.target.value})} />
                <input placeholder="Email" className="w-full bg-gray-50 border-none rounded-[20px] py-4 px-6 font-bold" value={clientInfo.email} onChange={(e) => setClientInfo({...clientInfo, email: e.target.value})} />
                <button onClick={handleBook} disabled={isSubmitting || !clientInfo.name} className="w-full py-6 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100">{isSubmitting ? 'BOOKING...' : 'CONFIRM'}</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PublicBookingPage;

