import React, { useState } from 'react';
import { Save, Building2, Palette, Trash2, Plus, Clock, X, Check } from 'lucide-react';

interface SettingsProps {
  businessName: string;
  onUpdateBusinessName: (name: string) => void;
  services: any[];
  onUpdateServices: (services: any[]) => void;
  theme: string;
  onUpdateTheme: (theme: string) => void;
}

const Settings: React.FC<SettingsProps> = ({ businessName, onUpdateBusinessName, services, onUpdateServices, theme, onUpdateTheme }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'services' | 'theme'>('profile');
  const [name, setName] = useState(businessName);
  const [newService, setNewService] = useState({ name: '', price: '', duration: '' });

  const handleSaveProfile = () => {
    onUpdateBusinessName(name);
  };

  const handleAddService = () => {
    if (!newService.name || !newService.price) return;
    onUpdateServices([...services, { 
      name: newService.name, 
      price: Number(newService.price), 
      duration: Number(newService.duration) || 60 
    }]);
    setNewService({ name: '', price: '', duration: '' });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex items-center justify-between border-b theme-border pb-6">
        <h2 className="text-4xl serif italic">Atelier Settings</h2>
        <div className="flex gap-1 bg-stone-100 p-1 rounded-full">
          {['profile', 'services', 'theme'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`px-6 py-2 rounded-full text-[9px] font-bold uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white shadow-sm text-stone-900' : 'text-stone-400'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'profile' && (
        <section className="bg-white p-12 rounded-[40px] border theme-border luxury-shadow space-y-8">
           <div className="space-y-4">
              <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">Business Identity</label>
              <input 
                type="text" 
                value={name} 
                onChange={(e) => setName(e.target.value)}
                className="w-full text-3xl serif italic border-b theme-border py-4 focus:ring-0 focus:border-stone-900 transition-all bg-transparent"
              />
           </div>
           <button onClick={handleSaveProfile} className="px-10 py-4 bg-stone-900 text-white rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-stone-800">
             Confirm Changes
           </button>
        </section>
      )}

      {activeTab === 'theme' && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[
            { id: 'luxury', name: 'Maison', colors: 'bg-[#1A1A1A] border-[#D4AF37]' },
            { id: 'modern', name: 'Studio', colors: 'bg-[#4F46E5] border-[#4F46E5]' },
            { id: 'organic', name: 'Retreat', colors: 'bg-[#365314] border-[#65A30D]' },
          ].map(t => (
            <button 
              key={t.id}
              onClick={() => onUpdateTheme(t.id)}
              className={`p-10 bg-white border-2 rounded-[40px] flex flex-col items-center gap-6 transition-all ${theme === t.id ? 'border-stone-900 scale-105' : 'border-stone-100 opacity-60'}`}
            >
              <div className={`w-16 h-16 rounded-3xl ${t.colors} border-4`} />
              <div className="text-center">
                <p className="text-xl serif italic">{t.name}</p>
                {theme === t.id && <p className="text-[9px] font-bold text-stone-900 uppercase tracking-[0.2em] mt-2 flex items-center gap-1 justify-center"><Check size={10}/> Active Signature</p>}
              </div>
            </button>
          ))}
        </div>
      )}

      {activeTab === 'services' && (
        <section className="bg-white p-12 rounded-[40px] border theme-border luxury-shadow">
          <div className="space-y-6">
             {services.map((s, i) => (
               <div key={i} className="flex items-center justify-between py-6 border-b theme-border last:border-0">
                  <div>
                    <p className="text-2xl serif italic">{s.name}</p>
                    <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">${s.price} • {s.duration} minutes</p>
                  </div>
                  <button onClick={() => onUpdateServices(services.filter((_, idx) => idx !== i))} className="text-stone-300 hover:text-red-500"><X size={20} strokeWidth={1}/></button>
               </div>
             ))}
             <div className="pt-8 grid grid-cols-1 md:grid-cols-3 gap-4">
                <input placeholder="New Service..." className="col-span-1 border-b py-2 text-sm serif italic" value={newService.name} onChange={e => setNewService({...newService, name: e.target.value})} />
                <input placeholder="Price..." className="border-b py-2 text-sm serif italic" value={newService.price} onChange={e => setNewService({...newService, price: e.target.value})} />
                <button onClick={handleAddService} className="bg-stone-100 py-3 rounded-full text-[9px] font-bold uppercase tracking-widest hover:bg-stone-200">Add Service</button>
             </div>
          </div>
        </section>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Sparkles } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  theme: string;
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, theme, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  useEffect(() => {
    document.body.setAttribute('data-theme', theme);
  }, [theme]);

  const handleBook = () => {
    setIsSubmitting(true);
    setTimeout(() => {
      onBookingComplete({ id: Math.random().toString(36).substr(2, 9), clientName: clientInfo.name, service: selectedService.name, date: '2024-05-16', time: selectedTime, duration: selectedService.duration, status: 'pending', price: selectedService.price });
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 2000);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-1000">
        <Sparkles size={64} className="theme-accent mb-8" strokeWidth={1} />
        <h2 className="text-6xl serif italic mb-6">Confirmed</h2>
        <p className="text-stone-500 mb-12 max-w-sm serif italic">Your reservation at {businessName} is secured.</p>
        <button onClick={() => window.location.reload()} className="px-16 py-5 theme-primary-bg text-white rounded-full font-bold uppercase tracking-[0.3em] text-[10px] shadow-2xl">Finish</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen font-sans">
      <div className="h-[40vh] theme-primary-bg flex flex-col items-center justify-center text-center px-6 relative overflow-hidden">
        <h1 className="text-7xl font-normal text-white serif italic tracking-tighter relative z-10">{businessName}</h1>
        {onBack && <button onClick={onBack} className="absolute top-10 left-10 text-white/50 text-[9px] font-bold uppercase tracking-widest hover:text-white flex items-center gap-2"><ArrowLeft size={12}/> ADMIN EXIT</button>}
      </div>

      <div className="max-w-4xl mx-auto -mt-20 pb-24 px-4 relative z-20">
        <div className="bg-white rounded-[40px] border theme-border shadow-2xl overflow-hidden p-10 md:p-20">
           <div className="flex justify-center gap-12 mb-16 opacity-30 text-[9px] font-bold uppercase tracking-[0.5em]">
              <span className={step >= 1 ? "theme-accent opacity-100" : ""}>Service</span>
              <span className={step >= 2 ? "theme-accent opacity-100" : ""}>Schedule</span>
              <span className={step >= 3 ? "theme-accent opacity-100" : ""}>GUEST</span>
           </div>

           {step === 1 && (
             <div className="space-y-8 animate-in fade-in duration-700">
                <h2 className="text-4xl serif italic text-center mb-12">Select Experience</h2>
                <div className="space-y-4">
                   {services.map(s => (
                     <button key={s.name} onClick={() => {setSelectedService(s); setStep(2);}} className="w-full flex items-center justify-between p-10 border-b theme-border hover:theme-accent transition-all text-left">
                        <span className="text-3xl serif italic">{s.name}</span>
                        <span className="text-xl serif italic">${s.price}</span>
                     </button>
                   ))}
                </div>
             </div>
           )}

           {step === 2 && (
             <div className="space-y-12 animate-in fade-in duration-700 text-center">
                <h2 className="text-4xl serif italic">Availability</h2>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  {["09:00", "11:00", "13:00", "15:00", "17:00"].map(t => (
                    <button key={t} onClick={() => {setSelectedTime(t); setStep(3);}} className="py-6 border theme-border rounded-2xl serif italic text-2xl hover:theme-primary-bg hover:text-white transition-all">{t}</button>
                  ))}
                </div>
             </div>
           )}

           {step === 3 && (
             <div className="max-w-md mx-auto space-y-10 animate-in fade-in duration-700">
                <div className="text-center">
                   <h2 className="text-4xl serif italic mb-2">Guest Details</h2>
                   <p className="text-[10px] font-bold uppercase tracking-widest opacity-40">{selectedService?.name} • {selectedTime}</p>
                </div>
                <div className="space-y-6">
                   <input placeholder="FULL NAME" className="w-full bg-stone-50 border-0 border-b theme-border py-4 px-2 text-sm font-bold tracking-widest focus:ring-0" value={clientInfo.name} onChange={e => setClientInfo({...clientInfo, name: e.target.value})} />
                   <input placeholder="EMAIL ADDRESS" className="w-full bg-stone-50 border-0 border-b theme-border py-4 px-2 text-sm font-bold tracking-widest focus:ring-0" value={clientInfo.email} onChange={e => setClientInfo({...clientInfo, email: e.target.value})} />
                </div>
                <button onClick={handleBook} disabled={isSubmitting || !clientInfo.name} className="w-full py-6 theme-primary-bg text-white rounded-full text-[10px] font-bold uppercase tracking-[0.4em] shadow-2xl hover:opacity-90">{isSubmitting ? 'SECURING...' : 'CONFIRM RESERVATION'}</button>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default PublicBookingPage;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Download } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);

  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded]);

  const handleOnboardingComplete = (data: { name: string; category: string }) => {
    setBusinessName(data.name);
    setBusinessCategory(data.category);
    setIsOnboarded(true);
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
    const exists = clients.some(c => c.name === newBooking.clientName);
    if (!exists) {
      setClients(prev => [...prev, {
        id: Math.random().toString(36).substr(2, 9),
        name: newBooking.clientName,
        email: 'customer@email.com',
        phone: 'Not provided',
      }]);
    }
  };

  if (!isOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return <AppointmentCalendar appointments={appointments} onAddClick={() => setShowAddModal(true)} />;
      case 'clients':
        return (
          <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm animate-in fade-in duration-500">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h2 className="text-2xl font-bold text-gray-900">Clients</h2>
                <p className="text-sm text-gray-500">Manage your customer database</p>
              </div>
              <button className="flex items-center gap-2 px-4 py-2 bg-gray-50 text-gray-600 rounded-xl hover:bg-gray-100 transition-colors font-bold text-xs">
                <Download size={14} /> Export CSV
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {clients.map(client => (
                <div key={client.id} className="p-6 border border-gray-100 rounded-2xl hover:border-indigo-300 transition-all bg-white hover:shadow-lg">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center font-bold">
                      {client.name.charAt(0)}
                    </div>
                    <div className="min-w-0">
                      <p className="font-bold text-gray-900 truncate">{client.name}</p>
                      <p className="text-xs text-gray-400 truncate">{client.email}</p>
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-50 flex justify-between items-center text-xs">
                    <span className="text-gray-500 font-medium">{client.phone}</span>
                    <button className="font-bold text-indigo-600 hover:underline">View Profile</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={setBusinessName} 
            services={services}
            onUpdateServices={setServices}
          />
        );
      default:
        return <Dashboard businessName={businessName} appointments={appointments} clients={clients} onOpenPublicView={() => setIsPublicView(true)} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b flex items-center justify-between px-8 shrink-0 z-20">
          <div className="flex items-center gap-3">
             <div className="md:hidden w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
               <Sparkles size={16} />
             </div>
             <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">{businessCategory}</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 bg-gray-50 rounded-full px-4 py-2 border border-gray-100 mr-4">
              <Search size={14} className="text-gray-400" />
              <input type="text" placeholder="Global search..." className="bg-transparent border-none text-xs focus:outline-none w-40" />
            </div>
            <button className="text-gray-400 hover:text-indigo-600 transition-colors"><Bell size={20} /></button>
            <div className="flex items-center gap-3 border-l border-gray-100 pl-4 ml-2">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-bold text-gray-900 leading-none">{businessName}</p>
              </div>
              <div className="w-9 h-9 rounded-full bg-indigo-600 flex items-center justify-center text-white text-xs font-bold">
                {businessName.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 max-w-7xl mx-auto w-full">
          {renderContent()}
        </div>
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
        />
      )}
    </div>
  );
};

export default App;

