import React, { useEffect, useState } from 'react';
import { Appointment, Client } from '../types';
import { TrendingUp, Users, CalendarCheck, Globe, QrCode, Zap, MapPin, Sparkles } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';

interface DashboardProps {
  businessName: string;
  appointments: Appointment[];
  clients: Client[];
  onOpenPublicView: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ businessName, appointments, clients, onOpenPublicView }) => {
  const [aiSummary, setAiSummary] = useState<string>("Analyzing your schedule...");

  useEffect(() => {
    const fetchAiSummary = async () => {
      const summary = await geminiAssistant.getSummary(appointments);
      setAiSummary(summary || "No insights available.");
    };
    fetchAiSummary();
  }, [appointments]);

  const stats = [
