import React, { useState } from 'react';
import { Save, Building2, Trash2, Plus, Clock, X, Check, Shield } from 'lucide-react';

interface SettingsProps {
  businessName: string;
  onUpdateBusinessName: (name: string) => void;
  services: any[];
  onUpdateServices: (services: any[]) => void;
}

const Settings: React.FC<SettingsProps> = ({ businessName, onUpdateBusinessName, services, onUpdateServices }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'services'>('profile');
  const [name, setName] = useState(businessName);
  const [newService, setNewService] = useState({ name: '', price: '', duration: '' });

  const handleSaveProfile = () => {
    onUpdateBusinessName(name);
  };

  const handleAddService = () => {
    if (!newService.name || !newService.price) return;
    onUpdateServices([...services, { 
      name: newService.name, 
      price: Number(newService.price), 
      duration: Number(newService.duration) || 60 
    }]);
    setNewService({ name: '', price: '', duration: '' });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex items-center justify-between border-b border-slate-200 pb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-900">Settings</h2>
          <p className="text-sm text-slate-500">Manage your business preferences</p>
        </div>
        <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
          {['profile', 'services'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`px-6 py-2 rounded-lg text-xs font-bold uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'profile' && (
        <section className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm space-y-8">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Business Name</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-slate-50 border-none rounded-xl py-3 px-4 font-bold text-slate-900 focus:ring-2 focus:ring-indigo-600 transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Business Category</label>
                <select className="w-full bg-slate-50 border-none rounded-xl py-3 px-4 font-bold text-slate-900 focus:ring-2 focus:ring-indigo-600">
                  <option>Professional Services</option>
                  <option>Beauty & Health</option>
                  <option>Retail</option>
                </select>
              </div>
           </div>
           <div className="pt-4 flex justify-end">
             <button onClick={handleSaveProfile} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2">
               <Save size={18} /> Save Changes
             </button>
           </div>
        </section>
      )}

      {activeTab === 'services' && (
        <section className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm space-y-6">
          <div className="space-y-4">
             {services.map((s, i) => (
               <div key={i} className="flex items-center justify-between py-4 border-b border-slate-50 last:border-0">
                  <div>
                    <p className="font-bold text-slate-900">{s.name}</p>
                    <p className="text-xs text-slate-500">${s.price} • {s.duration} mins</p>
                  </div>
                  <button onClick={() => onUpdateServices(services.filter((_, idx) => idx !== i))} className="p-2 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all">
                    <Trash2 size={18} />
                  </button>
               </div>
             ))}

             <div className="pt-6 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                <div className="md:col-span-2 space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Service Name</label>
                  <input placeholder="Deep Tissue Massage" className="w-full bg-slate-50 border-none rounded-xl py-3 px-4 text-sm" value={newService.name} onChange={e => setNewService({...newService, name: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Price ($)</label>
                  <input type="number" placeholder="99" className="w-full bg-slate-50 border-none rounded-xl py-3 px-4 text-sm" value={newService.price} onChange={e => setNewService({...newService, price: e.target.value})} />
                </div>
                <button onClick={handleAddService} className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold text-xs hover:bg-black transition-all">
                  Add Service
                </button>
             </div>
          </div>
        </section>
      )}

      <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 flex items-center gap-4">
        <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-indigo-600 shadow-sm">
          <Shield size={24} />
        </div>
        <div>
          <h4 className="font-bold text-slate-900 text-sm">Automated Backups</h4>
          <p className="text-xs text-slate-500">Your business data is safely stored and encrypted in the cloud.</p>
        </div>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Sparkles } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleBook = () => {
    setIsSubmitting(true);
    setTimeout(() => {
      onBookingComplete({ id: Math.random().toString(36).substr(2, 9), clientName: clientInfo.name, service: selectedService.name, date: '2024-05-16', time: selectedTime, duration: selectedService.duration, status: 'pending', price: selectedService.price });
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-3xl flex items-center justify-center mb-8 shadow-lg shadow-emerald-100">
          <CheckCircle2 size={40} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4">Appointment Confirmed!</h2>
        <p className="text-slate-500 mb-10 max-w-sm">We've scheduled your <strong>{selectedService?.name}</strong> at {businessName}. We'll send a confirmation email shortly.</p>
        <button onClick={() => window.location.reload()} className="w-full max-w-xs py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Done</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <div className="bg-indigo-600 pt-16 pb-32 px-6 text-center text-white relative">
        <h1 className="text-4xl font-black mb-2 tracking-tight">{businessName}</h1>
        <p className="text-indigo-100 text-sm font-medium uppercase tracking-widest">Book your session</p>
        {onBack && <button onClick={onBack} className="absolute top-8 left-8 bg-white/10 hover:bg-white/20 p-2 rounded-xl text-xs font-bold flex items-center gap-2 transition-all"><ArrowLeft size={16} /> BACK</button>}
      </div>

      <div className="max-w-3xl mx-auto -mt-20 px-4 pb-20 relative z-20">
        <div className="bg-white rounded-[40px] shadow-2xl overflow-hidden p-8 md:p-12 border border-indigo-50">
           <div className="flex justify-between items-center mb-12">
              {[1, 2, 3].map((s) => (
                <div key={s} className="flex flex-col items-center gap-2">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-sm font-black transition-all ${step >= s ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-100 text-slate-400'}`}>
                    {s}
                  </div>
                  <span className={`text-[9px] font-bold uppercase tracking-widest ${step >= s ? 'text-indigo-600' : 'text-slate-300'}`}>
                    {s === 1 ? 'Service' : s === 2 ? 'Schedule' : 'Details'}
                  </span>
                </div>
              ))}
           </div>

           {step === 1 && (
             <div className="space-y-4 animate-in fade-in duration-500">
                <h2 className="text-2xl font-black text-slate-900 mb-8">What do you need?</h2>
                <div className="grid grid-cols-1 gap-4">
                   {services.map(s => (
                     <button key={s.name} onClick={() => {setSelectedService(s); setStep(2);}} className="flex items-center justify-between p-6 bg-slate-50 border border-transparent rounded-2xl hover:border-indigo-600 hover:bg-white transition-all text-left group">
                        <div>
                          <p className="font-bold text-slate-900 text-lg group-hover:text-indigo-600 transition-colors">{s.name}</p>
                          <p className="text-xs text-slate-500">{s.duration} mins</p>
                        </div>
                        <div className="text-right">
                          <p className="font-black text-slate-900 text-lg">${s.price}</p>
                          <span className="text-[10px] font-bold text-indigo-600 uppercase">Select</span>
                        </div>
                     </button>
                   ))}
                </div>
             </div>
           )}

           {step === 2 && (
             <div className="space-y-10 animate-in fade-in duration-500 text-center">
                <h2 className="text-2xl font-black text-slate-900">Choose a time</h2>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  {["09:00", "10:30", "12:00", "14:00", "15:30", "17:00", "18:30"].map(t => (
                    <button key={t} onClick={() => {setSelectedTime(t); setStep(3);}} className="py-5 bg-slate-50 rounded-2xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all shadow-sm">
                      {t}
                    </button>
                  ))}
                </div>
                <button onClick={() => setStep(1)} className="text-xs font-bold text-slate-400 uppercase tracking-widest hover:text-indigo-600">Change Service</button>
             </div>
           )}

           {step === 3 && (
             <div className="max-w-md mx-auto space-y-8 animate-in fade-in duration-500">
                <div className="text-center">
                   <h2 className="text-2xl font-black text-slate-900 mb-2">Final Details</h2>
                   <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest">{selectedService?.name} • {selectedTime}</p>
                </div>
                <div className="space-y-4">
                   <div className="space-y-1">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Your Name</label>
                     <input type="text" placeholder="John Doe" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-bold focus:ring-2 focus:ring-indigo-600" value={clientInfo.name} onChange={e => setClientInfo({...clientInfo, name: e.target.value})} />
                   </div>
                   <div className="space-y-1">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
                     <input type="email" placeholder="john@example.com" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-bold focus:ring-2 focus:ring-indigo-600" value={clientInfo.email} onChange={e => setClientInfo({...clientInfo, email: e.target.value})} />
                   </div>
                </div>
                <button 
                  onClick={handleBook} 
                  disabled={isSubmitting || !clientInfo.name || !clientInfo.email} 
                  className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 transition-all"
                >
                  {isSubmitting ? 'BOOKING...' : 'CONFIRM APPOINTMENT'}
                </button>
                <button onClick={() => setStep(2)} className="w-full text-xs font-bold text-slate-400 uppercase tracking-widest text-center">Change Time</button>
             </div>
           )}
        </div>

        <p className="text-center text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-12">Powered by Bookly Intelligence</p>
      </div>
    </div>
  );
};

