import { GoogleGenAI } from "@google/genai";

const MarketingStudio: React.FC = () => {
  const [prompt, setPrompt] = useState("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<{ image?: string; caption?: string } | null>(null);

  const generateCampaign = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      // 1. Generate Image using gemini-2.5-flash-image
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: `A professional, high-quality promotional poster for a business service: ${prompt}. Minimalist, aesthetic, clean layout.` }] },
        config: { imageConfig: { aspectRatio: "1:1" } }
      });

      let base64Image = "";
      for (const part of imgResponse.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) base64Image = `data:image/png;base64,${part.inlineData.data}`;
      }

      // 2. Generate Caption using gemini-3-flash-preview
      const textResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a compelling Instagram caption with hashtags for this promotion: ${prompt}`,
      });

      setResult({
        image: base64Image,
        caption: textResponse.text || "Get ready for our new special offer! #Business #Promotion"
      });
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      <header className="flex items-center justify-between border-b border-slate-200 pb-6">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Marketing Studio</h2>
          <p className="text-slate-500 text-sm font-medium">Create high-converting content with Gemini AI</p>
        </div>
        <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
          <Megaphone size={20} />
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 items-start">
        <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-sm space-y-8">
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">What's your promotion?</label>
            <textarea 
              rows={4}
              placeholder="e.g. Summer special: 20% off all consultations booked before July..." 
              className="w-full bg-slate-50 border-none rounded-3xl p-6 text-sm font-medium focus:ring-2 focus:ring-indigo-600 outline-none resize-none"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
          </div>

          <button 
            onClick={generateCampaign}
            disabled={isGenerating || !prompt}
            className="w-full py-5 bg-slate-900 text-white rounded-[24px] font-black shadow-xl flex items-center justify-center gap-3 hover:bg-black transition-all disabled:opacity-50"
          >
            {isGenerating ? (
              <>
                <Loader2 size={20} className="animate-spin" />
                Engineering Content...
              </>
            ) : (
              <>
                <Wand2 size={20} />
                Generate Campaign
              </>
            )}
          </button>

          <div className="pt-4 grid grid-cols-2 gap-4">
             <div className="p-4 bg-indigo-50/50 rounded-2xl border border-indigo-100 flex items-center gap-3">
                <ImageIcon size={20} className="text-indigo-600" />
                <span className="text-[10px] font-bold text-indigo-600 uppercase">AI Poster Gen</span>
             </div>
             <div className="p-4 bg-emerald-50/50 rounded-2xl border border-emerald-100 flex items-center gap-3">
                <Copy size={20} className="text-emerald-600" />
                <span className="text-[10px] font-bold text-emerald-600 uppercase">Ad Copywriter</span>
             </div>
          </div>
        </div>

        <div className="space-y-8">
          {result ? (
            <div className="animate-in slide-in-from-bottom-4 duration-700 space-y-8">
              <div className="bg-white rounded-[40px] overflow-hidden shadow-2xl border border-slate-100">
                 {result.image && <img src={result.image} alt="Promotion" className="w-full aspect-square object-cover" />}
                 <div className="p-8">
                    <div className="flex items-center justify-between mb-4">
                       <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Suggested Caption</span>
                       <button className="text-indigo-600 hover:scale-110 transition-transform"><Copy size={16} /></button>
                    </div>
                    <p className="text-sm text-slate-700 leading-relaxed font-medium">
                      {result.caption}
                    </p>
                 </div>
              </div>
              <button className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg">
                <Download size={18} /> Export Assets
              </button>
            </div>
          ) : (
            <div className="h-full min-h-[400px] border-4 border-dashed border-slate-100 rounded-[40px] flex flex-col items-center justify-center text-center p-12 text-slate-300">
               <Sparkles size={48} className="mb-4 opacity-20" />
               <p className="font-bold text-sm">Input your idea to the left to see the magic happen.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default MarketingStudio;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import MarketingStudio from './components/MarketingStudio';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Download, Trophy } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);

  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded]);

  const handleOnboardingComplete = (data: { name: string; category: string }) => {
    setBusinessName(data.name);
    setBusinessCategory(data.category);
    setIsOnboarded(true);
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
  };

  if (!isOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return <AppointmentCalendar appointments={appointments} onAddClick={() => setShowAddModal(true)} />;
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm animate-in fade-in duration-500 pb-20">
            <div className="flex items-center justify-between mb-12">
              <div>
                <h2 className="text-3xl font-black text-gray-900">Clients</h2>
                <p className="text-sm text-gray-500 mt-1">Nurture your business relationships</p>
              </div>
              <button className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl hover:bg-black transition-all font-bold text-xs shadow-lg">
                <Plus size={14} /> Add Client
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {clients.map((client, idx) => (
                <div key={client.id} className="p-8 border border-gray-50 rounded-3xl hover:border-indigo-200 transition-all bg-white hover:shadow-2xl relative group">
                  {idx < 2 && (
                    <div className="absolute top-4 right-4 bg-amber-50 text-amber-600 px-3 py-1 rounded-full flex items-center gap-1.5 border border-amber-100">
                      <Trophy size={12} />
                      <span className="text-[10px] font-black uppercase tracking-tight">VIP Client</span>
                    </div>
                  )}
                  <div className="flex items-center gap-6 mb-8">
                    <div className="w-16 h-16 bg-slate-50 text-slate-400 border border-slate-100 rounded-[24px] flex items-center justify-center text-xl font-black group-hover:bg-indigo-600 group-hover:text-white transition-all">
                      {client.name.charAt(0)}
                    </div>
                    <div className="min-w-0">
                      <p className="text-xl font-black text-gray-900 truncate tracking-tight">{client.name}</p>
                      <p className="text-xs text-gray-400 font-medium truncate">{client.email}</p>
                    </div>
                  </div>
                  <div className="pt-6 border-t border-gray-50 flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400">{client.phone}</span>
                    <button className="text-indigo-600 hover:underline">View History</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={setBusinessName} 
            services={services}
            onUpdateServices={setServices}
          />
        );
      default:
        return <Dashboard businessName={businessName} appointments={appointments} clients={clients} onOpenPublicView={() => setIsPublicView(true)} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b flex items-center justify-between px-10 shrink-0 z-20">
          <div className="flex items-center gap-3">
             <div className="md:hidden w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
               <Sparkles size={16} />
             </div>
             <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">{businessCategory}</span>
          </div>
          <div className="flex items-center gap-6">
            <button className="text-gray-300 hover:text-indigo-600 transition-colors"><Bell size={20} strokeWidth={2} /></button>
            <div className="flex items-center gap-4 border-l border-gray-100 pl-6 ml-2">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-gray-900 leading-none">{businessName}</p>
              </div>
              <div className="w-10 h-10 rounded-[14px] bg-slate-900 flex items-center justify-center text-white text-xs font-black shadow-lg">
                {businessName.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 max-w-7xl mx-auto w-full custom-scroll">
          {renderContent()}
        </div>
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2, Mic, MicOff, Volume2 } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';
import { Appointment, Client } from '../types';
import { GoogleGenAI, Modality } from '@google/genai';

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

const AIAssistant: React.FC<{ appointments: Appointment[], clients: Client[] }> = ({ appointments, clients }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Hi! I'm Bookly's AI. How can I help with your business today?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Ref for Live session
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);
    try {
      const response = await geminiAssistant.analyzeSchedule(appointments, clients, userMsg);
      setMessages(prev => [...prev, { role: 'assistant', content: response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Connection error. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceMode = async () => {
    if (isVoiceMode) {
      setIsVoiceMode(false);
      if (sessionRef.current) sessionRef.current.close();
      return;
    }

    setIsVoiceMode(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: 'You are the Bookly Voice Concierge. Help the business owner manage their day conversationally.',
        },
        callbacks: {
          onopen: () => console.log('Live connected'),
          onmessage: (msg) => {
            // Handle audio/transcription if needed
            if (msg.serverContent?.modelTurn) {
              // Audio is handled automatically by the SDK in some environments 
              // but we can add visual feedback here.
            }
          },
          onclose: () => setIsVoiceMode(false),
          onerror: () => setIsVoiceMode(false),
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsVoiceMode(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-[40px] border border-gray-100 shadow-2xl overflow-hidden mb-16 md:mb-0 relative">
      <div className="p-6 border-b bg-indigo-50/30 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-xl">
            <Bot size={22} />
          </div>
          <div>
            <h3 className="font-black text-gray-900">Intelligence Concierge</h3>
            <p className="text-[10px] text-indigo-600 flex items-center gap-1 font-black uppercase tracking-widest">
              <Sparkles size={10} /> Active Growth Agent
            </p>
          </div>
        </div>
        <button 
          onClick={toggleVoiceMode}
          className={`flex items-center gap-3 px-6 py-2.5 rounded-2xl font-bold text-xs transition-all ${isVoiceMode ? 'bg-red-500 text-white animate-pulse' : 'bg-white border border-slate-200 text-slate-600 hover:border-indigo-600'}`}
        >
          {isVoiceMode ? <><MicOff size={16}/> End Voice Mode</> : <><Mic size={16}/> Voice Concierge</>}
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8 bg-white custom-scroll">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 shadow-sm ${
                msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'
              }`}>
                {msg.role === 'user' ? <User size={14} /> : <Bot size={14} />}
              </div>
              <div className={`p-6 rounded-[28px] text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-slate-50 text-slate-800 border border-slate-100 rounded-tl-none font-medium'
              }`}>
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="flex gap-3 items-center text-indigo-600">
              <div className="w-8 h-8 rounded-xl bg-indigo-50 flex items-center justify-center animate-pulse">
                <Loader2 className="animate-spin" size={14} />
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest animate-pulse">Consulting Gemini...</span>
            </div>
          </div>
        )}
      </div>

      {isVoiceMode && (
        <div className="absolute inset-x-0 bottom-24 flex flex-col items-center justify-center p-12 bg-white/90 backdrop-blur-md animate-in slide-in-from-bottom-10">
           <div className="flex items-center gap-1 h-12">
             {[...Array(12)].map((_, i) => (
               <div key={i} className="w-1.5 bg-indigo-600 rounded-full animate-bounce" style={{ height: `${Math.random() * 100}%`, animationDelay: `${i * 0.1}s` }} />
             ))}
           </div>
           <p className="mt-6 text-xs font-black text-slate-900 uppercase tracking-widest">Listening to your command...</p>
        </div>
      )}

      <div className="p-6 border-t bg-white shrink-0">
        <div className="relative max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask anything about your business..."
            className="w-full bg-slate-50 border-none rounded-[24px] px-8 py-5 pr-20 focus:outline-none focus:ring-2 focus:ring-indigo-600 text-sm font-medium transition-all shadow-inner"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className={`absolute right-2.5 top-2.5 bottom-2.5 px-6 bg-slate-900 text-white rounded-[18px] hover:bg-black transition-all shadow-lg ${isLoading || !input.trim() ? 'opacity-30' : ''}`}
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

