interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleBook = () => {
    setIsSubmitting(true);
    setTimeout(() => {
      onBookingComplete({ 
        id: Math.random().toString(36).substr(2, 9), 
        clientName: clientInfo.name, 
        service: selectedService.name, 
        date: '2024-05-16', 
        time: selectedTime, 
        duration: selectedService.duration, 
        status: 'confirmed', 
        price: selectedService.price
      });
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-indigo-100">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4">Booking Confirmed!</h2>
        <p className="text-slate-500 mb-10 max-w-sm">Your appointment for <strong>{selectedService?.name}</strong> has been scheduled. See you on May 16th at {selectedTime}!</p>
        <button onClick={() => window.location.reload()} className="w-full max-w-xs py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:bg-indigo-700 transition-all">Back to Home</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      <div className="bg-indigo-600 pt-16 pb-32 px-6 text-center text-white relative overflow-hidden">
