  return (
    <div className="bg-white rounded-2xl md:border border-gray-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-4 md:p-6 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-lg md:text-xl font-bold text-gray-900">Schedule</h3>
          <p className="text-xs md:text-sm text-gray-500">Manage client sessions and reminders</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-2">
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors font-bold text-xs shadow-lg"
          >
            <Plus size={14} />
            New Appointment
          </button>
        </div>
      </div>

      <div className="p-4 md:p-6 space-y-8">
        {dates.length === 0 ? (
          <div className="text-center py-20 text-gray-400">
            <CalendarIcon size={40} className="mx-auto mb-4 opacity-10" />
            <p className="text-sm">No scheduled sessions.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 flex items-center gap-2 border-b border-slate-50 pb-2">
                {new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}
              </h4>
              <div className="space-y-3">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group flex items-center gap-4 p-4 rounded-2xl border border-slate-50 hover:border-indigo-100 hover:bg-slate-50 transition-all bg-white">
                    <div className="flex flex-col items-center justify-center w-16 text-center border-r border-slate-100 pr-4">
                      <span className="text-sm font-black text-slate-900 leading-tight">{apt.time}</span>
                      <span className="text-[9px] text-slate-400 font-bold uppercase">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <h5 className="font-bold text-slate-900 text-sm truncate">{apt.clientName}</h5>
                        <div className="flex items-center gap-2">
                          {apt.reminderSent && (
                            <span className="flex items-center gap-1 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-2 py-0.5 rounded-full">
                              <Bell size={10} /> Sent {apt.reminderTimestamp}
                            </span>
                          )}
                          {apt.status === 'confirmed' && (
                            <span className="flex items-center gap-1 text-[9px] font-black uppercase text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-full">
                              <CheckCircle2 size={10} /> Confirmed
                            </span>
                          )}
                        </div>
                      </div>
                      <p className="text-xs text-slate-500 truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0 flex items-center gap-4">
                      <p className="text-sm font-black text-slate-900 hidden sm:block">${apt.price}</p>
                      <button 
                        onClick={() => handleSendReminder(apt)}
                        disabled={sendingId === apt.id}
                        className={`p-2.5 rounded-xl transition-all ${apt.reminderSent ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-indigo-600 hover:bg-white shadow-sm hover:shadow-md'}`}
                        title="Send Reminder"
                      >
                        {sendingId === apt.id ? (
                          <Loader2 size={18} className="animate-spin" />
                        ) : apt.reminderSent ? (
                          <CheckCircle2 size={18} />
                        ) : (
                          <Send size={18} />
                        )}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default AppointmentCalendar;

