                autoFocus
                type="text" 
                placeholder="e.g. Zen Spa, Tech Studio..." 
                className="mt-2 w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-lg font-bold focus:ring-2 focus:ring-indigo-600 outline-none"
