                  {["09:00", "10:00", "11:00", "12:00", "13:30", "14:30", "15:30", "16:30", "17:30", "18:30"].map(t => (
                    <button 
                      key={t} 
                      onClick={() => {setSelectedTime(t); setStep(4);}} 
                      className={`py-6 rounded-2xl font-black text-lg transition-all border-2 ${
