import React, { useState, useMemo } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Phone, ShieldCheck, Check, CalendarDays } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  // Generate next 14 days for selection
  const availableDates = useMemo(() => {
    const dates = [];
    for (let i = 0; i < 14; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push({
        full: d.toISOString().split('T')[0],
        dayName: d.toLocaleDateString('en-US', { weekday: 'short' }),
        dayNum: d.getDate(),
        month: d.toLocaleDateString('en-US', { month: 'short' }),
        isToday: i === 0
      });
    }
    return dates;
  }, []);

  const handleBook = () => {
    setIsSubmitting(true);
    // Simulate API delay
    setTimeout(() => {
      onBookingComplete({ 
        id: Math.random().toString(36).substr(2, 9), 
        clientName: clientInfo.name, 
        service: selectedService.name, 
        date: selectedDate, 
        time: selectedTime, 
        duration: selectedService.duration, 
        status: 'confirmed', 
        price: selectedService.price,
        // In a real app, we would also save the phone and email to the client record
      });
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tight">Booking Confirmed!</h2>
        <p className="text-slate-500 mb-10 max-w-sm font-medium leading-relaxed">
          Your appointment for <span className="text-indigo-600 font-bold">{selectedService?.name}</span> with <strong>{businessName}</strong> is locked in for <br/>
          <span className="text-slate-900 font-bold">{new Date(selectedDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric' })} at {selectedTime}</span>.
        </p>
        <div className="flex flex-col gap-4 w-full max-w-xs">
          <button onClick={() => window.location.reload()} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:bg-indigo-700 transition-all active:scale-95">Done</button>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">A confirmation email has been sent</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      {/* Hero Header */}
      <div className="bg-slate-900 pt-20 pb-40 px-6 text-center text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/20 blur-[120px] rounded-full -translate-y-1/2 translate-x-1/2" />
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-emerald-600/10 blur-[100px] rounded-full translate-y-1/2 -translate-x-1/2" />

        <div className="relative z-10">
          <div className="w-12 h-12 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center mx-auto mb-6">
            <Calendar size={24} className="text-indigo-400" />
          </div>
          <h1 className="text-4xl font-black mb-3 tracking-tight">{businessName}</h1>
          <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-widest text-indigo-300 backdrop-blur-sm">
            <CheckCircle2 size={12} /> Official Booking Portal
          </div>
        </div>

        {onBack && (
          <button 
            onClick={onBack} 
            className="absolute top-8 left-8 bg-white/10 hover:bg-white/20 p-2.5 rounded-xl text-[10px] font-black flex items-center gap-2 transition-all z-20 uppercase tracking-widest"
          >
            <ArrowLeft size={16} /> Exit
          </button>
        )}
      </div>

      <div className="max-w-4xl mx-auto -mt-24 px-4 relative z-20">
        <div className="bg-white rounded-[40px] shadow-2xl overflow-hidden border border-slate-100">
          {/* Progress Bar */}
          <div className="flex justify-between items-center px-12 py-8 border-b border-slate-50 relative">
             <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-50 -z-10 translate-y-[-50%]" />
             {[1, 2, 3, 4].map((s) => (
               <div key={s} className="flex flex-col items-center gap-2 bg-white px-3 relative z-10">
                 <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs font-black transition-all duration-500 ${
                   step === s ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 scale-110' : 
                   step > s ? 'bg-emerald-500 text-white' : 'bg-slate-50 text-slate-300'
                 }`}>
                   {step > s ? <Check size={18} strokeWidth={4} /> : s}
                 </div>
               </div>
             ))}
          </div>

          <div className="p-8 md:p-12">
            {step === 1 && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center">
                  <h2 className="text-2xl font-black text-slate-900">Select a Service</h2>
                  <p className="text-sm text-slate-500 font-medium mt-1">What can we help you with today?</p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {services.map(s => (
                    <button 
                      key={s.name} 
                      onClick={() => {setSelectedService(s); setStep(2);}} 
                      className="flex flex-col p-8 bg-slate-50 border-2 border-transparent rounded-3xl hover:border-indigo-600 hover:bg-white transition-all text-left group hover:shadow-xl"
                    >
                      <div className="flex justify-between items-start mb-6 w-full">
                        <div className="p-3 bg-white rounded-2xl text-indigo-600 shadow-sm">
                          <Clock size={24} />
                        </div>
                        <p className="font-black text-slate-900 text-2xl">${s.price}</p>
                      </div>
                      <h3 className="font-black text-slate-900 text-xl group-hover:text-indigo-600 transition-colors mb-1">{s.name}</h3>
                      <p className="text-sm text-slate-400 font-bold uppercase tracking-tight">{s.duration} minutes session</p>
                    </button>
                  ))}
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center">
                  <h2 className="text-2xl font-black text-slate-900">Choose Date</h2>
                  <p className="text-sm text-slate-500 font-medium mt-1">Pick a day that works for you</p>
                </div>

                <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar -mx-2 px-2">
                  {availableDates.map(date => (
                    <button
                      key={date.full}
                      onClick={() => {setSelectedDate(date.full); setStep(3);}}
                      className={`flex flex-col items-center justify-center min-w-[80px] h-[110px] rounded-3xl border-2 transition-all ${
                        selectedDate === date.full ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-slate-50 border-transparent text-slate-400 hover:bg-white hover:border-indigo-200'
                      }`}
                    >
                      <span className={`text-[10px] font-black uppercase tracking-widest mb-1 ${selectedDate === date.full ? 'text-indigo-200' : 'text-slate-400'}`}>
                        {date.isToday ? 'Today' : date.dayName}
                      </span>
                      <span className="text-2xl font-black mb-1">{date.dayNum}</span>
                      <span className={`text-[10px] font-bold uppercase ${selectedDate === date.full ? 'text-indigo-100' : 'text-slate-400'}`}>
                        {date.month}
                      </span>
                    </button>
                  ))}
                </div>

                <div className="flex justify-center">
                  <button onClick={() => setStep(1)} className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 hover:text-slate-600">
                    <ArrowLeft size={14} /> Back to Services
                  </button>
                </div>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center">
                  <h2 className="text-2xl font-black text-slate-900">Pick a Time</h2>
                  <p className="text-sm text-slate-500 font-medium mt-1">Available slots for {new Date(selectedDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
                </div>

                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
                  {["09:00", "10:00", "11:00", "12:00", "13:30", "14:30", "15:30", "16:30", "17:30", "18:30"].map(t => (
                    <button 
                      key={t} 
                      onClick={() => {setSelectedTime(t); setStep(4);}} 
                      className={`py-6 rounded-2xl font-black text-lg transition-all border-2 ${
                        selectedTime === t ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-slate-50 border-transparent text-slate-700 hover:bg-white hover:border-indigo-600 hover:text-indigo-600'
                      }`}
                    >
                      {t}
                    </button>
                  ))}
                </div>

                <div className="flex justify-center">
                  <button onClick={() => setStep(2)} className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 hover:text-slate-600">
                    <ArrowLeft size={14} /> Back to Date
                  </button>
                </div>
              </div>
            )}

            {step === 4 && (
              <div className="max-w-md mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center p-6 bg-indigo-50 rounded-3xl">
                  <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-2">Booking Summary</p>
                  <h3 className="text-xl font-black text-slate-900 mb-1">{selectedService?.name}</h3>
                  <p className="text-sm font-bold text-slate-600">
                    {new Date(selectedDate).toLocaleDateString('en-US', { weekday: 'short', month: 'long', day: 'numeric' })} at {selectedTime}
                  </p>
                </div>

                <div className="space-y-5">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Name</label>
                    <div className="relative">
                      <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                      <input 
                        required
                        type="text" 
                        placeholder="e.g. Sarah Parker" 
                        className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 pl-12 pr-6 font-bold focus:bg-white focus:border-indigo-600 outline-none transition-all" 
                        value={clientInfo.name} 
                        onChange={e => setClientInfo({...clientInfo, name: e.target.value})} 
                      />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
                    <div className="relative">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                      <input 
                        required
                        type="email" 
