import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Download, Trophy, Crown } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);

  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => {
    return (localStorage.getItem('bookly_subscription_plan') as 'basic' | 'premium') || 'basic';
  });

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
    localStorage.setItem('bookly_subscription_plan', subscriptionPlan);
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan]);

  const handleOnboardingComplete = (data: { name: string; category: string }) => {
    setBusinessName(data.name);
    setBusinessCategory(data.category);
    setIsOnboarded(true);
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
  };

  const handleUpdateAppointment = (updatedApt: Appointment) => {
    setAppointments(prev => prev.map(apt => apt.id === updatedApt.id ? updatedApt : apt));
  };

  if (!isOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return (
          <AppointmentCalendar 
            appointments={appointments} 
            onAddClick={() => setShowAddModal(true)} 
            onUpdateAppointment={handleUpdateAppointment}
          />
        );
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm animate-in fade-in duration-500 pb-20">
            <div className="flex items-center justify-between mb-12">
              <div>
                <h2 className="text-3xl font-black text-gray-900">Clients</h2>
                <p className="text-sm text-gray-500 mt-1">Nurture your business relationships</p>
              </div>
              <button className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl hover:bg-black transition-all font-bold text-xs shadow-lg">
                <Plus size={14} /> Add Client
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {clients.map((client, idx) => (
                <div key={client.id} className="p-8 border border-gray-50 rounded-3xl hover:border-indigo-200 transition-all bg-white hover:shadow-2xl relative group">
                  {idx < 2 && (
                    <div className="absolute top-4 right-4 bg-amber-50 text-amber-600 px-3 py-1 rounded-full flex items-center gap-1.5 border border-amber-100">
                      <Trophy size={12} />
                      <span className="text-[10px] font-black uppercase tracking-tight">VIP Client</span>
                    </div>
                  )}
                  <div className="flex items-center gap-6 mb-8">
                    <div className="w-16 h-16 bg-slate-50 text-slate-400 border border-slate-100 rounded-[24px] flex items-center justify-center text-xl font-black group-hover:bg-indigo-600 group-hover:text-white transition-all">
                      {client.name.charAt(0)}
                    </div>
                    <div className="min-w-0">
                      <p className="text-xl font-black text-gray-900 truncate tracking-tight">{client.name}</p>
                      <p className="text-xs text-gray-400 font-medium truncate">{client.email}</p>
                    </div>
                  </div>
                  <div className="pt-6 border-t border-gray-50 flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400">{client.phone}</span>
                    <button className="text-indigo-600 hover:underline">View History</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={setSubscriptionPlan} />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={setBusinessName} 
            services={services}
            onUpdateServices={setServices}
          />
        );
      default:
        return <Dashboard businessName={businessName} appointments={appointments} clients={clients} onOpenPublicView={() => setIsPublicView(true)} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} subscriptionPlan={subscriptionPlan} />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b flex items-center justify-between px-10 shrink-0 z-20">
          <div className="flex items-center gap-3">
             <div className="md:hidden w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
               <Sparkles size={16} />
             </div>
             <div className="flex items-center gap-2">
               <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">{businessCategory}</span>
               {subscriptionPlan === 'premium' && (
                 <span className="bg-indigo-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded flex items-center gap-1">
                   <Crown size={8} /> PRO
                 </span>
               )}
             </div>
          </div>
          <div className="flex items-center gap-6">
            <button className="text-gray-300 hover:text-indigo-600 transition-colors"><Bell size={20} strokeWidth={2} /></button>
            <div className="flex items-center gap-4 border-l border-gray-100 pl-6 ml-2">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-gray-900 leading-none">{businessName}</p>
              </div>
              <div className="w-10 h-10 rounded-[14px] bg-slate-900 flex items-center justify-center text-white text-xs font-black shadow-lg">
                {businessName.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 max-w-7xl mx-auto w-full custom-scroll">
          {renderContent()}
        </div>
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Check, Zap, Shield, Rocket, Sparkles, Star, Loader2, Crown } from 'lucide-react';

interface PricingProps {
  currentPlan: 'basic' | 'premium';
  onPlanChange: (plan: 'basic' | 'premium') => void;
}

const Pricing: React.FC<PricingProps> = ({ currentPlan, onPlanChange }) => {
  const [billingCycle, setBillingCycle] = useState<'monthly' | 'annual'>('annual');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  const handleSelectPlan = (planId: 'basic' | 'premium') => {
    if (planId === currentPlan) return;
    setIsProcessing(planId);
    // Simulate payment/processing delay
    setTimeout(() => {
      onPlanChange(planId);
      setIsProcessing(null);
    }, 1500);
  };

  const plans = [
    {
      id: 'basic' as const,
      name: 'Basic',
      price: billingCycle === 'annual' ? 0 : 0,
      description: 'The fundamentals for getting your business online.',
      features: [
        'Up to 50 Appointments/mo',
        'Standard Client Profiles',
        'Basic Booking Portal',
        'Email Notifications',
        'Standard Support'
      ],
      icon: Rocket,
      buttonText: 'Current Plan',
      color: 'slate'
    },
    {
      id: 'premium' as const,
      name: 'Premium',
      price: billingCycle === 'annual' ? 29 : 35,
      description: 'Harness the full power of Gemini AI for rapid growth.',
      features: [
        'Everything in Basic',
        'Unlimited Appointments',
        'AI Marketing Studio (Gemini)',
        'Advanced Growth Advisor',
        'Voice Concierge Access',
        'White-labeled Booking Page',
        'Priority 24/7 Support'
      ],
      icon: Crown,
      buttonText: 'Upgrade to Premium',
      isPopular: true,
      color: 'indigo',
      badge: 'Best Value'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto py-8 px-4 animate-in fade-in duration-700 pb-24">
      <div className="text-center mb-16 space-y-4">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-indigo-50 text-indigo-600 rounded-full text-xs font-black uppercase tracking-widest">
          <Star size={12} fill="currentColor" /> Subscription Plans
        </div>
        <h2 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight">Simple plans for every stage.</h2>
        <p className="text-slate-500 max-w-xl mx-auto font-medium text-lg leading-relaxed">
          Start for free and scale as your client base grows. Toggle annual billing to save more.
        </p>

        {/* Billing Toggle */}
        <div className="flex items-center justify-center gap-4 pt-6">
          <span className={`text-sm font-bold ${billingCycle === 'monthly' ? 'text-slate-900' : 'text-slate-400'}`}>Monthly</span>
          <button 
            onClick={() => setBillingCycle(billingCycle === 'monthly' ? 'annual' : 'monthly')}
            className="w-14 h-8 bg-slate-200 rounded-full p-1 relative transition-all duration-300"
          >
            <div className={`w-6 h-6 bg-white rounded-full shadow-md transition-all duration-300 transform ${billingCycle === 'annual' ? 'translate-x-6' : ''}`} />
          </button>
          <div className="flex items-center gap-2">
            <span className={`text-sm font-bold ${billingCycle === 'annual' ? 'text-slate-900' : 'text-slate-400'}`}>Annual</span>
            <span className="bg-emerald-100 text-emerald-600 text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter">Save 20%</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 lg:gap-12">
        {plans.map((plan) => {
          const isSelected = currentPlan === plan.id;
          const processing = isProcessing === plan.id;

          return (
            <div 
              key={plan.id}
              className={`relative flex flex-col p-10 rounded-[40px] border transition-all duration-500 ${
                plan.isPopular 
                  ? 'border-indigo-600 shadow-2xl shadow-indigo-100 scale-105 bg-white z-10' 
                  : 'border-slate-100 bg-white hover:border-indigo-200'
              } ${isSelected ? 'ring-2 ring-indigo-600 ring-offset-4' : ''}`}
            >
              {plan.badge && (
                <span className="absolute -top-4 left-1/2 -translate-x-1/2 bg-indigo-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] shadow-lg">
                  {plan.badge}
                </span>
              )}

              <div className="mb-10">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center mb-6 ${plan.isPopular ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400'}`}>
                  <plan.icon size={28} />
                </div>
                <h3 className="text-2xl font-black text-slate-900">{plan.name}</h3>
                <p className="text-sm text-slate-500 mt-2 font-medium leading-relaxed">{plan.description}</p>
              </div>

              <div className="mb-10">
                <div className="flex items-baseline gap-1">
                  <span className="text-5xl font-black text-slate-900">${plan.price}</span>
                  <span className="text-slate-400 font-bold">/mo</span>
                </div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">
                  {plan.price === 0 ? 'Forever Free' : (billingCycle === 'annual' ? `Billed $${plan.price * 12}/year` : 'Billed monthly')}
                </p>
              </div>

              <div className="flex-1 space-y-5 mb-10">
                {plan.features.map((feature, i) => (
                  <div key={i} className="flex items-start gap-3">
                    <div className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full flex items-center justify-center ${plan.isPopular ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-400'}`}>
                      <Check size={12} strokeWidth={4} />
                    </div>
                    <span className="text-sm font-semibold text-slate-600">{feature}</span>
                  </div>
                ))}
              </div>

              <button 
                onClick={() => handleSelectPlan(plan.id)}
                disabled={isSelected || processing}
                className={`w-full py-5 px-8 rounded-2xl font-black text-sm transition-all flex items-center justify-center gap-2 ${
                  isSelected 
                    ? 'bg-emerald-50 text-emerald-600 cursor-default border border-emerald-100' 
                    : processing
                      ? 'bg-slate-100 text-slate-400 cursor-wait'
                      : 'bg-indigo-600 text-white hover:bg-slate-900 hover:shadow-xl active:scale-95'
                }`}
              >
                {processing ? (
                  <>
                    <Loader2 size={18} className="animate-spin" />
                    Processing...
                  </>
                ) : isSelected ? (
                  <>
                    <Check size={18} strokeWidth={3} />
                    Current Plan
                  </>
                ) : (
                  plan.buttonText
                )}
              </button>
            </div>
          );
        })}
      </div>

      <div className="mt-20 p-10 rounded-[40px] bg-slate-900 text-white flex flex-col md:flex-row items-center justify-between gap-10 overflow-hidden relative">
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/10 blur-[100px] pointer-events-none" />
        <div className="flex items-center gap-6 relative z-10 text-center md:text-left">
          <div className="w-16 h-16 bg-white/10 rounded-3xl flex items-center justify-center shrink-0">
            <Shield size={32} className="text-indigo-400" />
          </div>
          <div>
            <h4 className="text-xl font-black mb-1">Enterprise Grade Security</h4>
            <p className="text-sm text-slate-400 font-medium">Bank-level encryption, PCI compliance, and GDPR ready for all tiers.</p>
          </div>
        </div>
        <div className="flex items-center gap-8 relative z-10 shrink-0">
          <div className="text-center">
            <p className="text-2xl font-black">99.9%</p>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Uptime</p>
          </div>
          <div className="w-px h-10 bg-white/10" />
          <div className="text-center">
            <p className="text-2xl font-black">24/7</p>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Support</p>
          </div>
        </div>
      </div>

      <p className="mt-10 text-center text-xs font-black text-slate-400 uppercase tracking-widest opacity-50">
        Prices in USD. Taxes may apply based on your region.
      </p>
    </div>
  );
};

export default Pricing;

