import React, { useState, useMemo } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Phone, ShieldCheck, Check, CalendarDays } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  // Generate next 14 days for selection
  const availableDates = useMemo(() => {
    const dates = [];
    for (let i = 0; i < 14; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push({
        full: d.toISOString().split('T')[0],
        dayName: d.toLocaleDateString('en-US', { weekday: 'short' }),
        dayNum: d.getDate(),
        month: d.toLocaleDateString('en-US', { month: 'short' }),
        isToday: i === 0
      });
    }
    return dates;
  }, []);

  const handleBook = () => {
    setIsSubmitting(true);
    // Simulate API delay
    setTimeout(() => {
      onBookingComplete({ 
        id: Math.random().toString(36).substr(2, 9), 
        clientId: 'public-' + Date.now(),
        clientName: clientInfo.name, 
        service: selectedService.name, 
        date: selectedDate, 
        time: selectedTime, 
        duration: selectedService.duration, 
        status: 'confirmed', 
        price: selectedService.price,
      });
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  const resetFlow = () => {
    setStep(1);
    setSelectedService(null);
    setSelectedTime("");
    setClientInfo({ name: '', email: '', phone: '' });
    setIsSuccess(false);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tight">Booking Confirmed!</h2>
        <p className="text-slate-500 mb-10 max-w-sm font-medium leading-relaxed">
          Your appointment for <span className="text-indigo-600 font-bold">{selectedService?.name}</span> with <strong>{businessName}</strong> is locked in for <br/>
          <span className="text-slate-900 font-bold">{new Date(selectedDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric' })} at {selectedTime}</span>.
        </p>
        <div className="flex flex-col gap-4 w-full max-w-xs">
          <button 
            onClick={onBack ? onBack : resetFlow} 
            className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:bg-indigo-700 transition-all active:scale-95"
          >
            {onBack ? 'Return to Dashboard' : 'Book Another'}
          </button>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">A confirmation email has been sent</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      {/* Hero Header */}
      <div className="bg-slate-900 pt-20 pb-40 px-6 text-center text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/20 blur-[120px] rounded-full -translate-y-1/2 translate-x-1/2" />
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-emerald-600/10 blur-[100px] rounded-full translate-y-1/2 -translate-x-1/2" />

        <div className="relative z-10">
          <div className="w-12 h-12 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center mx-auto mb-6">
