  const [activeTab, setActiveTab] = useState<'profile' | 'services' | 'integrations' | 'automations'>('profile');
  const [name, setName] = useState(businessName);
  const [newService, setNewService] = useState({ name: '', price: '', duration: '' });
  const [isConnecting, setIsConnecting] = useState<string | null>(null);
  const [connectedApps, setConnectedApps] = useState<string[]>(() => {
    const saved = localStorage.getItem('bookly_connected_apps');
    return saved ? JSON.parse(saved) : [];
  });

  const [automationConfig, setAutomationConfig] = useState({
    whatsapp: true,
    email: true,
    leadTime: '24'
  });

  const handleSaveProfile = () => {
    onUpdateBusinessName(name);
  };

  const handleConnect = (appId: string) => {
    if (connectedApps.includes(appId)) {
      setConnectedApps(prev => prev.filter(id => id !== appId));
      localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps.filter(id => id !== appId)));
      return;
    }

    setIsConnecting(appId);
    setTimeout(() => {
      const newApps = [...connectedApps, appId];
