import React, { useState, useEffect } from 'react';
import { Appointment } from '../types';
import { Calendar as CalendarIcon, Clock, Plus, CheckCircle2, Bell, Send, Loader2, Globe } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';

interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
  onUpdateAppointment?: (apt: Appointment) => void;
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ appointments, onAddClick, onUpdateAppointment }) => {
  const [sendingId, setSendingId] = useState<string | null>(null);
  const [connectedApps, setConnectedApps] = useState<string[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('bookly_connected_apps');
    if (saved) setConnectedApps(JSON.parse(saved));
  }, []);

  const handleSendReminder = async (apt: Appointment) => {
    setSendingId(apt.id);
    const businessName = localStorage.getItem('bookly_business_name') || 'Bookly Business';

    // Simulate API call to send WhatsApp/Email
    const message = await geminiAssistant.draftReminder(apt, businessName);
    console.log(`Sending to ${apt.clientName}: ${message}`);

    setTimeout(() => {
      if (onUpdateAppointment) {
        onUpdateAppointment({
          ...apt,
          reminderSent: true,
          reminderTimestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        });
      }
      setSendingId(null);
    }, 1500);
  };

  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-3xl md:border border-slate-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-6 md:p-8 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-xl font-black text-slate-900">Daily Schedule</h3>
          <p className="text-sm text-slate-500 font-medium mt-0.5">Manage sessions and automated client reminders</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-3">
          {connectedApps.length > 0 && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase tracking-widest border border-emerald-100">
               <Globe size={10} /> Calendar Sync Active
            </div>
          )}
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl hover:bg-slate-900 transition-all font-black text-xs shadow-xl active:scale-95"
          >
            <Plus size={14} />
            New Session
          </button>
        </div>
      </div>

      <div className="p-6 md:p-10 space-y-10">
        {dates.length === 0 ? (
          <div className="text-center py-24 text-slate-400">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <CalendarIcon size={32} className="opacity-20" />
            </div>
            <p className="font-bold text-sm">Your schedule is clear today.</p>
            <p className="text-xs font-medium mt-2">Add your first appointment to get started.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
