import { GoogleGenAI } from "@google/genai";
import { Appointment, Client } from "../types";

export class GeminiAssistant {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async draftReminder(appointment: Appointment, businessName: string) {
    const prompt = `
      Craft a friendly, professional 160-character WhatsApp/SMS reminder.
      Business: ${businessName}
      Client: ${appointment.clientName}
      Service: ${appointment.service}
      Time: ${appointment.time} on ${appointment.date}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text;
    } catch (error) {
      return `Reminder: Your ${appointment.service} session is tomorrow at ${appointment.time}. See you soon!`;
    }
  }

  async performDeepAudit(appointments: Appointment[], clients: Client[]) {
    const context = `
      Perform a Deep Business Audit for "${localStorage.getItem('bookly_business_name')}".
      Data: ${appointments.length} appointments, ${clients.length} clients.
      Calculate: Revenue velocity, client retention risk, and growth opportunities.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: context,
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          tools: [{ googleSearch: {} }]
        }
      });
      return response.text;
    } catch (error) {
      return "Strategic audit currently unavailable.";
    }
  }

  async analyzeSchedule(appointments: Appointment[], clients: Client[], query: string) {
    const context = `
      You are the Bookly Business Advisor. 
      Context: ${appointments.length} bookings, ${clients.length} clients.
      User Query: ${query}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: context,
        config: {
          tools: [{ googleSearch: {} }],
          temperature: 0.7,
        }
      });

      let text = response.text || "I'm processing your request...";
      const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      if (grounding && grounding.length > 0) {
        text += "\n\n**Market Intelligence Sources:**\n" + 
          grounding.filter(c => c.web).map((chunk: any) => `- [${chunk.web.title}](${chunk.web.uri})`).join('\n');
      }

      return text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "AI Link offline. Please check your connection.";
    }
  }

  async getSummary(appointments: Appointment[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Summarize business performance for: ${JSON.stringify(appointments)}. 2 sentences max.`,
      });
      return response.text;
    } catch (error) {
      return "Your business is currently steady.";
    }
  }
}

