            <Calendar size={20} className="text-indigo-400" />
          </div>
          <h1 className="text-3xl md:text-4xl font-black mb-3 tracking-tight truncate px-4">{businessName}</h1>
          <div className="inline-flex items-center gap-2 px-3 md:px-4 py-1.5 bg-white/10 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-widest text-indigo-300 backdrop-blur-sm">
            <CheckCircle2 size={12} /> Official Booking Portal
          </div>
        </div>

        {onBack && (
          <button 
            onClick={onBack} 
            className="absolute top-6 left-4 md:top-8 md:left-8 bg-white/10 hover:bg-white/20 p-2 md:p-2.5 rounded-xl text-[9px] md:text-[10px] font-black flex items-center gap-1.5 md:gap-2 transition-all z-20 uppercase tracking-widest text-white/90"
