    whatsapp: true,
    email: true,
    leadTime: '24'
  });

  const handleSaveProfile = () => {
    onUpdateBusinessName(name);
  };

  const handleConnect = (appId: string) => {
    if (connectedApps.includes(appId)) {
      onUpdateConnectedApps(connectedApps.filter(id => id !== appId));
      return;
    }

    setIsConnecting(appId);
    setTimeout(() => {
      onUpdateConnectedApps([...connectedApps, appId]);
      setIsConnecting(null);
