import React, { useState } from 'react';
import { Appointment } from '../types';
import { Calendar as CalendarIcon, Plus, CheckCircle2, Bell, Send, Loader2, Globe, Trash2 } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';

interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
  onUpdateAppointment?: (apt: Appointment) => void;
  onDeleteAppointment?: (id: string) => void;
  connectedApps: string[];
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ 
  appointments, 
  onAddClick, 
  onUpdateAppointment, 
  onDeleteAppointment,
  connectedApps 
}) => {
  const [sendingId, setSendingId] = useState<string | null>(null);
  const isCalendarConnected = connectedApps.length > 0;

  const handleSendReminder = async (apt: Appointment) => {
    setSendingId(apt.id);
    const businessName = localStorage.getItem('bookly_business_name') || 'Bookly Business';
    const message = await geminiAssistant.draftReminder(apt, businessName);

    setTimeout(() => {
      if (onUpdateAppointment) {
        onUpdateAppointment({
          ...apt,
          reminderSent: true,
          reminderTimestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        });
      }
      setSendingId(null);
    }, 1500);
  };

  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-3xl md:border border-slate-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-6 md:p-8 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-xl font-black text-slate-900">Daily Schedule</h3>
          <p className="text-sm text-slate-500 font-medium mt-0.5">Manage sessions and automated client reminders</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-3">
          {isCalendarConnected && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase tracking-widest border border-emerald-100">
               <Globe size={10} /> Calendar Sync Active
            </div>
          )}
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl hover:bg-slate-900 transition-all font-black text-xs shadow-xl active:scale-95"
          >
            <Plus size={14} />
            New Session
          </button>
        </div>
      </div>

      <div className="p-6 md:p-10 space-y-10">
        {dates.length === 0 ? (
          <div className="text-center py-24 text-slate-400">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <CalendarIcon size={32} className="opacity-20" />
            </div>
            <p className="font-bold text-sm">No appointments found.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-3">
                <span className="shrink-0">{new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}</span>
                <div className="h-px bg-slate-100 flex-1" />
              </h4>
              <div className="space-y-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group flex items-center gap-6 p-6 rounded-[28px] border border-slate-50 hover:border-indigo-100 hover:bg-slate-50/50 transition-all bg-white relative">
                    <div className="flex flex-col items-center justify-center w-16 text-center border-r border-slate-100 pr-6 shrink-0">
                      <span className="text-base font-black text-slate-900 leading-tight">{apt.time}</span>
                      <span className="text-[10px] text-slate-400 font-black uppercase mt-0.5">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1.5">
                        <div className="flex items-center gap-3">
                          <h5 className="font-black text-slate-900 text-base truncate">{apt.clientName}</h5>
                          {connectedApps.includes('google-calendar') && (
                            <div className="w-5 h-5 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center" title="Synced with Google Calendar">
                              <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M19 3H5C3.89 3 3 3.9 3 5V19C3 20.1 3.89 21 5 21H19C20.1 21 21 20.1 21 19V5C21 3.9 20.1 3 19 3Z" fill="currentColor"/>
                                <path d="M16.5 13H13V16.5H11V13H7.5V11H11V7.5H13V11H16.5V13Z" fill="white"/>
                              </svg>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-2">
                          {apt.reminderSent && (
                            <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                              <Bell size={10} fill="currentColor" /> Sent {apt.reminderTimestamp}
                            </span>
                          )}
                          <span className={`flex items-center gap-1.5 text-[9px] font-black uppercase px-3 py-1 rounded-full border ${
                            apt.status === 'confirmed' ? 'text-indigo-500 bg-indigo-50 border-indigo-100' : 'text-slate-400 bg-slate-50 border-slate-100'
                          }`}>
                            <CheckCircle2 size={10} fill="currentColor" /> {apt.status}
                          </span>
                        </div>
                      </div>
                      <p className="text-sm text-slate-500 font-medium truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0 flex items-center gap-4">
                      <div className="hidden sm:block text-right pr-4 border-r border-slate-100">
                        <p className="text-lg font-black text-slate-900">${apt.price}</p>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Revenue</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleSendReminder(apt)}
                          disabled={sendingId === apt.id}
                          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${apt.reminderSent ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-indigo-600 hover:bg-slate-50'}`}
                        >
                          {sendingId === apt.id ? <Loader2 size={16} className="animate-spin" /> : <Send size={18} />}
                        </button>
                        <button 
                          onClick={() => onDeleteAppointment?.(apt.id)}
                          className="w-10 h-10 rounded-xl text-slate-300 hover:text-rose-600 hover:bg-rose-50 transition-all flex items-center justify-center"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default AppointmentCalendar;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import MarketingStudio from './components/MarketingStudio';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Crown, Trash2, CheckCircle2, AlertCircle, X } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => {
    return (localStorage.getItem('bookly_subscription_plan') as 'basic' | 'premium') || 'basic';
  });

  const [connectedApps, setConnectedApps] = useState<string[]>(() => {
    const saved = localStorage.getItem('bookly_connected_apps');
    return saved ? JSON.parse(saved) : [];
  });

  const [legalData, setLegalData] = useState(() => {
    const saved = localStorage.getItem('bookly_legal');
    return saved ? JSON.parse(saved) : {
      privacyPolicy: `We value your privacy. Your contact details are only used to manage your appointments and send reminders. We do not sell your data to third parties.`,
      termsOfService: `By booking an appointment, you agree to our 24-hour cancellation policy. No-shows may be subject to a fee.`,
      gdprStrict: true
    };
  });

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
    localStorage.setItem('bookly_subscription_plan', subscriptionPlan);
    localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps));
    localStorage.setItem('bookly_legal', JSON.stringify(legalData));
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan, connectedApps, legalData]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleOnboardingComplete = (data: { name: string; category: string }) => {
    setBusinessName(data.name);
    setBusinessCategory(data.category);
    setIsOnboarded(true);
    showToast("Business profile created successfully!");
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
    showToast(`Session for ${newBooking.clientName} scheduled.`);
  };

  const handleDeleteAppointment = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    showToast("Appointment removed from schedule.", "error");
  };

  const handleDeleteClient = (id: string) => {
    setClients(prev => prev.filter(c => c.id !== id));
    showToast("Client record archived.", "error");
  };

  const handleUpdateAppointment = (updatedApt: Appointment) => {
    setAppointments(prev => prev.map(apt => apt.id === updatedApt.id ? updatedApt : apt));
  };

  const filteredAppointments = useMemo(() => {
    if (!searchQuery) return appointments;
    const q = searchQuery.toLowerCase();
    return appointments.filter(a => 
      a.clientName.toLowerCase().includes(q) || 
      a.service.toLowerCase().includes(q)
    );
  }, [appointments, searchQuery]);

  const filteredClients = useMemo(() => {
    if (!searchQuery) return clients;
    const q = searchQuery.toLowerCase();
    return clients.filter(c => 
      c.name.toLowerCase().includes(q) || 
      c.email.toLowerCase().includes(q)
    );
  }, [clients, searchQuery]);

  if (!isOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        legalData={legalData}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return (
          <AppointmentCalendar 
            appointments={filteredAppointments} 
            onAddClick={() => setShowAddModal(true)} 
            onUpdateAppointment={handleUpdateAppointment}
            onDeleteAppointment={handleDeleteAppointment}
            connectedApps={connectedApps}
          />
        );
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="space-y-10 animate-in fade-in duration-700 pb-32">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1">
                  <Plus size={12} /> CRM Command
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Client Network</h2>
                <p className="text-slate-500 font-medium">Managing {filteredClients.length} matching relationships.</p>
              </div>
              <button className="flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-indigo-600 transition-all font-black text-xs active:scale-95">
                <Plus size={16} /> New Client
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClients.map((client) => (
                <div key={client.id} className="p-10 bg-white border border-slate-100 rounded-[40px] hover:border-indigo-600 transition-all hover:shadow-2xl group relative overflow-hidden">
                  <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                     <button 
                      onClick={() => handleDeleteClient(client.id)}
