                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => { setSubscriptionPlan(p); showToast(`Upgraded to ${p} tier!`); }} />;
      case 'settings':
        return (
          <Settings 
