                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">מדיניות פרטיות (עברית)</label>
              </div>
              <textarea 
                rows={4}
                value={localLegal.privacyPolicy}
                onChange={e => setLocalLegal({...localLegal, privacyPolicy: e.target.value})}
                className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-medium text-slate-700 focus:ring-2 focus:ring-indigo-600 transition-all outline-none text-sm"
                placeholder="הסבר כיצד אתה שומר על מידע הלקוחות..."
              />
            </div>

            <div className="space-y-2">
              <div className="flex items-center gap-2 mb-2">
                <FileText size={16} className="text-slate-400" />
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">תנאי שימוש ומדיניות ביטולים</label>
              </div>
              <textarea 
                rows={4}
                value={localLegal.termsOfService}
                onChange={e => setLocalLegal({...localLegal, termsOfService: e.target.value})}
                className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-medium text-slate-700 focus:ring-2 focus:ring-indigo-600 transition-all outline-none text-sm"
                placeholder="ציין את מדיניות הביטולים ותנאי השירות..."
              />
            </div>

            <div className="pt-4 flex justify-end">
              <button onClick={handleSaveLegal} className="px-10 py-4 bg-slate-900 text-white rounded-[20px] font-black text-sm shadow-xl hover:bg-black transition-all flex items-center gap-2 active:scale-95">
                <Save size={18} /> עדכן הגדרות משפטיות
              </button>
            </div>
          </div>
        </section>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useMemo } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Phone, ShieldCheck, Check, CalendarDays, MapPin, X, FileText } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  legalData: { privacyPolicy: string; termsOfService: string; gdprStrict: boolean };
  isRTL: boolean;
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, legalData, isRTL, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [hasConsented, setHasConsented] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [viewingLegal, setViewingLegal] = useState<'privacy' | 'terms' | null>(null);

  const availableDates = useMemo(() => {
    const dates = [];
    for (let i = 0; i < 14; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push({
        full: d.toISOString().split('T')[0],
        dayName: d.toLocaleDateString('he-IL', { weekday: 'short' }),
        dayNum: d.getDate(),
        month: d.toLocaleDateString('he-IL', { month: 'short' }),
        isToday: i === 0
      });
    }
    return dates;
  }, []);

  const handleBook = () => {
    if (legalData.gdprStrict && !hasConsented) return;
    setIsSubmitting(true);
    setTimeout(() => {
      onBookingComplete({ 
        id: Math.random().toString(36).substr(2, 9), 
        clientId: 'public-' + Date.now(),
        clientName: clientInfo.name, 
        service: selectedService.name, 
        date: selectedDate, 
        time: selectedTime, 
        duration: selectedService.duration, 
        status: 'confirmed', 
        price: selectedService.price,
      });
      setIsSubmitting(false);
      setIsSuccess(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 1500);
  };

  const resetFlow = () => {
    setStep(1);
    setSelectedService(null);
    setSelectedDate(new Date().toISOString().split('T')[0]);
    setSelectedTime("");
    setClientInfo({ name: '', email: '', phone: '' });
    setHasConsented(false);
    setIsSuccess(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-20 h-20 md:w-24 md:h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-100 animate-bounce">
          <CheckCircle2 size={40} className="md:w-12 md:h-12" />
        </div>
        <h2 className="text-3xl md:text-4xl font-black text-slate-900 mb-4 tracking-tight px-4">התור נקבע בהצלחה!</h2>
        <p className="text-slate-500 mb-10 max-w-sm font-medium leading-relaxed px-4">
          התור שלך ל-<span className="text-indigo-600 font-bold">{selectedService?.name}</span> ב-<strong>{businessName}</strong> נקבע ליום <br className="hidden sm:block"/>
          <span className="text-slate-900 font-bold">{new Date(selectedDate).toLocaleDateString('he-IL', { month: 'long', day: 'numeric' })} בשעה {selectedTime}</span>.
        </p>
        <div className="flex flex-col gap-4 w-full max-w-[280px]">
          <button 
            onClick={onBack ? onBack : resetFlow} 
            className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-xl hover:bg-indigo-700 transition-all active:scale-95"
          >
            {onBack ? 'חזור לעמוד הבית' : 'קבע תור נוסף'}
          </button>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">אישור נשלח למייל שלך</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen bg-slate-50 font-sans pb-10 ${isRTL ? 'font-assistant' : ''}`}>
      {/* Hero Header */}
      <div className="bg-slate-900 pt-16 md:pt-20 pb-32 md:pb-40 px-6 text-center text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 md:w-96 h-64 md:h-96 bg-indigo-600/20 blur-[80px] md:blur-[120px] rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none" />
        <div className="absolute bottom-0 left-0 w-48 md:w-64 h-48 md:h-64 bg-emerald-600/10 blur-[60px] md:blur-[100px] rounded-full translate-y-1/2 -translate-x-1/2 pointer-events-none" />

        <div className="relative z-10">
          <div className="w-10 h-10 md:w-12 md:h-12 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center mx-auto mb-4 md:mb-6">
            <Calendar size={20} className="text-indigo-400" />
