                      <span className="text-xl md:text-2xl font-black mb-1">{date.dayNum}</span>
                      <span className={`text-[9px] md:text-[10px] font-bold uppercase ${selectedDate === date.full ? 'text-indigo-100' : 'text-slate-400'}`}>
