                      onClick={() => {setSelectedTime(t); setStep(4); window.scrollTo({ top: 0, behavior: 'smooth' });}} 
                      className={`py-5 md:py-6 rounded-xl md:rounded-2xl font-black text-base md:text-lg transition-all border-2 active:scale-95 ${
