              </div>
           </div>
        </div>
      )}

      <div className="max-w-4xl mx-auto px-4 mt-6 md:mt-12 text-center text-slate-400">
        <p className="text-[10px] md:text-xs font-medium px-6">מבוסס על <span className="font-black text-indigo-400">Bookly AI</span> — הפלטפורמה המובילה לניהול עסקים.</p>
      </div>
    </div>
  );
};

export default PublicBookingPage;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import MarketingStudio from './components/MarketingStudio';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { Plus, Search, Bell, Sparkles, Crown, Trash2, CheckCircle2, AlertCircle, X } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Global Locale State
  const [language, setLanguage] = useState<'he' | 'en'>(() => (localStorage.getItem('bookly_lang') as 'he' | 'en') || 'he');
  const [currency, setCurrency] = useState<'ILS' | 'USD' | 'EUR' | 'GBP'>(() => (localStorage.getItem('bookly_currency') as any) || 'ILS');
  const isRTL = language === 'he';

  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => {
    return (localStorage.getItem('bookly_subscription_plan') as 'basic' | 'premium') || 'basic';
  });

  const [connectedApps, setConnectedApps] = useState<string[]>(() => {
    const saved = localStorage.getItem('bookly_connected_apps');
    return saved ? JSON.parse(saved) : [];
  });

  const [legalData, setLegalData] = useState(() => {
    const saved = localStorage.getItem('bookly_legal');
    return saved ? JSON.parse(saved) : {
      privacyPolicy: `Global Trust Policy: This business complies with Israeli PPL, EU GDPR, and California CCPA. Your data is processed securely and only for appointment management.`,
      termsOfService: `Standard 24-hour cancellation policy applies globally. מדיניות ביטולים של 24 שעות מראש חלה על כלל ההזמנות.`,
      gdprStrict: true
    };
  });

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('bookly_appointments');
    return saved ? JSON.parse(saved) : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('bookly_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('bookly_appointments', JSON.stringify(appointments));
    localStorage.setItem('bookly_clients', JSON.stringify(clients));
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
    localStorage.setItem('bookly_subscription_plan', subscriptionPlan);
    localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps));
    localStorage.setItem('bookly_legal', JSON.stringify(legalData));
    localStorage.setItem('bookly_lang', language);
    localStorage.setItem('bookly_currency', currency);

    document.documentElement.dir = isRTL ? 'rtl' : 'ltr';
    document.documentElement.lang = language;
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan, connectedApps, legalData, language, currency]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleOnboardingComplete = (data: { name: string; category: string }) => {
    setBusinessName(data.name);
    setBusinessCategory(data.category);
    setIsOnboarded(true);
    showToast(language === 'he' ? "הפרופיל העסקי נוצר בהצלחה!" : "Business profile created successfully!");
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
    showToast(language === 'he' ? `נקבע תור עבור ${newBooking.clientName}.` : `Scheduled for ${newBooking.clientName}.`);
  };

  const handleDeleteAppointment = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    showToast(language === 'he' ? "התור הוסר מהיומן." : "Appointment removed.", "error");
  };

  const handleDeleteClient = (id: string) => {
    setClients(prev => prev.filter(c => c.id !== id));
    showToast(language === 'he' ? "כרטיס הלקוח הועבר לארכיון." : "Client archived.", "error");
  };

  const handleUpdateAppointment = (updatedApt: Appointment) => {
    setAppointments(prev => prev.map(apt => apt.id === updatedApt.id ? updatedApt : apt));
  };

  const filteredAppointments = useMemo(() => {
    if (!searchQuery) return appointments;
    const q = searchQuery.toLowerCase();
    return appointments.filter(a => 
      a.clientName.toLowerCase().includes(q) || 
      a.service.toLowerCase().includes(q)
    );
  }, [appointments, searchQuery]);

  const filteredClients = useMemo(() => {
    if (!searchQuery) return clients;
    const q = searchQuery.toLowerCase();
    return clients.filter(c => 
      c.name.toLowerCase().includes(q) || 
      c.email.toLowerCase().includes(q)
    );
  }, [clients, searchQuery]);

  if (!isOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        legalData={legalData}
        isRTL={isRTL}
        currency={currency}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          currency={currency}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return (
          <AppointmentCalendar 
            appointments={filteredAppointments} 
            onAddClick={() => setShowAddModal(true)} 
            onUpdateAppointment={handleUpdateAppointment}
            onDeleteAppointment={handleDeleteAppointment}
            connectedApps={connectedApps}
            currency={currency}
          />
        );
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="space-y-10 animate-in fade-in duration-700 pb-32">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1">
                  <Plus size={12} /> CRM Command
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">{language === 'he' ? 'לקוחות' : 'Client Network'}</h2>
                <p className="text-slate-500 font-medium">{language === 'he' ? `ניהול ${filteredClients.length} מערכות יחסים פעילות.` : `Managing ${filteredClients.length} active relationships.`}</p>
              </div>
              <button className="flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-indigo-600 transition-all font-black text-xs active:scale-95">
                <Plus size={16} /> {language === 'he' ? 'לקוח חדש' : 'New Client'}
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClients.map((client) => (
                <div key={client.id} className="p-10 bg-white border border-slate-100 rounded-[40px] hover:border-indigo-600 transition-all hover:shadow-2xl group relative overflow-hidden">
                  <div className={`absolute top-4 ${isRTL ? 'left-4' : 'right-4'} flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                     <button 
                      onClick={() => handleDeleteClient(client.id)}
                      className="w-10 h-10 bg-rose-50 text-rose-400 rounded-xl flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                  <div className="flex flex-col items-center text-center">
                    <div className="w-24 h-24 bg-slate-50 text-slate-400 border border-slate-100 rounded-[32px] flex items-center justify-center text-3xl font-black group-hover:bg-indigo-600 group-hover:text-white group-hover:scale-110 transition-all duration-500 mb-6">
                      {client.name.charAt(0)}
                    </div>
                    <h4 className="text-2xl font-black text-slate-900 tracking-tight">{client.name}</h4>
                    <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1 mb-8">{client.email}</p>
                    <div className="w-full grid grid-cols-2 gap-2">
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{language === 'he' ? 'פעילות' : 'Activity'}</span>
                          <span className="text-sm font-black text-slate-900">Active</span>
                       </div>
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{language === 'he' ? 'דירוג' : 'Ranking'}</span>
                          <span className="text-sm font-black text-slate-900">VIP</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => { setSubscriptionPlan(p); showToast(`Upgraded to ${p}!`); }} />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={(n) => { setBusinessName(n); showToast("Profile updated."); }} 
            services={services}
            onUpdateServices={(s) => { setServices(s); showToast("Services updated."); }}
            connectedApps={connectedApps}
            onUpdateConnectedApps={setConnectedApps}
            legalData={legalData}
            onUpdateLegalData={(d) => { setLegalData(d); showToast("Global compliance updated."); }}
            language={language}
            onUpdateLanguage={setLanguage}
            currency={currency}
            onUpdateCurrency={setCurrency}
          />
        );
      default:
        return <Dashboard 
          businessName={businessName} 
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          currency={currency}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
    }
  };

  return (
    <div className={`flex h-screen bg-slate-50 overflow-hidden font-sans selection:bg-indigo-100 selection:text-indigo-900 ${isRTL ? 'font-assistant' : ''}`}>
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        subscriptionPlan={subscriptionPlan} 
        connectedApps={connectedApps}
      />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-24 bg-white/80 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 shrink-0 z-20">
          <div className="flex items-center gap-10 flex-1">
             <div className="relative w-full max-w-md hidden md:block">
               <Search className={`absolute ${isRTL ? 'right-4' : 'left-4'} top-1/2 -translate-y-1/2 text-slate-300`} size={18} />
               <input 
                  type="text" 
                  placeholder={language === 'he' ? 'חיפוש חכם...' : 'Universal Search...'}
                  className={`w-full bg-slate-50 border-none rounded-2xl py-3 ${isRTL ? 'pr-12 pl-12' : 'pl-12 pr-12'} text-sm font-medium focus:ring-2 focus:ring-indigo-600 outline-none transition-all`}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
               />
               {searchQuery && (
                 <button onClick={() => setSearchQuery("")} className={`absolute ${isRTL ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600`}>
                   <X size={14} />
                 </button>
               )}
             </div>
          </div>
          <div className="flex items-center gap-8">
            <div className="flex items-center gap-6">
              <button className="text-slate-300 hover:text-indigo-600 transition-colors relative">
                <Bell size={22} strokeWidth={2} />
                <div className={`absolute -top-1 ${isRTL ? '-left-1' : '-right-1'} w-2.5 h-2.5 bg-rose-500 border-2 border-white rounded-full`} />
              </button>
            </div>
            <div className={`flex items-center gap-5 ${isRTL ? 'border-r pr-8' : 'border-l pl-8'} border-slate-100`}>
              <div className={`${isRTL ? 'text-left' : 'text-right'} hidden sm:block`}>
                <p className="text-sm font-black text-slate-900 tracking-tight leading-none">{businessName}</p>
                <div className={`flex items-center ${isRTL ? 'justify-start' : 'justify-end'} gap-2 mt-1.5`}>
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{businessCategory}</span>
                  {subscriptionPlan === 'premium' && (
                    <span className="bg-slate-900 text-white text-[8px] font-black px-2 py-0.5 rounded flex items-center gap-1">
                      <Crown size={8} /> ELITE
                    </span>
                  )}
                </div>
              </div>
              <div className="w-12 h-12 rounded-2xl bg-slate-900 flex items-center justify-center text-white text-sm font-black shadow-xl ring-4 ring-slate-50 group cursor-pointer hover:rotate-12 transition-transform">
                {businessName.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        {toast && (
          <div className={`fixed top-28 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-4 rounded-[20px] shadow-2xl animate-in slide-in-from-top-10 duration-500 ${toast.type === 'success' ? 'bg-indigo-600 text-white' : 'bg-rose-600 text-white'}`}>
            {toast.type === 'success' ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
            <span className="text-xs font-black uppercase tracking-widest">{toast.message}</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-12 max-w-[1600px] mx-auto w-full custom-scroll">
          {renderContent()}
        </div>
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
          currency={currency}
          isRTL={isRTL}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Save, Trash2, MessageSquare, Mail, Zap, Globe, Calendar, Loader2, Sparkles, ShieldCheck, FileText, Lock, Languages, DollarSign } from 'lucide-react';

interface SettingsProps {
  businessName: string;
  onUpdateBusinessName: (name: string) => void;
  services: any[];
  onUpdateServices: (services: any[]) => void;
  connectedApps: string[];
  onUpdateConnectedApps: (apps: string[]) => void;
  legalData: { privacyPolicy: string; termsOfService: string; gdprStrict: boolean };
  onUpdateLegalData: (data: any) => void;
  language: 'he' | 'en';
  onUpdateLanguage: (lang: 'he' | 'en') => void;
  currency: 'ILS' | 'USD' | 'EUR' | 'GBP';
  onUpdateCurrency: (cur: 'ILS' | 'USD' | 'EUR' | 'GBP') => void;
}

const Settings: React.FC<SettingsProps> = ({ 
  businessName, 
  onUpdateBusinessName, 
  services, 
  onUpdateServices,
  connectedApps,
  onUpdateConnectedApps,
  legalData,
  onUpdateLegalData,
  language,
  onUpdateLanguage,
  currency,
  onUpdateCurrency
}) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'services' | 'localization' | 'integrations' | 'automations' | 'legal'>('profile');
  const [name, setName] = useState(businessName);
  const [newService, setNewService] = useState({ name: '', price: '', duration: '' });
  const [isConnecting, setIsConnecting] = useState<string | null>(null);
  const [localLegal, setLocalLegal] = useState(legalData);

  const handleSaveProfile = () => onUpdateBusinessName(name);
  const handleSaveLegal = () => onUpdateLegalData(localLegal);

  const handleConnect = (appId: string) => {
    if (connectedApps.includes(appId)) {
      onUpdateConnectedApps(connectedApps.filter(id => id !== appId));
      return;
    }
    setIsConnecting(appId);
    setTimeout(() => {
      onUpdateConnectedApps([...connectedApps, appId]);
      setIsConnecting(null);
    }, 2000);
  };

  const handleAddService = () => {
    if (!newService.name || !newService.price) return;
    onUpdateServices([...services, { 
      name: newService.name, 
      price: Number(newService.price), 
      duration: Number(newService.duration) || 60 
    }]);
    setNewService({ name: '', price: '', duration: '' });
  };

  const currencySymbols = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-200 pb-6 gap-4">
        <div>
          <h2 className="text-2xl font-black text-slate-900">{language === 'he' ? 'הגדרות' : 'Settings'}</h2>
          <p className="text-sm text-slate-500 font-medium">{language === 'he' ? 'ניהול העסק והאינטגרציות שלך' : 'Manage your business core and integrations'}</p>
        </div>
        <div className="flex flex-wrap gap-1 bg-slate-100 p-1.5 rounded-[18px]">
          {['profile', 'services', 'localization', 'integrations', 'automations', 'legal'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'profile' && (
        <section className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-sm space-y-8">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{language === 'he' ? 'שם העסק' : 'Business Name'}</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-bold text-slate-900 focus:ring-2 focus:ring-indigo-600 outline-none"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{language === 'he' ? 'קטגוריה' : 'Business Category'}</label>
                <select className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-bold text-slate-900 focus:ring-2 focus:ring-indigo-600 outline-none appearance-none">
                  <option>Beauty & Health</option>
                  <option>Tech & Professional</option>
                  <option>Creative Services</option>
                </select>
              </div>
           </div>
           <div className="pt-4 flex justify-end">
             <button onClick={handleSaveProfile} className="px-10 py-4 bg-slate-900 text-white rounded-[20px] font-black text-sm shadow-xl hover:bg-black transition-all active:scale-95">
               {language === 'he' ? 'שמור שינויים' : 'Save Profile'}
             </button>
           </div>
        </section>
      )}

      {activeTab === 'localization' && (
        <section className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-sm space-y-8 animate-in slide-in-from-bottom-4 duration-500">
           <div className="flex items-center gap-4 mb-4">
            <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
              <Globe size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-900">Global Market Settings</h3>
              <p className="text-sm text-slate-500 font-medium">Configure your export strategy and target locales.</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4 p-6 bg-slate-50 rounded-3xl border border-slate-100">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Languages size={14}/> Interface Language</label>
              <div className="grid grid-cols-2 gap-2">
                <button onClick={() => onUpdateLanguage('he')} className={`py-3 rounded-xl font-black text-xs transition-all ${language === 'he' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-300'}`}>Hebrew (עברית)</button>
                <button onClick={() => onUpdateLanguage('en')} className={`py-3 rounded-xl font-black text-xs transition-all ${language === 'en' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-300'}`}>English (US)</button>
              </div>
            </div>

            <div className="space-y-4 p-6 bg-slate-50 rounded-3xl border border-slate-100">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><DollarSign size={14}/> Primary Currency</label>
              <div className="grid grid-cols-4 gap-2">
                {Object.keys(currencySymbols).map(cur => (
                  <button 
                    key={cur}
                    onClick={() => onUpdateCurrency(cur as any)} 
                    className={`py-3 rounded-xl font-black text-xs transition-all ${currency === cur ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-300'}`}
                  >
                    {(currencySymbols as any)[cur]}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </section>
      )}

      {activeTab === 'legal' && (
        <section className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-sm space-y-8 animate-in slide-in-from-bottom-4 duration-500">
          <div className="flex items-center gap-4 mb-4">
            <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
              <ShieldCheck size={24} />
