              <div className="space-y-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group flex items-center gap-6 p-6 rounded-[28px] border border-slate-50 hover:border-indigo-100 hover:bg-slate-50/50 transition-all bg-white relative">
                    <div className="flex flex-col items-center justify-center w-16 text-center border-r border-slate-100 pr-6 shrink-0">
