                      <span className="text-[10px] text-slate-400 font-black uppercase mt-0.5">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1.5">
                        <div className="flex items-center gap-3">
                          <h5 className="font-black text-slate-900 text-base truncate">{apt.clientName}</h5>
                          {connectedApps.includes('google-calendar') && (
                            <div className="w-5 h-5 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center" title="Synced with Google Calendar">
                              <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M19 3H5C3.89 3 3 3.9 3 5V19C3 20.1 3.89 21 5 21H19C20.1 21 21 20.1 21 19V5C21 3.9 20.1 3 19 3Z" fill="currentColor"/>
                                <path d="M16.5 13H13V16.5H11V13H7.5V11H11V7.5H13V11H16.5V13Z" fill="white"/>
                              </svg>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-2">
                          {apt.reminderSent && (
                            <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                              <Bell size={10} fill="currentColor" /> Sent {apt.reminderTimestamp}
                            </span>
                          )}
                          <span className={`flex items-center gap-1.5 text-[9px] font-black uppercase px-3 py-1 rounded-full border ${
                            apt.status === 'confirmed' ? 'text-indigo-500 bg-indigo-50 border-indigo-100' : 'text-slate-400 bg-slate-50 border-slate-100'
                          }`}>
                            <CheckCircle2 size={10} fill="currentColor" /> {apt.status}
                          </span>
                        </div>
                      </div>
                      <p className="text-sm text-slate-500 font-medium truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0 flex items-center gap-4">
                      <div className="hidden sm:block text-right pr-4 border-r border-slate-100">
                        {/* Fix: Use dynamic currency symbol instead of hardcoded $ */}
                        <p className="text-lg font-black text-slate-900">{currencySymbol}{apt.price}</p>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Revenue</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleSendReminder(apt)}
                          disabled={sendingId === apt.id}
                          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${apt.reminderSent ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-indigo-600 hover:bg-slate-50'}`}
                        >
                          {sendingId === apt.id ? <Loader2 size={16} className="animate-spin" /> : <Send size={18} />}
                        </button>
                        <button 
                          onClick={() => onDeleteAppointment?.(apt.id)}
                          className="w-10 h-10 rounded-xl text-slate-300 hover:text-rose-600 hover:bg-rose-50 transition-all flex items-center justify-center"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

