          <div className={`fixed top-28 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-4 rounded-[20px] shadow-2xl animate-in slide-in-from-top-10 duration-500 ${toast.type === 'success' ? 'bg-indigo-600 text-white' : 'bg-rose-600 text-white'}`}>
            {toast.type === 'success' ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
            <span className="text-xs font-black uppercase tracking-widest">{toast.message}</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-12 max-w-[1600px] mx-auto w-full custom-scroll">
          {renderContent()}
        </div>
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
          currency={currency}
          isRTL={isRTL}
        />
      )}
    </div>
  );
};

