      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="space-y-10 animate-in fade-in duration-700 pb-32">
            <header className={`flex flex-col md:flex-row md:items-end justify-between gap-6 ${isRTL ? 'md:flex-row-reverse' : ''}`}>
              <div className={isRTL ? 'text-right' : ''}>
                <div className={`flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1 ${isRTL ? 'flex-row-reverse' : ''}`}>
                  <Plus size={12} /> CRM Command
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">{t.clients}</h2>
                <p className="text-slate-500 font-medium">{t.managing} {filteredClients.length} {t.activeRel}</p>
              </div>
              <button className={`flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-indigo-600 transition-all font-black text-xs active:scale-95 ${isRTL ? 'flex-row-reverse' : ''}`}>
                <Plus size={16} /> {t.newClient}
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClients.map((client) => (
                <div key={client.id} className="p-10 bg-white border border-slate-100 rounded-[40px] hover:border-indigo-600 transition-all hover:shadow-2xl group relative overflow-hidden">
                  <div className={`absolute top-4 ${isRTL ? 'left-4' : 'right-4'} flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                     <button 
                      onClick={() => handleDeleteClient(client.id)}
                      className="w-10 h-10 bg-rose-50 text-rose-400 rounded-xl flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all"
                    >
                      <Trash2 size={18} />
