                    <h4 className="text-2xl font-black text-slate-900 tracking-tight">{client.name}</h4>
                    <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1 mb-8">{client.email}</p>
                    <div className="w-full grid grid-cols-2 gap-2">
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
