                       </div>
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{t.ranking}</span>
                          <span className="text-sm font-black text-slate-900">VIP</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} language={language} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => { setSubscriptionPlan(p); showToast(`Upgraded to ${p}!`); }} />;
