               <input 
                  type="text" 
                  placeholder={t.search}
                  className={`w-full bg-slate-50 border-none rounded-2xl py-3 ${isRTL ? 'pr-12 pl-12' : 'pl-12 pr-12'} text-sm font-medium focus:ring-2 focus:ring-indigo-600 outline-none transition-all`}
                  value={searchQuery}
