               {searchQuery && (
                 <button onClick={() => setSearchQuery("")} className={`absolute ${isRTL ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600`}>
                   <X size={14} />
