              <ShieldCheck size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-900">Global Trust Hub</h3>
              <p className="text-sm text-slate-500 font-medium">Unified compliance for Israeli PPL, EU GDPR, and US CCPA standards.</p>
            </div>
          </div>

          <div className="space-y-6">
            <textarea 
              rows={6}
              value={localLegal.privacyPolicy}
              onChange={e => setLocalLegal({...localLegal, privacyPolicy: e.target.value})}
              className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 font-medium text-slate-700 focus:ring-2 focus:ring-indigo-600 transition-all outline-none text-sm"
              placeholder="Your global privacy statement..."
