                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Ranking</span>
                          <span className="text-sm font-black text-slate-900">VIP</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => { setSubscriptionPlan(p); showToast(`Upgraded to ${p}!`); }} />;
