import React, { useState } from 'react';
import { Appointment } from '../types';
import { Calendar as CalendarIcon, Plus, CheckCircle2, Bell, Send, Loader2, Globe, Trash2 } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';

interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
  onUpdateAppointment?: (apt: Appointment) => void;
  onDeleteAppointment?: (id: string) => void;
  connectedApps: string[];
  currency?: 'ILS' | 'USD' | 'EUR' | 'GBP';
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ 
  appointments, 
  onAddClick, 
  onUpdateAppointment, 
  onDeleteAppointment,
  connectedApps,
  currency
}) => {
  const [sendingId, setSendingId] = useState<string | null>(null);
  const isCalendarConnected = connectedApps.length > 0;
  const currencySymbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency || 'USD'] || '$';

  const handleSendReminder = async (apt: Appointment) => {
    setSendingId(apt.id);
    const businessName = localStorage.getItem('bookly_business_name') || 'Bookly Business';
    await geminiAssistant.draftReminder(apt, businessName);
    setTimeout(() => {
      if (onUpdateAppointment) {
        onUpdateAppointment({ ...apt, reminderSent: true, reminderTimestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) });
      }
      setSendingId(null);
    }, 1500);
  };

  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-3xl md:border border-slate-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-6 md:p-8 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-xl font-black text-slate-900">Operations Schedule</h3>
          <p className="text-sm text-slate-500 font-medium mt-0.5">Manage daily sessions and client communications</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-3">
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl hover:bg-slate-900 transition-all font-black text-xs shadow-xl active:scale-95"
          >
            <Plus size={14} />
            New Session
          </button>
        </div>
      </div>

      <div className="p-6 md:p-10 space-y-10">
        {dates.length === 0 ? (
          <div className="text-center py-24 text-slate-400">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <CalendarIcon size={32} className="opacity-20" />
            </div>
            <p className="font-bold text-sm">No scheduled appointments.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-3">
                <span className="shrink-0">{new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}</span>
                <div className="h-px bg-slate-100 flex-1" />
              </h4>
              <div className="space-y-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group flex items-center gap-6 p-6 rounded-[28px] border border-slate-50 hover:border-indigo-100 hover:bg-slate-50/50 transition-all bg-white relative">
                    <div className="flex flex-col items-center justify-center w-16 text-center border-r pr-6 border-slate-100 shrink-0">
                      <span className="text-base font-black text-slate-900 leading-tight">{apt.time}</span>
                      <span className="text-[10px] font-black text-slate-400 uppercase">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1.5">
                        <h5 className="font-black text-slate-900 text-base truncate">{apt.clientName}</h5>
                        <div className="flex items-center gap-2">
                          {apt.reminderSent && (
                             <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                               <Bell size={10} fill="currentColor" /> Sent {apt.reminderTimestamp}
                             </span>
                          )}
                          <span className={`flex items-center gap-1.5 text-[9px] font-black uppercase px-3 py-1 rounded-full border ${apt.status === 'confirmed' ? 'text-indigo-500 bg-indigo-50 border-indigo-100' : 'text-slate-400 bg-slate-50 border-slate-100'}`}>
                            <CheckCircle2 size={10} fill="currentColor" /> {apt.status}
                          </span>
                        </div>
                      </div>
                      <p className="text-sm text-slate-500 font-medium truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0 flex items-center gap-4">
                      <div className="hidden sm:block text-right pr-4 border-r border-slate-100">
                        <p className="text-lg font-black text-slate-900">{currencySymbol}{apt.price}</p>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Revenue</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleSendReminder(apt)}
                          disabled={sendingId === apt.id}
                          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${apt.reminderSent ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-indigo-600 hover:bg-slate-50'}`}
                        >
                          {sendingId === apt.id ? <Loader2 size={16} className="animate-spin" /> : <Send size={18} />}
                        </button>
                        <button 
                          onClick={() => onDeleteAppointment?.(apt.id)}
                          className="w-10 h-10 rounded-xl text-slate-300 hover:text-rose-600 hover:bg-rose-50 transition-all flex items-center justify-center"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

