import React, { useState, useMemo } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, ArrowLeft, User, Mail, Phone, ShieldCheck, Check, CalendarDays, MapPin, X, FileText, Globe } from 'lucide-react';

interface PublicBookingPageProps {
  businessName: string;
  services: any[];
  legalData: { privacyPolicy: string; termsOfService: string; gdprStrict: boolean };
  currency: 'ILS' | 'USD' | 'EUR' | 'GBP';
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, legalData, currency, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [hasConsented, setHasConsented] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const currencySymbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency];

  const availableDates = useMemo(() => {
    const dates = [];
    for (let i = 0; i < 14; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push({
        full: d.toISOString().split('T')[0],
        dayName: d.toLocaleDateString('en-US', { weekday: 'short' }),
        dayNum: d.getDate(),
        month: d.toLocaleDateString('en-US', { month: 'short' }),
        isToday: i === 0
      });
    }
    return dates;
  }, []);

  const handleBook = () => {
    setIsSubmitting(true);
    setTimeout(() => {
      onBookingComplete({ 
        id: Math.random().toString(36).substr(2, 9), 
        clientId: 'public-' + Date.now(),
        clientName: clientInfo.name, 
        service: selectedService.name, 
        date: selectedDate, 
        time: selectedTime, 
        duration: selectedService.duration, 
        status: 'confirmed', 
        price: selectedService.price,
      });
      setIsSubmitting(false);
      setIsSuccess(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4">Booking Confirmed!</h2>
        <p className="text-slate-500 mb-10 max-w-sm font-medium">{businessName} is looking forward to seeing you.</p>
        <button onClick={onBack || (() => window.location.reload())} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-xl active:scale-95 transition-all">Back to Home</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      <div className="bg-slate-900 pt-16 pb-32 px-6 text-center text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/20 blur-[120px] rounded-full translate-x-1/4 -translate-y-1/2 pointer-events-none" />
        <div className="relative z-10">
          <div className="w-12 h-12 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center mx-auto mb-6">
            <Globe size={24} className="text-indigo-400" />
          </div>
          <h1 className="text-4xl font-black mb-3 tracking-tight">{businessName}</h1>
          <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-widest text-indigo-300 backdrop-blur-sm">
            <ShieldCheck size={12} /> Secure Booking Portal
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto -mt-24 px-4 relative z-20 pb-10">
        <div className="bg-white rounded-[40px] shadow-2xl overflow-hidden border border-slate-100">
          <div className="p-12">
            {step === 1 && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 text-center">
                <h2 className="text-2xl font-black text-slate-900">Select Service</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {services.map(s => (
                    <button 
                      key={s.name} 
                      onClick={() => {setSelectedService(s); setStep(2);}} 
                      className="flex flex-col p-8 bg-slate-50 border-2 border-transparent rounded-3xl hover:border-indigo-600 hover:bg-white transition-all group hover:shadow-xl active:scale-[0.98] text-left"
                    >
                      <div className="flex justify-between items-start mb-6 w-full">
                        <div className="p-3 bg-white rounded-2xl text-indigo-600 shadow-sm"><Clock size={24} /></div>
                        <p className="font-black text-slate-900 text-2xl">{currencySymbol}{s.price}</p>
                      </div>
                      <h3 className="font-black text-slate-900 text-xl group-hover:text-indigo-600 mb-1">{s.name}</h3>
                      <p className="text-sm text-slate-400 font-bold uppercase tracking-tight">{s.duration} min session</p>
                    </button>
                  ))}
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 text-center">
                <h2 className="text-2xl font-black text-slate-900">Pick Date</h2>
                <div className="flex overflow-x-auto gap-4 pb-6 no-scrollbar -mx-6 px-6 touch-pan-x">
                  {availableDates.map(date => (
                    <button
                      key={date.full}
                      onClick={() => {setSelectedDate(date.full); setStep(3);}}
                      className={`flex flex-col items-center justify-center min-w-[80px] h-[110px] rounded-3xl border-2 transition-all active:scale-[0.95] ${
                        selectedDate === date.full ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-slate-50 border-transparent text-slate-400 hover:bg-white hover:border-indigo-200'
                      }`}
                    >
                      <span className="text-[10px] font-black uppercase tracking-widest mb-1">{date.isToday ? 'Today' : date.dayName}</span>
                      <span className="text-2xl font-black mb-1">{date.dayNum}</span>
                      <span className="text-[10px] font-bold uppercase">{date.month}</span>
                    </button>
                  ))}
                </div>
                <button onClick={() => setStep(1)} className="text-xs font-black text-slate-400 uppercase flex items-center gap-2 mx-auto">Change Service</button>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 text-center">
                <h2 className="text-2xl font-black text-slate-900">Pick Time</h2>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                  {["09:00", "10:00", "11:00", "12:00", "13:30", "14:30", "15:30", "16:30"].map(t_val => (
                    <button 
                      key={t_val} 
                      onClick={() => {setSelectedTime(t_val); setStep(4);}} 
                      className={`py-6 rounded-2xl font-black text-lg transition-all border-2 active:scale-95 ${
                        selectedTime === t_val ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-slate-50 border-transparent text-slate-700 hover:bg-white hover:border-indigo-600'
                      }`}
                    >
                      {t_val}
                    </button>
                  ))}
                </div>
                <button onClick={() => setStep(2)} className="text-xs font-black text-slate-400 uppercase flex items-center gap-2 mx-auto">Change Date</button>
              </div>
            )}

            {step === 4 && (
              <div className="max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center p-6 bg-indigo-50 rounded-[32px]">
                  <h3 className="text-xl font-black text-slate-900 mb-1">{selectedService?.name}</h3>
                  <p className="text-sm font-bold text-slate-600">
                    {new Date(selectedDate).toLocaleDateString('en-US', { weekday: 'short', month: 'long', day: 'numeric' })} @ {selectedTime}
                  </p>
                </div>

                <div className="space-y-4">
                  <input required placeholder="Full Name" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 px-6 focus:bg-white focus:border-indigo-600 outline-none transition-all" value={clientInfo.name} onChange={e => setClientInfo({...clientInfo, name: e.target.value})} />
                  <input required type="email" placeholder="Email Address" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 px-6 focus:bg-white focus:border-indigo-600 outline-none transition-all" value={clientInfo.email} onChange={e => setClientInfo({...clientInfo, email: e.target.value})} />
                  <input required type="tel" placeholder="Phone Number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 px-6 focus:bg-white focus:border-indigo-600 outline-none transition-all" value={clientInfo.phone} onChange={e => setClientInfo({...clientInfo, phone: e.target.value})} />
                </div>

                <div className="pt-4 space-y-4">
                  <label className="flex items-start gap-3 cursor-pointer group">
                    <input type="checkbox" checked={hasConsented} onChange={e => setHasConsented(e.target.checked)} className="mt-1 w-5 h-5 rounded border-2 border-slate-300 text-indigo-600 focus:ring-indigo-500 transition-all" />
                    <span className="text-[10px] font-medium text-slate-500 leading-relaxed">
                      I agree to the Terms of Service and Privacy Policy.
                    </span>
                  </label>

                  <button onClick={handleBook} disabled={isSubmitting || !clientInfo.name || !hasConsented} className="w-full py-5 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50">
                    {isSubmitting ? 'Confirming...' : 'Complete Booking'}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PublicBookingPage;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2, Mic, MicOff, BrainCircuit, Globe, ChevronRight } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';
import { Appointment, Client } from '../types';
import { GoogleGenAI, Modality } from '@google/genai';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  isDeep?: boolean;
}

const AIAssistant: React.FC<{ appointments: Appointment[], clients: Client[] }> = ({ appointments, clients }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Systems online. I'm ready to optimize your business operations. Shall we look at a growth strategy or handle standard tasks?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isDeepMode, setIsDeepMode] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', content: userMsg, isDeep: isDeepMode }]);
    setIsLoading(true);

    try {
      let response;
      if (isDeepMode) {
        response = await geminiAssistant.performDeepAudit(appointments, clients);
      } else {
        response = await geminiAssistant.analyzeSchedule(appointments, clients, userMsg);
      }
      setMessages(prev => [...prev, { role: 'assistant', content: response, isDeep: isDeepMode }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Communication failure. System rebooting..." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceMode = async () => {
    if (isVoiceMode) {
      setIsVoiceMode(false);
      if (sessionRef.current) sessionRef.current.close();
      return;
    }
    setIsVoiceMode(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } },
          systemInstruction: 'You are the Bookly Operations Core. Be precise, helpful, and professional in English.',
        },
        callbacks: {
          onopen: () => console.log('Neural Link Active'),
          onclose: () => setIsVoiceMode(false),
          onerror: () => setIsVoiceMode(false),
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      setIsVoiceMode(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-[48px] border border-slate-100 shadow-2xl overflow-hidden relative">
      <div className="p-8 border-b bg-slate-50 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-5">
          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-xl transition-all duration-500 ${isDeepMode ? 'bg-indigo-600 scale-110 rotate-3' : 'bg-slate-900'}`}>
            {isDeepMode ? <BrainCircuit size={28} /> : <Bot size={28} />}
          </div>
          <div>
            <h3 className="font-black text-slate-900 text-lg">Neural Operations Hub</h3>
            <div className="flex items-center gap-2">
               <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                 <div className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /> Synchronized
               </span>
               {isDeepMode && (
                 <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-indigo-500 bg-indigo-50 px-3 py-1 rounded-full border border-indigo-100">
                   Deep Strategy Active
                 </span>
               )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setIsDeepMode(!isDeepMode)}
            className={`flex items-center gap-2 px-5 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${isDeepMode ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white border border-slate-200 text-slate-500 hover:border-indigo-600'}`}
          >
            <BrainCircuit size={14} /> {isDeepMode ? 'Exit Strategy' : 'Deep strategy'}
          </button>
          <button 
            onClick={toggleVoiceMode}
            className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${isVoiceMode ? 'bg-red-500 text-white animate-pulse shadow-red-200 shadow-xl' : 'bg-slate-100 text-slate-600 hover:bg-white border border-transparent hover:border-slate-200'}`}
          >
            {isVoiceMode ? <MicOff size={20}/> : <Mic size={20}/>}
          </button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-10 space-y-10 bg-white custom-scroll relative">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] flex gap-5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 shadow-sm ${
                msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400 border border-slate-100'
              }`}>
                {msg.role === 'user' ? <User size={18} /> : (msg.isDeep ? <BrainCircuit size={18} /> : <Bot size={18} />)}
              </div>
              <div className={`p-8 rounded-[32px] text-base leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-tr-none' 
                  : `bg-slate-50 text-slate-800 border border-slate-100 rounded-tl-none font-medium ${msg.isDeep ? 'border-l-4 border-l-indigo-600 shadow-xl shadow-indigo-50/50' : ''}`
              }`}>
                {msg.isDeep && msg.role === 'assistant' && (
                  <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-indigo-600 uppercase tracking-widest">
                    <Sparkles size={12} /> Strategic Insight Report
                  </div>
                )}
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="flex gap-4 items-center text-indigo-600 bg-indigo-50/50 p-6 rounded-[32px] border border-indigo-50">
              <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
                <Loader2 className="animate-spin" size={18} />
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-widest">{isDeepMode ? 'Utilizing Thinking Budget...' : 'Accessing Neural Core...'}</span>
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tight">Syncing with Market Intelligence</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-8 border-t bg-white shrink-0">
        <div className="relative max-w-5xl mx-auto group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isDeepMode ? "Describe your business challenge for a deep audit..." : "Optimize my day..."}
            className="w-full bg-slate-50 border-2 border-transparent rounded-[32px] px-10 py-6 pr-24 focus:outline-none focus:border-indigo-600 focus:bg-white text-base font-medium transition-all shadow-inner"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className={`absolute right-3 top-3 bottom-3 px-8 bg-slate-900 text-white rounded-[24px] hover:bg-indigo-600 transition-all shadow-xl flex items-center gap-2 ${isLoading || !input.trim() ? 'opacity-30' : ''}`}
          >
            <span className="text-xs font-black uppercase tracking-widest">Send</span>
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

