import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import MarketingStudio from './components/MarketingStudio';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { MOCK_APPOINTMENTS, MOCK_CLIENTS, SERVICES as DEFAULT_SERVICES } from './constants';
import { Appointment, Client } from './types';
import { storageService } from './services/storageService';
import { Plus, Search, Bell, Sparkles, Crown, Trash2, CheckCircle2, AlertCircle, X } from 'lucide-react';

const App: React.FC = () => {
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [currency, setCurrency] = useState<'ILS' | 'USD' | 'EUR' | 'GBP'>(() => (localStorage.getItem('bookly_currency') as any) || 'USD');
  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');

  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => storageService.getSubscription());

  const [connectedApps, setConnectedApps] = useState<string[]>(() => {
    const saved = localStorage.getItem('bookly_connected_apps');
    return saved ? JSON.parse(saved) : [];
  });

  const [legalData, setLegalData] = useState(() => {
    const saved = localStorage.getItem('bookly_legal');
    return saved ? JSON.parse(saved) : {
      privacyPolicy: `Standard privacy protection applies globally. We respect your data.`,
      termsOfService: `Standard 24-hour cancellation policy applies.`,
      gdprStrict: true
    };
  });

  const [services, setServices] = useState(() => {
    const saved = localStorage.getItem('bookly_services');
    return saved ? JSON.parse(saved) : DEFAULT_SERVICES;
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const data = storageService.getAppointments();
    return data.length > 0 ? data : MOCK_APPOINTMENTS;
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const data = storageService.getClients();
    return data.length > 0 ? data : MOCK_CLIENTS;
  });

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  useEffect(() => {
    storageService.saveAppointments(appointments);
    storageService.saveClients(clients);
    storageService.saveSubscription(subscriptionPlan);
    localStorage.setItem('bookly_services', JSON.stringify(services));
    localStorage.setItem('bookly_business_name', businessName);
    localStorage.setItem('bookly_business_category', businessCategory);
    localStorage.setItem('bookly_onboarded', isOnboarded.toString());
    localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps));
    localStorage.setItem('bookly_legal', JSON.stringify(legalData));
    localStorage.setItem('bookly_currency', currency);
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan, connectedApps, legalData, currency]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleNewBooking = (newBooking: Appointment) => {
    setAppointments(prev => [newBooking, ...prev]);
    showToast(`Appointment scheduled for ${newBooking.clientName}`);
  };

  const handleDeleteClient = (id: string) => {
    setClients(prev => prev.filter(c => c.id !== id));
    showToast("Client removed from database", "error");
  };

  const handleUpdateAppointment = (updatedApt: Appointment) => {
    setAppointments(prev => prev.map(apt => apt.id === updatedApt.id ? updatedApt : apt));
  };

  const handleDeleteAppointment = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    showToast("Appointment deleted", "error");
  };

  const filteredAppointments = useMemo(() => {
    if (!searchQuery) return appointments;
    const q = searchQuery.toLowerCase();
    return appointments.filter(a => a.clientName.toLowerCase().includes(q) || a.service.toLowerCase().includes(q));
  }, [appointments, searchQuery]);

  const filteredClients = useMemo(() => {
    if (!searchQuery) return clients;
    const q = searchQuery.toLowerCase();
    return clients.filter(c => c.name.toLowerCase().includes(q) || c.email.toLowerCase().includes(q));
  }, [clients, searchQuery]);

  if (!isOnboarded) {
    return <Onboarding onComplete={(data) => { setBusinessName(data.name); setBusinessCategory(data.category); setIsOnboarded(true); }} />;
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        legalData={legalData}
        currency={currency}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          currency={currency}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return (
          <AppointmentCalendar 
            appointments={filteredAppointments} 
            onAddClick={() => setShowAddModal(true)} 
            onUpdateAppointment={handleUpdateAppointment}
            onDeleteAppointment={handleDeleteAppointment}
            connectedApps={connectedApps}
            currency={currency}
          />
        );
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="space-y-10 animate-in fade-in duration-700 pb-32">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1">
                  <Plus size={12} /> CRM Command
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Clients</h2>
                <p className="text-slate-500 font-medium">Managing {filteredClients.length} active relationships.</p>
              </div>
              <button className="flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-indigo-600 transition-all font-black text-xs active:scale-95">
                <Plus size={16} /> New Client
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClients.map((client) => (
                <div key={client.id} className="p-10 bg-white border border-slate-100 rounded-[40px] hover:border-indigo-600 transition-all hover:shadow-2xl group relative overflow-hidden">
                  <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                     <button 
                      onClick={() => handleDeleteClient(client.id)}
                      className="w-10 h-10 bg-rose-50 text-rose-400 rounded-xl flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all"
                    >
