// This service simulates the latency and behavior of a real production backend.
// To move to a real DB, you only need to change the implementation of these functions.

const LATENCY = 600;

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  appointments: {
    list: async (): Promise<Appointment[]> => {
      await delay(LATENCY);
      return storageService.getAppointments();
    },
    create: async (data: Appointment): Promise<Appointment> => {
      await delay(LATENCY + 400);
      const current = storageService.getAppointments();
      const updated = [data, ...current];
      storageService.saveAppointments(updated);
      return data;
    },
    delete: async (id: string): Promise<void> => {
      await delay(LATENCY);
      const current = storageService.getAppointments();
      storageService.saveAppointments(current.filter(a => a.id !== id));
    },
    update: async (data: Appointment): Promise<Appointment> => {
      await delay(LATENCY);
      const current = storageService.getAppointments();
      storageService.saveAppointments(current.map(a => a.id === data.id ? data : a));
      return data;
    }
  },
  clients: {
    list: async (): Promise<Client[]> => {
      await delay(LATENCY);
      return storageService.getClients();
    },
    delete: async (id: string): Promise<void> => {
      await delay(LATENCY);
      const current = storageService.getClients();
      storageService.saveClients(current.filter(c => c.id !== id));
    }
  },
  system: {
    checkAvailability: async (date: string): Promise<string[]> => {
      await delay(1200); // Simulate heavy lookup
      // In production, check against existing appointments
      return ["09:00", "10:00", "11:00", "12:00", "13:30", "14:30", "15:30", "16:30"];
    }
  }
};

