                <h2 className="text-2xl font-black text-slate-900">Pick Time</h2>
                {isCheckingSlots ? (
                  <div className="py-20 flex flex-col items-center gap-4">
                    <Loader2 className="animate-spin text-indigo-600" size={40} />
                    <p className="text-xs font-black uppercase tracking-widest text-slate-400">Verifying availability...</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                    {availableSlots.map(t_val => (
                      <button 
                        key={t_val} 
                        onClick={() => {setSelectedTime(t_val); setStep(4);}} 
                        className={`py-6 rounded-2xl font-black text-lg transition-all border-2 active:scale-95 ${
                          selectedTime === t_val ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-slate-50 border-transparent text-slate-700 hover:bg-white hover:border-indigo-600'
                        }`}
                      >
                        {t_val}
                      </button>
                    ))}
                  </div>
                )}
                <button onClick={() => setStep(2)} className="text-xs font-black text-slate-400 uppercase flex items-center gap-2 mx-auto hover:text-indigo-600">Change Date</button>
              </div>
            )}

            {step === 4 && (
              <div className="max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center p-6 bg-indigo-50 rounded-[32px] border border-indigo-100">
                  <h3 className="text-xl font-black text-slate-900 mb-1">{selectedService?.name}</h3>
                  <p className="text-sm font-bold text-slate-600">
                    {new Date(selectedDate).toLocaleDateString('en-US', { weekday: 'short', month: 'long', day: 'numeric' })} @ {selectedTime}
                  </p>
                </div>

                <div className="space-y-4">
                  <div className="relative">
                    <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required placeholder="Full Name" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 pl-12 pr-6 focus:bg-white focus:border-indigo-600 outline-none transition-all text-sm font-bold" value={clientInfo.name} onChange={e => setClientInfo({...clientInfo, name: e.target.value})} />
                  </div>
                  <div className="relative">
                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required type="email" placeholder="Email Address" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 pl-12 pr-6 focus:bg-white focus:border-indigo-600 outline-none transition-all text-sm font-bold" value={clientInfo.email} onChange={e => setClientInfo({...clientInfo, email: e.target.value})} />
                  </div>
                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required type="tel" placeholder="Phone Number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl py-4 pl-12 pr-6 focus:bg-white focus:border-indigo-600 outline-none transition-all text-sm font-bold" value={clientInfo.phone} onChange={e => setClientInfo({...clientInfo, phone: e.target.value})} />
                  </div>
                </div>

                <div className="pt-4 space-y-4">
                  <label className="flex items-start gap-3 cursor-pointer group">
                    <input type="checkbox" checked={hasConsented} onChange={e => setHasConsented(e.target.checked)} className="mt-1 w-5 h-5 rounded border-2 border-slate-300 text-indigo-600 focus:ring-indigo-500 transition-all" />
                    <span className="text-[10px] font-black uppercase text-slate-400 leading-relaxed tracking-widest">
                      Agree to policy & session terms.
                    </span>
                  </label>

                  <button onClick={handleBook} disabled={isSubmitting || !clientInfo.name || !hasConsented} className="w-full py-5 bg-indigo-600 text-white rounded-[24px] font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-3">
                    {isSubmitting ? <Loader2 size={20} className="animate-spin" /> : <Lock size={18} />}
                    {isSubmitting ? 'Authorizing...' : 'Finalize Reservation'}
                  </button>
                  <button onClick={() => setStep(3)} className="w-full text-xs font-black text-slate-400 uppercase flex items-center justify-center gap-2 hover:text-indigo-600">Back to schedule</button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PublicBookingPage;

import React, { useState } from 'react';
import { Appointment } from '../types';
import { Calendar as CalendarIcon, Plus, CheckCircle2, Bell, Send, Loader2, Globe, Trash2, Smartphone } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';
import { notificationService } from '../services/notificationService';

interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
  onUpdateAppointment?: (apt: Appointment) => void;
  onDeleteAppointment?: (id: string) => void;
  connectedApps: string[];
  currency?: 'ILS' | 'USD' | 'EUR' | 'GBP';
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ 
  appointments, 
  onAddClick, 
  onUpdateAppointment, 
  onDeleteAppointment,
  connectedApps,
  currency
}) => {
  const [sendingId, setSendingId] = useState<string | null>(null);
  const currencySymbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency || 'USD'] || '$';

  const handleSendReminder = async (apt: Appointment) => {
    setSendingId(apt.id);
    const businessName = localStorage.getItem('bookly_business_name') || 'Bookly Business';

    // 1. Generate via AI
    const message = await geminiAssistant.draftReminder(apt, businessName);

    // 2. Dispatch via Notification Service (Live simulation)
    const result = await notificationService.sendReminder(apt, message || '');

    if (result.success && onUpdateAppointment) {
      onUpdateAppointment({ 
        ...apt, 
        reminderSent: true, 
        reminderTimestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
      });
    }
    setSendingId(null);
  };

  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-3xl md:border border-slate-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-6 md:p-8 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-xl font-black text-slate-900">Operations Schedule</h3>
          <p className="text-sm text-slate-500 font-medium mt-0.5">Manage daily sessions and live client communications</p>
        </div>
        <div className="flex items-center justify-between md:justify-end gap-3">
          <button 
            onClick={onAddClick}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl hover:bg-slate-900 transition-all font-black text-xs shadow-xl active:scale-95"
          >
            <Plus size={14} />
            New Session
          </button>
        </div>
      </div>

      <div className="p-6 md:p-10 space-y-10">
        {dates.length === 0 ? (
          <div className="text-center py-24 text-slate-400">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <CalendarIcon size={32} className="opacity-20" />
            </div>
            <p className="font-bold text-sm">No scheduled sessions.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date}>
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-3">
                <span className="shrink-0">{new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}</span>
                <div className="h-px bg-slate-100 flex-1" />
              </h4>
              <div className="space-y-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => (
                  <div key={apt.id} className="group flex items-center gap-6 p-6 rounded-[28px] border border-slate-50 hover:border-indigo-100 hover:bg-slate-50/50 transition-all bg-white relative">
                    <div className="flex flex-col items-center justify-center w-16 text-center border-r pr-6 border-slate-100 shrink-0">
                      <span className="text-base font-black text-slate-900 leading-tight">{apt.time}</span>
                      <span className="text-[10px] font-black text-slate-400 uppercase">{apt.duration}m</span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1.5">
                        <h5 className="font-black text-slate-900 text-base truncate">{apt.clientName}</h5>
                        <div className="flex items-center gap-2">
                          {apt.reminderSent && (
                             <span className="flex items-center gap-1.5 text-[9px] font-black uppercase text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                               <Smartphone size={10} fill="currentColor" /> Dispatched {apt.reminderTimestamp}
                             </span>
                          )}
                          <span className={`flex items-center gap-1.5 text-[9px] font-black uppercase px-3 py-1 rounded-full border ${apt.status === 'confirmed' ? 'text-indigo-500 bg-indigo-50 border-indigo-100' : 'text-slate-400 bg-slate-50 border-slate-100'}`}>
                            <CheckCircle2 size={10} fill="currentColor" /> {apt.status}
                          </span>
                        </div>
                      </div>
                      <p className="text-sm text-slate-500 font-medium truncate">{apt.service}</p>
                    </div>
                    <div className="text-right shrink-0 flex items-center gap-4">
                      <div className="hidden sm:block text-right pr-4 border-r border-slate-100">
                        <p className="text-lg font-black text-slate-900">{currencySymbol}{apt.price}</p>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Revenue</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleSendReminder(apt)}
                          disabled={sendingId === apt.id}
                          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${apt.reminderSent ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-indigo-600 hover:bg-slate-50'}`}
                          title="Send SMS Reminder"
                        >
                          {sendingId === apt.id ? <Loader2 size={16} className="animate-spin" /> : <Send size={18} />}
                        </button>
                        <button 
                          onClick={() => onDeleteAppointment?.(apt.id)}
                          className="w-10 h-10 rounded-xl text-slate-300 hover:text-rose-600 hover:bg-rose-50 transition-all flex items-center justify-center"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default AppointmentCalendar;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import BottomNav from './components/BottomNav';
import Dashboard from './components/Dashboard';
import AppointmentCalendar from './components/AppointmentCalendar';
import AIAssistant from './components/AIAssistant';
import MarketingStudio from './components/MarketingStudio';
import Pricing from './components/Pricing';
import PublicBookingPage from './components/PublicBookingPage';
import Settings from './components/Settings';
import AddAppointmentModal from './components/AddAppointmentModal';
import Onboarding from './components/Onboarding';
import { Appointment, Client } from './types';
import { api } from './services/api';
import { storageService } from './services/storageService';
import { Plus, Search, Bell, Loader2, Radio, CheckCircle2, AlertCircle, X, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [isInitializing, setIsInitializing] = useState(true);
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Business State
  const [currency, setCurrency] = useState<'ILS' | 'USD' | 'EUR' | 'GBP'>(() => (localStorage.getItem('bookly_currency') as any) || 'USD');
  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');
  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => storageService.getSubscription());
  const [connectedApps, setConnectedApps] = useState<string[]>(() => JSON.parse(localStorage.getItem('bookly_connected_apps') || '[]'));

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [services, setServices] = useState(() => JSON.parse(localStorage.getItem('bookly_services') || '[]'));
  const [legalData, setLegalData] = useState(() => JSON.parse(localStorage.getItem('bookly_legal') || '{"privacyPolicy": "", "termsOfService": "", "gdprStrict": true}'));

  // Hydration: Fetching data from the Production Bridge
  useEffect(() => {
    const hydrate = async () => {
      try {
        const [aptData, clientData] = await Promise.all([
          api.appointments.list(),
          api.clients.list()
        ]);
        setAppointments(aptData);
        setClients(clientData);
      } catch (err) {
        showToast("Synchronization failure. Retrying...", "error");
      } finally {
        setTimeout(() => setIsInitializing(false), 800);
      }
    };
    if (isOnboarded) hydrate();
    else setIsInitializing(false);
  }, [isOnboarded]);

  useEffect(() => {
    const path = window.location.pathname;
    if (path.includes('/book/')) setIsPublicView(true);
  }, []);

  // Persistence triggers
  useEffect(() => {
    if (!isInitializing) {
      storageService.saveAppointments(appointments);
      storageService.saveClients(clients);
      storageService.saveSubscription(subscriptionPlan);
      localStorage.setItem('bookly_services', JSON.stringify(services));
      localStorage.setItem('bookly_business_name', businessName);
      localStorage.setItem('bookly_business_category', businessCategory);
      localStorage.setItem('bookly_onboarded', isOnboarded.toString());
      localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps));
      localStorage.setItem('bookly_legal', JSON.stringify(legalData));
      localStorage.setItem('bookly_currency', currency);
    }
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan, connectedApps, legalData, currency, isInitializing]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleNewBooking = async (newBooking: Appointment) => {
    const saved = await api.appointments.create(newBooking);
    setAppointments(prev => [saved, ...prev]);
    showToast(`Session locked for ${saved.clientName}`);
  };

  const handleUpdateAppointment = async (updatedApt: Appointment) => {
    const saved = await api.appointments.update(updatedApt);
    setAppointments(prev => prev.map(apt => apt.id === saved.id ? saved : apt));
  };

  const handleDeleteAppointment = async (id: string) => {
    await api.appointments.delete(id);
    setAppointments(prev => prev.filter(a => a.id !== id));
    showToast("Session cancelled", "error");
  };

  const filteredAppointments = useMemo(() => {
    if (!searchQuery) return appointments;
    const q = searchQuery.toLowerCase();
    return appointments.filter(a => a.clientName.toLowerCase().includes(q) || a.service.toLowerCase().includes(q));
  }, [appointments, searchQuery]);

  const filteredClients = useMemo(() => {
    if (!searchQuery) return clients;
    const q = searchQuery.toLowerCase();
    return clients.filter(c => c.name.toLowerCase().includes(q) || c.email.toLowerCase().includes(q));
  }, [clients, searchQuery]);

  if (!isOnboarded) {
    return <Onboarding onComplete={(data) => { setBusinessName(data.name); setBusinessCategory(data.category); setIsOnboarded(true); }} />;
  }

  if (isInitializing) {
    return (
      <div className="h-screen w-screen bg-slate-900 flex flex-col items-center justify-center space-y-8 animate-in fade-in duration-500">
         <div className="w-20 h-20 bg-indigo-600 rounded-[24px] flex items-center justify-center text-white shadow-2xl shadow-indigo-500/20 animate-pulse">
            <Radio size={40} className="animate-bounce" />
         </div>
         <div className="text-center space-y-2">
            <h2 className="text-white text-xl font-black tracking-widest uppercase">Initializing Live Core</h2>
            <div className="flex items-center justify-center gap-2 text-indigo-400 text-[10px] font-black uppercase tracking-[0.2em]">
               <ShieldCheck size={12} /> Encrypted Handshake Active
            </div>
         </div>
      </div>
    );
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        legalData={legalData}
        currency={currency}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          businessName={businessName}
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          currency={currency}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
      case 'calendar':
        return (
          <AppointmentCalendar 
            appointments={filteredAppointments} 
            onAddClick={() => setShowAddModal(true)} 
            onUpdateAppointment={handleUpdateAppointment}
            onDeleteAppointment={handleDeleteAppointment}
            connectedApps={connectedApps}
            currency={currency}
          />
        );
      case 'marketing':
        return <MarketingStudio />;
      case 'clients':
        return (
          <div className="space-y-10 animate-in fade-in duration-700 pb-32">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1">
                  <Plus size={12} /> CRM Command
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Clients</h2>
                <p className="text-slate-500 font-medium">Managing {filteredClients.length} active relationships.</p>
              </div>
              <button className="flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-indigo-600 transition-all font-black text-xs active:scale-95">
                <Plus size={16} /> New Client
              </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClients.map((client) => (
                <div key={client.id} className="p-10 bg-white border border-slate-100 rounded-[40px] hover:border-indigo-600 transition-all hover:shadow-2xl group relative overflow-hidden">
                  <div className="flex flex-col items-center text-center">
                    <div className="w-24 h-24 bg-slate-50 text-slate-400 border border-slate-100 rounded-[32px] flex items-center justify-center text-3xl font-black group-hover:bg-indigo-600 group-hover:text-white group-hover:scale-110 transition-all duration-500 mb-6">
                      {client.name.charAt(0)}
                    </div>
                    <h4 className="text-2xl font-black text-slate-900 tracking-tight">{client.name}</h4>
                    <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1 mb-8">{client.email}</p>
                    <div className="w-full grid grid-cols-2 gap-2">
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Status</span>
                          <span className="text-sm font-black text-emerald-500">Live</span>
                       </div>
                       <div className="p-4 bg-slate-50 rounded-2xl border border-slate-50 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Tier</span>
                          <span className="text-sm font-black text-slate-900">VIP</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => { setSubscriptionPlan(p); showToast(`Plan upgraded to ${p}!`); }} />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={(n) => { setBusinessName(n); showToast("Profile synchronized"); }} 
            services={services}
            onUpdateServices={(s) => { setServices(s); showToast("Service catalog updated"); }}
            connectedApps={connectedApps}
            onUpdateConnectedApps={setConnectedApps}
            legalData={legalData}
            onUpdateLegalData={(d) => { setLegalData(d); showToast("Legal compliance verified"); }}
            currency={currency}
            onUpdateCurrency={setCurrency}
          />
        );
      default:
        return <Dashboard 
          businessName={businessName} 
          appointments={appointments} 
          clients={clients} 
          connectedApps={connectedApps}
          legalData={legalData}
          currency={currency}
          onOpenPublicView={() => setIsPublicView(true)} 
        />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        subscriptionPlan={subscriptionPlan} 
        connectedApps={connectedApps}
      />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-24 bg-white/80 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 shrink-0 z-20">
          <div className="flex items-center gap-10 flex-1">
             <div className="relative w-full max-w-md hidden md:block">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
               <input 
                  type="text" 
                  placeholder="Global Search Core..."
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 pl-12 pr-12 text-sm font-medium focus:ring-2 focus:ring-indigo-600 outline-none transition-all"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
               />
             </div>
          </div>
          <div className="flex items-center gap-8">
            <button className="text-slate-300 hover:text-indigo-600 transition-colors relative">
              <Bell size={22} strokeWidth={2} />
              <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-rose-500 border-2 border-white rounded-full" />
            </button>
            <div className="flex items-center gap-5 border-l pl-8 border-slate-100">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-black text-slate-900 tracking-tight leading-none">{businessName}</p>
                <div className="flex items-center justify-end gap-2 mt-1.5">
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{businessCategory}</span>
                </div>
              </div>
              <div className="w-12 h-12 rounded-2xl bg-slate-900 flex items-center justify-center text-white text-sm font-black shadow-xl ring-4 ring-slate-50 hover:scale-105 transition-transform">
                {businessName.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        {toast && (
          <div className="fixed top-28 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-4 rounded-[20px] shadow-2xl animate-in slide-in-from-top-10 duration-500 bg-indigo-600 text-white border border-indigo-400">
            {toast.type === 'success' ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
