export interface CheckoutSession {
  id: string;
  amount: number;
  currency: string;
  status: 'pending' | 'completed' | 'failed';
}

export interface MerchantStats {
  grossEarnings: number;
  pendingPayout: number;
  isStripeConnected: boolean;
  lastPayoutDate?: string;
}

export const paymentService = {
  // Retrieves simulated merchant earnings from storage
  getMerchantStats: (): MerchantStats => {
    const data = localStorage.getItem('bookly_merchant_stats');
    return data ? JSON.parse(data) : {
      grossEarnings: 1450.50, // Mock initial data
      pendingPayout: 240.00,
      isStripeConnected: false
    };
  },

  saveMerchantStats: (stats: MerchantStats) => {
    localStorage.setItem('bookly_merchant_stats', JSON.stringify(stats));
  },

  async createCheckoutSession(amount: number, currency: string): Promise<CheckoutSession> {
    // In production, this would call: 
    // const session = await stripe.checkout.sessions.create({ ... });
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          id: `cs_${Math.random().toString(36).substr(2, 9)}`,
          amount,
          currency,
          status: 'pending'
        });
      }, 800);
    });
  },

  async processPayment(sessionId: string, amount: number): Promise<boolean> {
    // Simulates the credit card processing step
    return new Promise((resolve) => {
      setTimeout(() => {
        const stats = this.getMerchantStats();
        stats.grossEarnings += amount;
        stats.pendingPayout += amount;
        this.saveMerchantStats(stats);
        resolve(true);
      }, 2500);
    });
  },

  async connectStripe(): Promise<boolean> {
    // Simulates the Stripe Connect OAuth flow
    return new Promise((resolve) => {
      setTimeout(() => {
        const stats = this.getMerchantStats();
        stats.isStripeConnected = true;
        this.saveMerchantStats(stats);
        resolve(true);
      }, 1500);
    });
  }
};

