export interface Transaction {
  id: string;
  type: 'subscription' | 'payout' | 'booking';
  amount: number;
  currency: string;
  date: string;
  status: 'succeeded' | 'processing' | 'failed';
  description: string;
}

export interface MerchantStats {
  grossEarnings: number;
  netEarnings: number;
  pendingPayout: number;
  isStripeConnected: boolean;
  stripeAccountId?: string;
  history: Transaction[];
}

export const paymentService = {
  getMerchantStats: (): MerchantStats => {
    const data = localStorage.getItem('bookly_merchant_stats');
    if (data) return JSON.parse(data);

    // Default initial state
    return {
      grossEarnings: 0,
      netEarnings: 0,
      pendingPayout: 0,
      isStripeConnected: false,
      history: []
    };
  },

  saveMerchantStats: (stats: MerchantStats) => {
    localStorage.setItem('bookly_merchant_stats', JSON.stringify(stats));
  },

  async connectStripe(): Promise<boolean> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const stats = this.getMerchantStats();
        stats.isStripeConnected = true;
        stats.stripeAccountId = `acct_${Math.random().toString(36).substr(2, 14)}`;

        // Add a "system" notification for connection
        stats.history.unshift({
          id: `tx_${Date.now()}`,
          type: 'payout',
          amount: 0,
          currency: 'ILS',
          date: new Date().toLocaleString(),
          status: 'succeeded',
          description: 'Stripe Connect: Bank Account Verified'
        });

        this.saveMerchantStats(stats);
        resolve(true);
      }, 2000);
    });
  },

  async processIncomingPayment(amount: number, currency: string, description: string): Promise<void> {
    const stats = this.getMerchantStats();

    // In real Stripe, processing fees are ~2.9% + 1.20 ILS
    const fee = (amount * 0.029) + 1.2;
    const net = amount - fee;

    stats.grossEarnings += amount;
    stats.pendingPayout += net;
    stats.netEarnings += net;

    stats.history.unshift({
      id: `ch_${Math.random().toString(36).substr(2, 9)}`,
      type: 'subscription',
      amount: amount,
      currency: currency,
      date: new Date().toLocaleString(),
      status: 'succeeded',
      description: description
    });

    this.saveMerchantStats(stats);
  },

  async triggerPayout(): Promise<boolean> {
    const stats = this.getMerchantStats();
    if (stats.pendingPayout <= 0) return false;

    return new Promise((resolve) => {
      setTimeout(() => {
        const amountToPay = stats.pendingPayout;
        stats.pendingPayout = 0;

        stats.history.unshift({
          id: `po_${Math.random().toString(36).substr(2, 9)}`,
          type: 'payout',
          amount: -amountToPay,
          currency: 'ILS',
          date: new Date().toLocaleString(),
          status: 'processing',
          description: 'Transfer to Bank (Discount Bank Israel)'
        });

        this.saveMerchantStats(stats);
        resolve(true);
      }, 1500);
    });
  }
};

