export interface Transaction {
  id: string;
  type: 'subscription' | 'payout' | 'booking';
  amount: number;
  currency: string;
  date: string;
  status: 'succeeded' | 'processing' | 'failed';
  description: string;
  invoiceUrl?: string; // Link to the digital tax receipt
}

export interface MerchantStats {
  grossEarnings: number;
  netEarnings: number;
  pendingPayout: number;
  isGatewayConnected: boolean;
  clearerName?: string;
  history: Transaction[];
}

export const paymentService = {
  getMerchantStats: (): MerchantStats => {
    const data = localStorage.getItem('bookly_merchant_stats');
    if (data) return JSON.parse(data);

    return {
      grossEarnings: 1250,
      netEarnings: 1180,
      pendingPayout: 450,
      isGatewayConnected: false,
      history: []
    };
  },

  saveMerchantStats: (stats: MerchantStats) => {
    localStorage.setItem('bookly_merchant_stats', JSON.stringify(stats));
  },

  async connectLocalGateway(): Promise<boolean> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const stats = this.getMerchantStats();
        stats.isGatewayConnected = true;
        stats.clearerName = "Meshulam / Morning API";

        stats.history.unshift({
          id: `sys_${Date.now()}`,
          type: 'payout',
          amount: 0,
          currency: 'ILS',
          date: new Date().toLocaleString('he-IL'),
          status: 'succeeded',
          description: 'Local Gateway Verified: Tax Invoices Enabled'
        });

        this.saveMerchantStats(stats);
        resolve(true);
      }, 1500);
    });
  },

  async processIncomingPayment(amount: number, description: string): Promise<void> {
    const stats = this.getMerchantStats();

    // Local clearing fees are usually lower than Stripe in Israel (~1.5% - 2%)
    const fee = (amount * 0.018) + 1.0; 
    const net = amount - fee;

    stats.grossEarnings += amount;
    stats.pendingPayout += net;
    stats.netEarnings += net;

    // Simulate Digital Invoice Generation (Legal requirement in Israel)
    const invoiceId = `INV-${Math.floor(1000 + Math.random() * 9000)}`;

    stats.history.unshift({
      id: `ch_${Math.random().toString(36).substr(2, 9)}`,
      type: 'subscription',
      amount: amount,
      currency: 'ILS',
      date: new Date().toLocaleString('he-IL'),
      status: 'succeeded',
      description: `${description} (Invoice ${invoiceId})`,
      invoiceUrl: '#' // In real app, this would be a PDF link from Morning/Meshulam
    });

    this.saveMerchantStats(stats);
  },

  async triggerPayout(): Promise<boolean> {
    const stats = this.getMerchantStats();
    if (stats.pendingPayout <= 0) return false;

    return new Promise((resolve) => {
      setTimeout(() => {
        const amountToPay = stats.pendingPayout;
        stats.pendingPayout = 0;

        stats.history.unshift({
          id: `po_${Math.random().toString(36).substr(2, 9)}`,
          type: 'payout',
          amount: -amountToPay,
          currency: 'ILS',
          date: new Date().toLocaleString('he-IL'),
          status: 'processing',
          description: 'Bank Transfer: Discount / Leumi'
        });

        this.saveMerchantStats(stats);
        resolve(true);
      }, 1200);
    });
  }
};

