const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, legalData, currency, onBookingComplete, onBack }) => {
  const [clientLang, setClientLang] = useState<'en' | 'he'>('en');
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<any>(null);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '' });
  const [hasConsented, setHasConsented] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCheckingSlots, setIsCheckingSlots] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [availableSlots, setAvailableSlots] = useState<string[]>([]);

  // Simple conversion for global clients - in real world use an API
  const convertPrice = (priceInIls: number) => {
    if (currency === 'ILS') return priceInIls;
    const rates = { USD: 0.27, EUR: 0.25, GBP: 0.21 };
    return Math.round(priceInIls * (rates[currency as keyof typeof rates] || 1));
  };

  const symbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency];

  const t = {
    en: {
      select: "Select Session",
      pickDate: "Pick Date",
      pickTime: "Pick Time",
      confirm: "Booking Confirmed!",
      back: "Back to Home",
      info: "Contact Details",
      finalize: "Finalize Reservation",
      policy: "Agree to policy & session terms.",
      verifying: "Verifying availability...",
      today: "Today"
    },
    he: {
      select: "בחירת שירות",
      pickDate: "בחירת תאריך",
      pickTime: "בחירת שעה",
      confirm: "ההזמנה אושרה!",
      back: "חזרה לדף הבית",
      info: "פרטי התקשרות",
      finalize: "סיום הזמנה",
      policy: "אני מסכים לתנאי השימוש והמדיניות",
      verifying: "בודק זמינות...",
      today: "היום"
    }
  }[clientLang];

  const isRtl = clientLang === 'he';

  useEffect(() => {
    if (step === 3) {
      const fetchSlots = async () => {
        setIsCheckingSlots(true);
        const slots = await api.system.checkAvailability(selectedDate);
        setAvailableSlots(slots);
        setIsCheckingSlots(false);
      };
      fetchSlots();
    }
  }, [step, selectedDate]);

  const handleBook = async () => {
    setIsSubmitting(true);
    const result = await api.appointments.create({ 
      id: Math.random().toString(36).substr(2, 9), 
      clientId: 'public-' + Date.now(),
      clientName: clientInfo.name, 
      service: selectedService.name, 
      date: selectedDate, 
      time: selectedTime, 
      duration: selectedService.duration, 
      status: 'confirmed', 
      price: selectedService.price,
    });

    onBookingComplete(result);
    setIsSubmitting(false);
    setIsSuccess(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (isSuccess) {
    return (
      <div className={`min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-700 ${isRtl ? 'font-["Heebo"]' : ''}`} dir={isRtl ? 'rtl' : 'ltr'}>
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4">{t.confirm}</h2>
        <p className="text-slate-500 mb-10 max-w-sm font-medium">
