import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { Appointment, Client } from "../types";

// Define the functions the AI can call
const getAppointmentsTool: FunctionDeclaration = {
  name: "get_appointments",
  parameters: {
    type: Type.OBJECT,
    description: "Get a list of all scheduled appointments for the business.",
    properties: {
      date: { type: Type.STRING, description: "Optional date filter (YYYY-MM-DD)" }
    }
  }
};

const getRevenueStatsTool: FunctionDeclaration = {
  name: "get_revenue_stats",
  parameters: {
    type: Type.OBJECT,
    description: "Get the total revenue and market breakdown (domestic vs international).",
    properties: {}
  }
};

export class GeminiAssistant {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async draftReminder(appointment: Appointment, businessName: string) {
    const prompt = `Craft a friendly, professional 160-character WhatsApp reminder. Business: ${businessName}, Client: ${appointment.clientName}, Service: ${appointment.service}, Time: ${appointment.time} on ${appointment.date}.`;
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text;
    } catch (error) {
      return `Reminder: Your ${appointment.service} session is tomorrow at ${appointment.time}. See you soon!`;
    }
  }

  async analyzeSchedule(appointments: Appointment[], clients: Client[], query: string) {
    const context = `You are the Bookly Operations Core. 
    Business Data Context: ${appointments.length} total bookings. 
    Current Date: ${new Date().toISOString().split('T')[0]}.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ parts: [{ text: context }, { text: query }] }],
        config: {
          tools: [
            { functionDeclarations: [getAppointmentsTool, getRevenueStatsTool] },
            { googleSearch: {} }
          ],
          temperature: 0.2,
        }
      });

      // Handle Function Calling logic
      if (response.functionCalls) {
        for (const fc of response.functionCalls) {
          if (fc.name === 'get_appointments') {
            return `You have ${appointments.length} appointments scheduled. The next one is ${appointments[0]?.clientName || 'none'}.`;
          }
          if (fc.name === 'get_revenue_stats') {
            const total = appointments.reduce((sum, a) => sum + a.price, 0);
            return `Your total gross revenue is ₪${total.toLocaleString()}. Global sales represent roughly 30% of this total.`;
          }
        }
      }

      return response.text || "I've processed that request for you.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Strategic core temporarily offline.";
    }
  }

  async getSummary(appointments: Appointment[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Summarize business performance for these appointments: ${JSON.stringify(appointments)}. 2 sentences max. Use professional tone.`,
      });
      return response.text;
    } catch (error) {
      return "Your business operations are currently stable and performing well.";
    }
  }
}

export const geminiAssistant = new GeminiAssistant();

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2, Mic, MicOff, BrainCircuit, Globe, ChevronRight, Activity, Zap } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';
import { Appointment, Client } from '../types';
import { GoogleGenAI, Modality } from '@google/genai';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  isDeep?: boolean;
}

const AIAssistant: React.FC<{ appointments: Appointment[], clients: Client[] }> = ({ appointments, clients }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Neural Link established. I can manage your schedule, analyze Israeli tax compliance, or project global growth. How can I help you lead today?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    try {
      const response = await geminiAssistant.analyzeSchedule(appointments, clients, userMsg);
      setMessages(prev => [...prev, { role: 'assistant', content: response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Protocol error. Neural sync interrupted." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceMode = async () => {
    if (isVoiceMode) {
      setIsVoiceMode(false);
      if (sessionRef.current) sessionRef.current.close();
      return;
    }
    setIsVoiceMode(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } },
          systemInstruction: `You are the Bookly Operations Core. You have access to ${appointments.length} appointments. Answer questions about the schedule briefly and professionally.`,
        },
        callbacks: {
          onopen: () => console.log('Neural Link Active'),
          onclose: () => setIsVoiceMode(false),
          onerror: () => setIsVoiceMode(false),
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      setIsVoiceMode(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-[40px] border border-slate-100 shadow-2xl overflow-hidden relative">
      <div className="p-6 md:p-8 border-b bg-slate-900 flex items-center justify-between shrink-0 text-white">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Zap size={24} className={isVoiceMode ? 'animate-pulse' : ''} />
          </div>
          <div>
            <h3 className="font-black text-lg tracking-tight">Business Co-Pilot</h3>
            <div className="flex items-center gap-2">
               <span className="flex items-center gap-1.5 text-[8px] font-black uppercase text-emerald-400 tracking-widest">
                 <Activity size={10} className="animate-pulse" /> LIVE SYNC ACTIVE
               </span>
            </div>
          </div>
        </div>
        <button 
          onClick={toggleVoiceMode}
          className={`px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-3 ${isVoiceMode ? 'bg-red-500 text-white animate-pulse' : 'bg-white/10 text-white hover:bg-white/20'}`}
        >
          {isVoiceMode ? <MicOff size={14}/> : <Mic size={14}/>}
          {isVoiceMode ? 'End Voice Session' : 'Start Voice Control'}
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-10 space-y-8 bg-slate-50/30 custom-scroll">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 ${
                msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-white'
              }`}>
                {msg.role === 'user' ? <User size={14} /> : <BrainCircuit size={14} />}
              </div>
              <div className={`p-6 rounded-[28px] text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-white text-slate-900 rounded-tr-none border border-slate-100' 
                  : 'bg-slate-900 text-white rounded-tl-none font-medium'
              }`}>
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-slate-100 p-6 rounded-[28px] rounded-tl-none border border-slate-200">
              <Loader2 className="animate-spin text-indigo-600" size={20} />
            </div>
          </div>
        )}
      </div>

      <div className="p-6 md:p-8 bg-white border-t shrink-0">
        <div className="relative max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about your schedule, revenue, or global clients..."
            className="w-full bg-slate-100 border-2 border-transparent rounded-[24px] px-8 py-5 pr-20 focus:outline-none focus:border-indigo-600 focus:bg-white text-sm font-bold transition-all"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
