interface AppointmentCalendarProps {
  appointments: Appointment[];
  onAddClick: () => void;
  onUpdateAppointment?: (apt: Appointment) => void;
  onDeleteAppointment?: (id: string) => void;
  connectedApps: string[];
  currency?: 'ILS' | 'USD' | 'EUR' | 'GBP';
}

const AppointmentCalendar: React.FC<AppointmentCalendarProps> = ({ 
  appointments, 
  onAddClick, 
  onUpdateAppointment, 
  onDeleteAppointment,
  connectedApps,
  currency
}) => {
  const [sendingId, setSendingId] = useState<string | null>(null);
  const currencySymbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency || 'USD'] || '$';

  // In a real app, this would be fetched from the client's metadata
  const getClientTimezone = (clientId: string) => {
    return clientId.includes('public') ? 'UTC-5 (EST)' : 'UTC+2 (IST)';
  };

  const handleSendReminder = async (apt: Appointment) => {
    setSendingId(apt.id);
    const businessName = localStorage.getItem('bookly_business_name') || 'Bookly Business';
    const message = await geminiAssistant.draftReminder(apt, businessName);
    const result = await notificationService.sendReminder(apt, message || '');

    if (result.success && onUpdateAppointment) {
      onUpdateAppointment({ 
        ...apt, 
        reminderSent: true, 
        reminderTimestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
      });
    }
    setSendingId(null);
  };

  const grouped = appointments.reduce((acc, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push(curr);
    return acc;
  }, {} as Record<string, Appointment[]>);

  const dates = Object.keys(grouped).sort();

  return (
    <div className="bg-white rounded-[40px] md:border border-slate-100 shadow-sm overflow-hidden mb-20 md:mb-0">
      <div className="p-8 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white sticky top-0 z-10">
        <div>
          <h3 className="text-2xl font-black text-slate-900 tracking-tight">Global Schedule</h3>
          <p className="text-sm text-slate-500 font-medium mt-0.5">Synced across Israeli & International time zones</p>
        </div>
        <button 
          onClick={onAddClick}
          className="flex items-center gap-3 px-8 py-4 bg-indigo-600 text-white rounded-2xl hover:bg-slate-900 transition-all font-black text-sm shadow-xl active:scale-95"
        >
          <Plus size={18} />
          Schedule Session
        </button>
      </div>

      <div className="p-6 md:p-10 space-y-12">
        {dates.length === 0 ? (
          <div className="text-center py-24 text-slate-300">
            <div className="w-24 h-24 bg-slate-50 rounded-[32px] flex items-center justify-center mx-auto mb-6">
              <CalendarIcon size={40} className="opacity-20" />
            </div>
            <p className="font-black uppercase tracking-widest text-xs">No active sessions.</p>
          </div>
        ) : (
          dates.map(date => (
            <div key={date} className="space-y-6">
              <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-4">
                <span className="shrink-0 bg-slate-100 px-4 py-1.5 rounded-full text-slate-600">
                  {new Date(date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}
                </span>
                <div className="h-px bg-slate-100 flex-1" />
              </h4>
              <div className="space-y-4">
                {grouped[date].sort((a,b) => a.time.localeCompare(b.time)).map(apt => {
                  const isInternational = apt.clientId.includes('public');
                  return (
                    <div key={apt.id} className="group flex flex-col md:flex-row md:items-center gap-6 p-8 rounded-[36px] border border-slate-50 hover:border-indigo-100 hover:bg-slate-50/50 transition-all bg-white relative">
                      <div className="flex items-center md:flex-col justify-between md:justify-center md:w-20 md:text-center md:border-r md:pr-8 md:border-slate-100 shrink-0 gap-2">
                        <span className="text-xl font-black text-slate-900">{apt.time}</span>
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 md:bg-transparent px-2 py-1 rounded-md">{apt.duration}M</span>
                      </div>

                      <div className="flex-1 min-w-0 space-y-1">
                        <div className="flex items-center flex-wrap gap-2 mb-1">
                          <h5 className="font-black text-slate-900 text-lg truncate">{apt.clientName}</h5>
                          {isInternational && (
                            <div className="flex items-center gap-1.5 px-2.5 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[9px] font-black uppercase tracking-tighter border border-indigo-100">
