import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { Appointment, Client } from "../types";

const getAppointmentsTool: FunctionDeclaration = {
  name: "get_appointments",
  parameters: {
    type: Type.OBJECT,
    description: "Get a list of all scheduled appointments for the business.",
    properties: {
      date: { type: Type.STRING, description: "Optional date filter (YYYY-MM-DD)" }
    }
  }
};

const getRevenueStatsTool: FunctionDeclaration = {
  name: "get_revenue_stats",
  parameters: {
    type: Type.OBJECT,
    description: "Get the total revenue and market breakdown (domestic vs international).",
    properties: {}
  }
};

export interface GroundingLink {
  uri: string;
  title: string;
}

export class GeminiAssistant {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeSchedule(appointments: Appointment[], clients: Client[], query: string) {
    const context = `You are the Bookly Operations Core. 
    Business Data Context: ${appointments.length} total bookings. 
    Current Date: ${new Date().toISOString().split('T')[0]}.`;

    // Try to get user location for better maps grounding
    let latLng = { latitude: 32.0853, longitude: 34.7818 }; // Default: Tel Aviv
    try {
      const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
      latLng = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
    } catch (e) { /* ignore */ }

    try {
      // Re-initialize to ensure latest API key is used
      const aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await aiInstance.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ parts: [{ text: context }, { text: query }] }],
        config: {
          tools: [
            { functionDeclarations: [getAppointmentsTool, getRevenueStatsTool] },
            { googleSearch: {} },
            { googleMaps: {} }
          ],
          toolConfig: {
            retrievalConfig: { latLng }
          },
          temperature: 0.2,
        }
      });

      const groundingLinks: GroundingLink[] = [];
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      chunks.forEach((chunk: any) => {
        if (chunk.web) groundingLinks.push({ uri: chunk.web.uri, title: chunk.web.title });
        if (chunk.maps) groundingLinks.push({ uri: chunk.maps.uri, title: chunk.maps.title });
      });

      let text = response.text || "";

      if (response.functionCalls) {
        for (const fc of response.functionCalls) {
          if (fc.name === 'get_appointments') {
            text = `You have ${appointments.length} appointments scheduled. The next one is ${appointments[0]?.clientName || 'none'}.`;
          }
          if (fc.name === 'get_revenue_stats') {
            const total = appointments.reduce((sum, a) => sum + a.price, 0);
            text = `Your total gross revenue is ₪${total.toLocaleString()}. Global sales represent roughly 30% of this total.`;
          }
        }
      }

      return { text, links: groundingLinks };
    } catch (error) {
      console.error("Gemini Error:", error);
      return { text: "Strategic core temporarily offline.", links: [] };
    }
  }

  // Fix: Added missing draftReminder method as used in AppointmentCalendar.tsx
  async draftReminder(appointment: Appointment, businessName: string) {
    try {
      const aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await aiInstance.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Draft a friendly, professional one-sentence appointment reminder for ${appointment.clientName} for their ${appointment.service} session at ${businessName} on ${appointment.date} at ${appointment.time}.` }] },
      });
      return response.text;
    } catch (error) {
      console.error("Drafting error:", error);
      return `Friendly reminder of your ${appointment.service} session at ${businessName} on ${appointment.date} at ${appointment.time}.`;
    }
  }

  async getSummary(appointments: Appointment[]) {
    try {
      const aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await aiInstance.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Summarize business performance for these appointments: ${JSON.stringify(appointments)}. 2 sentences max.`,
      });
      return response.text;
    } catch (error) {
      return "Your business operations are currently stable and performing well.";
    }
  }
}

