  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Sparkles, Megaphone, Image as ImageIcon, Copy, Download, Loader2, Wand2, Smartphone, Monitor, Square, Check, RefreshCw, Video, Play, AlertCircle, ExternalLink, Lock, CheckCircle, Clock } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

// Fix: Removed problematic declare global block that conflicted with environment-defined AIStudio type
// Instead, we will cast window to any when accessing aistudio to bypass strict re-declaration and modifier rules.

const MarketingStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'image' | 'video'>('image');
  const [prompt, setPrompt] = useState("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<"1:1" | "4:3" | "16:9" | "9:16">("1:1");
  const [result, setResult] = useState<{ image?: string; video?: string; caption?: string } | null>(null);
  const [videoStatus, setVideoStatus] = useState<string>("");
  const [hasKey, setHasKey] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // Fix: Used (window as any) to avoid compilation errors with predefined aistudio globals
      const selected = await (window as any).aistudio?.hasSelectedApiKey();
      setHasKey(!!selected);
    };
    checkKey();
  }, [activeTab]);

  const handleSelectKey = async () => {
    // Fix: Used (window as any) to trigger the key selection dialog
    await (window as any).aistudio?.openSelectKey();
    setHasKey(true); // Proceed assuming success per race condition rules
  };

  const generateCampaign = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setResult(null);
    // Fix: Initializing GoogleGenAI inside method as per guidelines for dynamic key availability
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const isElite = localStorage.getItem('bookly_subscription_plan') === 'premium';

    try {
      if (activeTab === 'image') {
        const imgModel = isElite ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
        const imgResponse = await ai.models.generateContent({
          model: imgModel,
          contents: { parts: [{ text: `A professional business ad for: ${prompt}. Cinematic aesthetic.` }] },
          config: { imageConfig: { aspectRatio } }
        });

        let base64Image = "";
        for (const part of imgResponse.candidates?.[0]?.content?.parts || []) {
          if (part.inlineData) base64Image = `data:image/png;base64,${part.inlineData.data}`;
        }

        const textResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Create a professional Instagram caption for: ${prompt}`,
        });

        setResult({ image: base64Image, caption: textResponse.text });
      } else {
        // Veo Video Generation
        setVideoStatus("Initializing Cinematic Engine...");
        let operation = await ai.models.generateVideos({
          model: 'veo-3.1-fast-generate-preview',
          prompt: `A high-end cinematic advertisement for ${prompt}. Professional color grading, smooth transitions.`,
          config: {
            numberOfVideos: 1,
            resolution: '1080p',
            aspectRatio: '16:9'
          }
        });

        const statusMessages = [
          "Synthesizing high-res textures...",
          "Simulating lighting pathways...",
          "Refining motion vectors...",
          "Finalizing cinematic render...",
          "Encoding global distribution format..."
        ];
        let msgIndex = 0;

        while (!operation.done) {
          setVideoStatus(statusMessages[msgIndex % statusMessages.length]);
          msgIndex++;
          await new Promise(resolve => setTimeout(resolve, 8000));
          operation = await ai.operations.getVideosOperation({ operation: operation });
        }

        const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
        const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
        const blob = await videoResponse.blob();
        const videoUrl = URL.createObjectURL(blob);

        setResult({ video: videoUrl, caption: `Elevate your business with ${prompt}. Now booking sessions globally.` });
      }
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setHasKey(false);
      }
    } finally {
      setIsGenerating(false);
      setVideoStatus("");
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-700 pb-32">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 border-b border-slate-100 pb-8">
        <div>
          <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-1">
            <Wand2 size={12} /> GLOBAL AD FACTORY
          </div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Marketing Studio</h2>
        </div>
        <div className="flex bg-slate-100 p-1.5 rounded-2xl">
           <button onClick={() => setActiveTab('image')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'image' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>
             <ImageIcon size={14} /> Image Ads
           </button>
           <button onClick={() => setActiveTab('video')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'video' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>
             <Video size={14} /> Video Promos
           </button>
        </div>
      </header>

      {activeTab === 'video' && !hasKey && (
        <div className="bg-amber-50 border border-amber-200 rounded-[32px] p-8 flex flex-col md:flex-row items-center gap-8 animate-in zoom-in-95">
           <div className="w-16 h-16 bg-amber-100 rounded-2xl flex items-center justify-center text-amber-600 shrink-0">
             <Lock size={32} />
           </div>
           <div className="flex-1 space-y-2 text-center md:text-left">
             <h3 className="text-lg font-black text-slate-900 uppercase">Paid API Key Required for Video</h3>
             <p className="text-sm text-slate-600 font-medium leading-relaxed">
               Veo 3.1 requires a dedicated billing project. Set up your key at 
               <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-indigo-600 ml-1 underline">ai.google.dev/billing</a>.
             </p>
           </div>
           <button onClick={handleSelectKey} className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-sm shadow-xl active:scale-95 whitespace-nowrap">
             Select Paid API Key
           </button>
        </div>
      )}

      <div className="grid grid-cols-1 xl:grid-cols-5 gap-10">
        <div className="xl:col-span-2 space-y-8">
          <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-10">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Campaign Narrative</label>
              <textarea 
                rows={4}
                placeholder="Describe your promotion strategy..." 
                className="w-full bg-slate-50 border-none rounded-[32px] p-8 text-base font-medium focus:ring-2 focus:ring-indigo-600 outline-none resize-none shadow-inner"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
            </div>

            <div className="space-y-4">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Orientation</label>
               <div className="grid grid-cols-2 gap-3">
                  <button onClick={() => setAspectRatio("1:1")} className={`p-4 rounded-2xl border-2 flex items-center justify-center gap-3 transition-all ${aspectRatio === "1:1" ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>
                    <Square size={16} /> <span className="text-[10px] font-black uppercase">Post</span>
                  </button>
                  <button onClick={() => setAspectRatio("9:16")} className={`p-4 rounded-2xl border-2 flex items-center justify-center gap-3 transition-all ${aspectRatio === "9:16" ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>
                    <Smartphone size={16} /> <span className="text-[10px] font-black uppercase">Story</span>
                  </button>
               </div>
            </div>

            <button 
              onClick={generateCampaign}
              disabled={isGenerating || !prompt || (activeTab === 'video' && !hasKey)}
              className="w-full py-6 bg-slate-900 text-white rounded-[28px] font-black text-sm shadow-2xl flex items-center justify-center gap-4 hover:bg-indigo-600 transition-all disabled:opacity-50 active:scale-95"
            >
              {isGenerating ? (
                <>
                  <RefreshCw size={20} className="animate-spin" />
                  {activeTab === 'video' ? 'Rendering Masterpiece...' : 'Visualizing Ad...'}
                </>
              ) : (
                <>
                  {activeTab === 'video' ? <Video size={20} /> : <Sparkles size={20} />}
                  {activeTab === 'video' ? 'Produce Video Promo' : 'Generate Ad Assets'}
                </>
              )}
            </button>
          </div>
        </div>

        <div className="xl:col-span-3">
          {isGenerating && activeTab === 'video' ? (
            <div className="h-full min-h-[500px] bg-slate-900 rounded-[48px] flex flex-col items-center justify-center text-center p-12 space-y-8 animate-in fade-in">
               <div className="relative">
                 <div className="w-32 h-32 border-4 border-indigo-500/20 rounded-full animate-spin border-t-indigo-500" />
                 <Video className="absolute inset-0 m-auto text-indigo-400 animate-pulse" size={40} />
               </div>
               <div className="space-y-4">
                 <h3 className="text-2xl font-black text-white uppercase tracking-tight">{videoStatus}</h3>
                 <p className="text-slate-400 max-w-sm mx-auto text-sm font-bold uppercase tracking-widest leading-relaxed">
                   AI-Driven Cinematography is a complex process. Please do not close the studio.
                 </p>
               </div>
            </div>
          ) : result ? (
            <div className="animate-in slide-in-from-right-10 duration-700 space-y-8">
              <div className="bg-white rounded-[48px] overflow-hidden shadow-2xl border border-slate-100">
                 <div className={`relative ${aspectRatio === "9:16" ? 'aspect-[9/16] max-h-[700px] overflow-hidden' : 'aspect-square'} bg-slate-100`}>
                    {result.video ? (
                      <video src={result.video} controls autoPlay loop className="w-full h-full object-cover" />
                    ) : (
                      <img src={result.image} alt="Promo" className="w-full h-full object-cover" />
                    )}
                 </div>
                 <div className="p-10">
                    <div className="flex items-center justify-between mb-4">
                       <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Social Copy Generated</span>
                       <button className="p-3 bg-slate-50 rounded-xl text-slate-400" onClick={() => { if(result.caption) navigator.clipboard.writeText(result.caption) }}><Copy size={18} /></button>
                    </div>
                    <p className="text-xl text-slate-800 font-medium leading-relaxed">{result.caption}</p>
                 </div>
              </div>
            </div>
          ) : (
            <div className="h-full min-h-[500px] border-4 border-dashed border-slate-100 rounded-[48px] flex flex-col items-center justify-center text-center p-20 text-slate-300 bg-white/50">
               <div className="w-24 h-24 bg-white rounded-3xl shadow-sm flex items-center justify-center mb-8 opacity-40">
                 {activeTab === 'video' ? <Play size={48} /> : <ImageIcon size={48} />}
               </div>
               <h3 className="text-xl font-black text-slate-400 uppercase">Studio Ready</h3>
               <p className="max-w-xs mt-4 font-bold text-sm opacity-60">
                 {activeTab === 'video' ? "Let's create a high-impact cinematic video for your global brand." : "Describe your strategy to generate high-res marketing assets."}
               </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

