import React, { useEffect, useState, useMemo } from 'react';
import { Appointment, Client } from '../types';
import { TrendingUp, Users, CalendarCheck, Globe, Zap, Sparkles, DollarSign, Copy, Check, Activity, Target, ArrowUpRight, BarChart3, ShieldCheck, Database, Layout, ExternalLink, Map, History, Radio, MapPin } from 'lucide-react';
import { geminiAssistant } from '../services/geminiService';
import { translations, Language } from '../services/translations';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

interface DashboardProps {
  businessName: string;
  appointments: Appointment[];
  clients: Client[];
  connectedApps: string[];
  legalData: any;
  currency: 'ILS' | 'USD' | 'EUR' | 'GBP';
  onOpenPublicView: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ businessName, appointments, clients, connectedApps, legalData, currency, onOpenPublicView }) => {
  const [aiSummary, setAiSummary] = useState<string>("Analyzing operational performance...");
  const lang = (localStorage.getItem('bookly_lang') as Language) || 'en';
  const t = translations[lang];
  const currencySymbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency];

  useEffect(() => {
    const fetchAiSummary = async () => {
      const summary = await geminiAssistant.getSummary(appointments);
      setAiSummary(summary || "Operational velocity is steady.");
    };
    if (appointments.length > 0) fetchAiSummary();
  }, [appointments]);

  const stats = useMemo(() => {
    const total = appointments.reduce((acc, curr) => acc + curr.price, 0);
    // Real logic: Check if client ID is from the public portal (International) or manual (Domestic)
    const globalTotal = appointments
      .filter(a => a.clientId.startsWith('public-'))
      .reduce((acc, curr) => acc + curr.price, 0);

    const domesticTotal = total - globalTotal;

    return { total, domestic: domesticTotal, global: globalTotal };
  }, [appointments]);

  const pieData = [
    { name: lang === 'he' ? 'ישראל' : 'Israel', value: stats.domestic || 0.1, color: '#4f46e5' },
    { name: lang === 'he' ? 'בינלאומי' : 'International', value: stats.global || 0, color: '#10b981' },
