const App: React.FC = () => {
  const [isInitializing, setIsInitializing] = useState(true);
  const [isOnboarded, setIsOnboarded] = useState(() => localStorage.getItem('bookly_onboarded') === 'true');
  const [isPublicView, setIsPublicView] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [lang, setLang] = useState<Language>(() => (localStorage.getItem('bookly_lang') as Language) || 'en');
  const [currency, setCurrency] = useState<'ILS' | 'USD' | 'EUR' | 'GBP'>(() => (localStorage.getItem('bookly_currency') as any) || 'ILS');
  const [businessName, setBusinessName] = useState(() => localStorage.getItem('bookly_business_name') || '');
  const [businessCategory, setBusinessCategory] = useState(() => localStorage.getItem('bookly_business_category') || 'General');
  const [subscriptionPlan, setSubscriptionPlan] = useState<'basic' | 'premium'>(() => storageService.getSubscription());
  const [connectedApps, setConnectedApps] = useState<string[]>(() => JSON.parse(localStorage.getItem('bookly_connected_apps') || '[]'));

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [services, setServices] = useState(() => JSON.parse(localStorage.getItem('bookly_services') || '[]'));
  const [legalData, setLegalData] = useState(() => JSON.parse(localStorage.getItem('bookly_legal') || '{"privacyPolicy": "", "termsOfService": "", "gdprStrict": true}'));

  const t = translations[lang];

  useEffect(() => {
    document.documentElement.dir = t.dir;
    document.documentElement.lang = lang;
    localStorage.setItem('bookly_lang', lang);
  }, [lang, t.dir]);

  useEffect(() => {
    const hydrate = async () => {
      try {
        const [aptData, clientData] = await Promise.all([
          api.appointments.list(),
          api.clients.list()
        ]);
        setAppointments(aptData);
        setClients(clientData);
      } catch (err) {
        showToast("Sync Error", "error");
      } finally {
        setTimeout(() => setIsInitializing(false), 800);
      }
    };
    if (isOnboarded) hydrate();
    else setIsInitializing(false);
  }, [isOnboarded]);

  useEffect(() => {
    if (!isInitializing) {
      storageService.saveAppointments(appointments);
      storageService.saveClients(clients);
      storageService.saveSubscription(subscriptionPlan);
      localStorage.setItem('bookly_services', JSON.stringify(services));
      localStorage.setItem('bookly_business_name', businessName);
      localStorage.setItem('bookly_business_category', businessCategory);
      localStorage.setItem('bookly_onboarded', isOnboarded.toString());
      localStorage.setItem('bookly_connected_apps', JSON.stringify(connectedApps));
      localStorage.setItem('bookly_legal', JSON.stringify(legalData));
      localStorage.setItem('bookly_currency', currency);
    }
  }, [appointments, clients, services, businessName, businessCategory, isOnboarded, subscriptionPlan, connectedApps, legalData, currency, isInitializing]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleNewBooking = async (newBooking: Appointment) => {
    const saved = await api.appointments.create(newBooking);
    setAppointments(prev => [saved, ...prev]);
    showToast(lang === 'he' ? 'הפגישה נקבעה בהצלחה' : `Session locked for ${saved.clientName}`);
  };

  if (!isOnboarded) {
    return <Onboarding onComplete={(data) => { setBusinessName(data.name); setBusinessCategory(data.category); setIsOnboarded(true); }} />;
  }

  if (isInitializing) {
    return (
      <div className="h-screen w-screen bg-slate-900 flex flex-col items-center justify-center space-y-8">
         <div className="w-20 h-20 bg-indigo-600 rounded-[24px] flex items-center justify-center text-white shadow-2xl animate-pulse">
            <Radio size={40} className="animate-bounce" />
         </div>
         <h2 className="text-white text-xl font-black tracking-widest uppercase">{lang === 'he' ? 'מפעיל ליבה...' : 'Initializing Core...'}</h2>
      </div>
    );
  }

  if (isPublicView) {
    return (
      <PublicBookingPage 
        businessName={businessName} 
        services={services}
        legalData={legalData}
        currency={currency}
        onBookingComplete={handleNewBooking}
        onBack={() => setIsPublicView(false)} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12">
            <Dashboard businessName={businessName} appointments={appointments} clients={clients} connectedApps={connectedApps} legalData={legalData} currency={currency} onOpenPublicView={() => setIsPublicView(true)} />

            <div className="bg-white border border-slate-100 rounded-[40px] p-10 shadow-sm animate-in slide-in-from-bottom-6 duration-1000">
               <div className="flex items-center justify-between mb-10">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Production Readiness</h3>
                    <p className="text-sm text-slate-500 font-medium italic">Owner Checklist: Preparing for App Store Launch</p>
                  </div>
                  <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600">
                    <Zap size={24} />
                  </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 space-y-4 group relative">
                     <div className="flex items-center justify-between">
                       <ShieldCheck className="text-emerald-500" size={24} />
                       <CheckCircle className="text-emerald-500" size={16} />
                     </div>
                     <p className="font-black text-xs uppercase tracking-widest text-slate-900">PWA Manifest</p>
                     <p className="text-[10px] text-slate-500 font-bold leading-relaxed">System identity is linked. This lets your clients "Install" your booking portal as a mobile app.</p>
                     <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Info size={14} className="text-indigo-400" />
                     </div>
                  </div>
                  <div className={`p-6 rounded-3xl border transition-all space-y-4 group relative ${connectedApps.length > 0 ? 'bg-slate-50 border-slate-100' : 'bg-amber-50 border-amber-100'}`}>
                     <div className="flex items-center justify-between">
                       <Radio className={connectedApps.length > 0 ? 'text-emerald-500' : 'text-amber-500'} size={24} />
                       {connectedApps.length > 0 ? <CheckCircle className="text-emerald-500" size={16} /> : <AlertCircle className="text-amber-500" size={16} />}
                     </div>
                     <p className="font-black text-xs uppercase tracking-widest text-slate-900">Israeli Clearing</p>
                     <p className="text-[10px] text-slate-500 font-bold leading-relaxed">Connecting your Israeli bank account for auto-invoicing and Bit payments.</p>
                     <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Info size={14} className="text-indigo-400" />
                     </div>
                  </div>
                  <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 space-y-4 group relative">
                     <div className="flex items-center justify-between">
                       <Globe className="text-indigo-600" size={24} />
                       <CheckCircle className="text-emerald-500" size={16} />
                     </div>
                     <p className="font-black text-xs uppercase tracking-widest text-slate-900">Global Grounding</p>
                     <p className="text-[10px] text-slate-500 font-bold leading-relaxed">The AI now tracks your local Israeli market and your foreign competitors automatically.</p>
                     <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Info size={14} className="text-indigo-400" />
                     </div>
                  </div>
               </div>
            </div>
          </div>
        );
      case 'calendar':
        return <AppointmentCalendar appointments={appointments} onAddClick={() => setShowAddModal(true)} onUpdateAppointment={(a) => setAppointments(prev => prev.map(x => x.id === a.id ? a : x))} onDeleteAppointment={(id) => setAppointments(prev => prev.filter(x => x.id !== id))} connectedApps={connectedApps} currency={currency} />;
      case 'clients':
        return <ClientCRM clients={clients} appointments={appointments} onDeleteClient={(id) => setClients(prev => prev.filter(c => c.id !== id))} />;
      case 'marketing':
        return <MarketingStudio />;
      case 'ai-assistant':
        return <AIAssistant appointments={appointments} clients={clients} />;
      case 'subscription':
        return <Pricing currentPlan={subscriptionPlan} onPlanChange={(p) => setSubscriptionPlan(p)} />;
      case 'settings':
        return (
          <Settings 
            businessName={businessName} 
            onUpdateBusinessName={setBusinessName} 
            services={services}
            onUpdateServices={setServices}
            connectedApps={connectedApps}
            onUpdateConnectedApps={setConnectedApps}
            legalData={legalData}
            onUpdateLegalData={setLegalData}
            currency={currency}
            onUpdateCurrency={setCurrency}
          />
        );
      default:
        return <Dashboard businessName={businessName} appointments={appointments} clients={clients} connectedApps={connectedApps} legalData={legalData} currency={currency} onOpenPublicView={() => setIsPublicView(true)} />;
    }
  };

  return (
    <div className={`flex h-screen bg-slate-50 overflow-hidden font-sans selection:bg-indigo-100 selection:text-indigo-900 ${lang === 'he' ? 'font-["Heebo"]' : ''}`}>
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        subscriptionPlan={subscriptionPlan} 
        connectedApps={connectedApps}
      />
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 bg-white/80 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-6 md:px-12 shrink-0 z-20">
          <div className="flex items-center gap-4 flex-1">
             <div className="md:hidden w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">
               {businessName.charAt(0)}
             </div>
             <div className="relative w-full max-w-xs hidden md:block">
               <Search className={`absolute ${t.dir === 'rtl' ? 'right-4' : 'left-4'} top-1/2 -translate-y-1/2 text-slate-300`} size={16} />
               <input 
                  type="text" 
                  placeholder={lang === 'he' ? 'חיפוש גלובלי...' : "Global Search..."}
                  className={`w-full bg-slate-50 border-none rounded-2xl py-2.5 ${t.dir === 'rtl' ? 'pr-12 pl-4' : 'pl-12 pr-4'} text-sm font-medium focus:ring-2 focus:ring-indigo-600 outline-none`}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
               />
             </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8">
            <button 
              onClick={() => setLang(lang === 'en' ? 'he' : 'en')}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 rounded-full text-[10px] font-black uppercase tracking-widest text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 transition-all"
            >
              <Languages size={14} /> {lang === 'en' ? 'Hebrew' : 'English'}
            </button>
            <button className="text-slate-300 hover:text-indigo-600 transition-colors relative">
              <Bell size={20} />
              <div className="absolute top-0 right-0 w-2 h-2 bg-rose-500 border-2 border-white rounded-full" />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 w-full custom-scroll">
          {renderContent()}
        </div>

        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </main>

      {showAddModal && (
        <AddAppointmentModal 
          onClose={() => setShowAddModal(false)} 
          onAdd={handleNewBooking}
          clients={clients}
          services={services}
        />
      )}
    </div>
  );
};

