// Fix: Manual base64 encoding for raw PCM audio streaming
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// Fix: Manual base64 decoding for raw PCM audio playback
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Fix: Custom audio decoding for raw PCM data streams
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Fix: Utility to create PCM blobs for real-time input
function createBlob(data: Float32Array) {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const AIAssistant: React.FC<{ appointments: Appointment[], clients: Client[] }> = ({ appointments, clients }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Neural Link established. I can manage your schedule, analyze Israeli tax compliance, or project global growth. How can I help you lead today?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    try {
      const response = await geminiAssistant.analyzeSchedule(appointments, clients, userMsg);
      setMessages(prev => [...prev, { role: 'assistant', content: response.text, links: response.links }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Protocol error. Neural sync interrupted." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceMode = async () => {
    if (isVoiceMode) {
      setIsVoiceMode(false);
      if (sessionRef.current) sessionRef.current.close();
      return;
    }

    // Fix: Full implementation of Live API session with audio feedback loop
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 16000});
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const outputNode = outputAudioContext.createGain();
    outputNode.connect(outputAudioContext.destination);

    let nextStartTime = 0;
    const sources = new Set<AudioBufferSourceNode>();

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      setIsVoiceMode(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } },
          systemInstruction: `You are the Bookly Operations Core. You have access to ${appointments.length} appointments. Answer questions about the schedule briefly and professionally. Use grounding search results when needed.`,
        },
        callbacks: {
          onopen: () => {
            console.log('Neural Link Active');
            const source = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
              const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64EncodedAudioString = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64EncodedAudioString) {
              nextStartTime = Math.max(nextStartTime, outputAudioContext.currentTime);
              const audioBuffer = await decodeAudioData(
                decode(base64EncodedAudioString),
                outputAudioContext,
                24000,
                1,
              );
              const source = outputAudioContext.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputNode);
              source.addEventListener('ended', () => {
                sources.delete(source);
              });
              source.start(nextStartTime);
              nextStartTime = nextStartTime + audioBuffer.duration;
              sources.add(source);
            }

            if (message.serverContent?.interrupted) {
              for (const source of sources.values()) {
                source.stop();
                sources.delete(source);
              }
              nextStartTime = 0;
            }
          },
          onclose: () => setIsVoiceMode(false),
          onerror: (e) => {
            console.error('Neural Link Error', e);
            setIsVoiceMode(false);
          },
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start Voice Session', err);
      setIsVoiceMode(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-[40px] border border-slate-100 shadow-2xl overflow-hidden relative">
      <div className="p-6 md:p-8 border-b bg-slate-900 flex items-center justify-between shrink-0 text-white">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Zap size={24} className={isVoiceMode ? 'animate-pulse' : ''} />
          </div>
          <div>
            <h3 className="font-black text-lg tracking-tight uppercase">Strategy Core</h3>
            <div className="flex items-center gap-2">
               <span className="flex items-center gap-1.5 text-[8px] font-black uppercase text-emerald-400 tracking-widest">
                 <Activity size={10} className="animate-pulse" /> SEARCH & MAPS READY
               </span>
            </div>
          </div>
        </div>
        <button 
          onClick={toggleVoiceMode}
          className={`px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-3 ${isVoiceMode ? 'bg-red-500 text-white animate-pulse' : 'bg-white/10 text-white hover:bg-white/20'}`}
        >
          {isVoiceMode ? <MicOff size={14}/> : <Mic size={14}/>}
          {isVoiceMode ? 'End Session' : 'Start Voice'}
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-10 space-y-8 bg-slate-50/30 custom-scroll">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 ${
                  msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-white'
                }`}>
                  {msg.role === 'user' ? <User size={14} /> : <BrainCircuit size={14} />}
                </div>
                <div className={`p-6 rounded-[28px] text-sm leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-white text-slate-900 rounded-tr-none border border-slate-100 font-bold' 
                    : 'bg-slate-900 text-white rounded-tl-none font-medium'
                }`}>
                  {msg.content}
                </div>
              </div>

              {msg.links && msg.links.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-2">
                   {msg.links.map((link, idx) => (
                     <a 
                      key={idx} 
                      href={link.uri} 
                      target="_blank" 
                      className="inline-flex items-center gap-2 px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-tight hover:bg-indigo-100 transition-colors border border-indigo-100"
                     >
                       <LinkIcon size={10} /> {link.title.substring(0, 30)}...
                     </a>
                   ))}
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-slate-100 p-6 rounded-[28px] rounded-tl-none border border-slate-200">
              <Loader2 className="animate-spin text-indigo-600" size={20} />
            </div>
          </div>
        )}
      </div>

      <div className="p-6 md:p-8 bg-white border-t shrink-0">
        <div className="relative max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Market trends, local competitors, or revenue insights..."
            className="w-full bg-slate-100 border-2 border-transparent rounded-[24px] px-8 py-5 pr-20 focus:outline-none focus:border-indigo-600 focus:bg-white text-sm font-bold transition-all shadow-inner"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="absolute right-2 top-2 bottom-2 px-6 bg-slate-900 text-white rounded-[18px] hover:bg-indigo-600 transition-all shadow-lg flex items-center gap-2 disabled:opacity-20"
          >
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

