import React, { useState, useEffect } from 'react';
import { Calendar, Users, LayoutDashboard, Settings, CreditCard, Sparkles, Megaphone, Crown, Zap, Activity, Globe, Radio, Link as LinkIcon } from 'lucide-react';
import { translations, Language } from '../services/translations';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  subscriptionPlan?: 'basic' | 'premium';
  connectedApps: string[];
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, subscriptionPlan = 'basic', connectedApps }) => {
  const [isNeuralPulsing, setIsNeuralPulsing] = useState(false);
  const lang = (localStorage.getItem('bookly_lang') as Language) || 'en';
  const t = translations[lang];

  useEffect(() => {
    const interval = setInterval(() => {
      setIsNeuralPulsing(true);
      setTimeout(() => setIsNeuralPulsing(false), 2000);
    }, 8000);
    return () => clearInterval(interval);
  }, []);

  const menuItems = [
    { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
    { id: 'calendar', label: t.calendar, icon: Calendar },
    { id: 'services', label: 'Booking Links', icon: LinkIcon, linkToTab: 'settings' },
    { id: 'clients', label: t.clients, icon: Users },
    { id: 'marketing', label: t.marketing, icon: Megaphone },
    { id: 'ai-assistant', label: t.aiAssistant, icon: Sparkles },
    { id: 'subscription', label: t.payouts, icon: CreditCard },
  ];

  const handleNav = (item: any) => {
    if (item.id === 'services') {
      setActiveTab('settings');
      // We'll need a way to deep-link to the services tab in Settings, 
      // but for now setting the active tab to 'settings' is the first step.
    } else {
      setActiveTab(item.id);
    }
  };

  return (
    <div className="hidden md:flex w-64 bg-slate-900 h-full flex-col shrink-0 relative z-50 shadow-2xl">
      <div className="p-8">
        <h1 className="text-2xl font-black text-white flex items-center gap-2 tracking-tight">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <Sparkles size={18} />
          </div>
          Bookly
        </h1>
      </div>

      <nav className="flex-1 px-4 space-y-1 overflow-y-auto no-scrollbar">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => handleNav(item)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium text-sm group ${
              activeTab === item.id || (item.id === 'services' && activeTab === 'settings')
                ? 'bg-indigo-600 text-white shadow-lg'
                : 'text-slate-500 hover:text-white hover:bg-slate-800/50'
            }`}
          >
            <item.icon size={18} className={`${activeTab === item.id ? 'text-white' : 'text-slate-500 group-hover:text-indigo-400'}`} />
            {item.label}
          </button>
        ))}
      </nav>

      <div className="p-6 border-t border-slate-800/50">
        <button 
          onClick={() => setActiveTab('settings')}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium text-sm ${
            activeTab === 'settings' 
              ? 'bg-indigo-600 text-white shadow-lg' 
              : 'text-slate-500 hover:text-white hover:bg-slate-800/50'
          }`}
        >
          <Settings size={18} />
          {t.settings}
        </button>
      </div>
    </div>
  );
};

