                    <div className="relative z-10">
                      <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1">Total Fee (Locked)</p>
                      <p className="text-sm font-bold text-white">Full Session & AI Post-Report</p>
                    </div>
                    <p className="text-4xl font-black tracking-tighter relative z-10">{symbol}{selectedService?.price}</p>
                 </div>

                 <button 
                  onClick={handleBook} 
                  disabled={isSubmitting || !clientInfo.name || !clientInfo.email}
                  className="w-full py-6 bg-slate-900 text-white rounded-[28px] font-black text-base shadow-2xl flex items-center justify-center gap-4 transition-all hover:bg-indigo-600 active:scale-95 disabled:opacity-30 group"
