    if (appointments.length > 0) fetchAiSummary();
  }, [appointments]);

  const stats = useMemo(() => {
    const total = appointments.reduce((acc, curr) => acc + curr.price, 0);
    const globalTotal = appointments
      .filter(a => a.clientId.startsWith('public-'))
      .reduce((acc, curr) => acc + curr.price, 0);

    const domesticTotal = total - globalTotal;

    return { total, domestic: domesticTotal, global: globalTotal };
