          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
        {/* Main Strategic Card */}
        <div className="xl:col-span-3 bg-slate-900 rounded-[48px] p-10 text-white relative overflow-hidden flex flex-col justify-between shadow-2xl border border-white/5">
          <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/30 blur-[120px] rounded-full translate-x-1/2 -translate-y-1/2" />
          <div className="absolute bottom-0 left-0 w-64 h-64 bg-emerald-600/10 blur-[100px] rounded-full -translate-x-1/4 translate-y-1/4" />

          <div className="relative z-10 space-y-10">
             <div className="flex items-center justify-between border-b border-white/10 pb-8">
                <div className="space-y-2">
                  <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em]">Neural Insights 3.0</span>
                  <p className={`text-2xl font-black leading-tight tracking-tight text-white max-w-2xl ${lang === 'he' ? 'text-right' : 'text-left'}`}>
                    "{aiSummary}"
