      <div className="w-full max-w-4xl bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden flex flex-col md:flex-row min-h-[600px] animate-in zoom-in-95 duration-500">

        {/* Sidebar Info (Calendly Left Pane) */}
