import React, { useState, useEffect } from 'react';
import { Calendar, Clock, ChevronRight, CheckCircle2, User, Phone, ShieldCheck, Check, Globe, Loader2, Lock, Languages, Info, ArrowLeft, ArrowRight, CalendarDays, Star, Zap, Users, Shield, MessageSquareText, Globe2, Sparkles, Send, X } from 'lucide-react';
import { api } from '../services/api';
import { Service } from '../types';
import { geminiAssistant } from '../services/geminiService';

interface PublicBookingPageProps {
  businessName: string;
  services: Service[];
  legalData: { privacyPolicy: string; termsOfService: string; gdprStrict: boolean };
  currency: 'ILS' | 'USD' | 'EUR' | 'GBP';
  onBookingComplete: (booking: any) => void;
  onBack?: () => void;
}

const PublicBookingPage: React.FC<PublicBookingPageProps> = ({ businessName, services, legalData, currency, onBookingComplete, onBack }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState<Service | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>("");
  const [selectedTime, setSelectedTime] = useState("");
  const [clientInfo, setClientInfo] = useState({ name: '', email: '', phone: '', note: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [availableSlots, setAvailableSlots] = useState<string[]>([]);
  const [isSuccess, setIsSuccess] = useState(false);

  // AI Concierge State
  const [showAi, setShowAi] = useState(false);
  const [aiInput, setAiInput] = useState("");
  const [aiMessages, setAiMessages] = useState<{role: 'ai' | 'user', text: string}[]>([]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const symbol = { ILS: '₪', USD: '$', EUR: '€', GBP: '£' }[currency];

  useEffect(() => {
    if (selectedDate) {
      const fetchSlots = async () => {
        const slots = await api.system.checkAvailability(selectedDate);
        setAvailableSlots(slots);
      };
      fetchSlots();
    }
  }, [selectedDate]);

  const handleBook = async () => {
    if (!selectedService) return;
    setIsSubmitting(true);
    const result = await api.appointments.create({ 
      id: Math.random().toString(36).substr(2, 9), 
      clientId: 'public-' + Date.now(),
      clientName: clientInfo.name, 
      service: selectedService.name, 
      date: selectedDate, 
      time: selectedTime, 
      duration: selectedService.duration, 
      status: 'confirmed', 
      price: selectedService.price,
